INSERT INTO public.books (entry_id, phase_id, title, author, pages, type, sort_order, pub_year, page_count_confidence, format, is_omnibus, row_type, location_primary, location_segmentum, in_universe_date, protagonist, key_characters, sub_faction, faction_primary, faction_secondary, sub_genre, mood_tags, semantic_tags, spoiler_free_summary, track, reading_order_note, also_in, acquired, research_note) VALUES
  ('P0-01', 0, 'Angels of Darkness', 'Gav Thorpe', 288, 'novel', 1, NULL, 'high', 'novel', false, 'entry', 'Piscina V (Piscina system)', 'Segmentum Obscurus', 'M41', 'Interrogator-Chaplain Boreas', '{"Astelan","Cypher"}', 'Dark Angels', 'Dark Angels', NULL, 'Character Study; Mystery', '{"grim","bleak","morally ambiguous","tragic"}', '{"Dark Angels","the Fallen","Interrogator-Chaplain","Piscina V","hunt for the Fallen","interrogation","secrets and cover-up","loyalty vs treachery","faith","clash of ideologies","gene-seed","recruiting world","atonement","Horus Heresy legacy"}', 'Dark Angels Interrogator-Chaplain Boreas guards the recruiting world of Piscina V. When the Chapter''s darkest secret - the Fallen - resurfaces, his past interrogation of a captured traitor returns to haunt him, with tragic consequences.', 'core', NULL, NULL, true, NULL),
  ('P0-02', 0, 'The Purging of Kadillus', 'Gav Thorpe', 416, 'novel', 2, NULL, 'high', 'novel', false, 'entry', 'Piscina IV (Kadillus Harbour)', 'Segmentum Obscurus', '997.M41', 'Captain Belial', '{"Ghazghkull Thraka","Nazdreg","Naaman"}', 'Dark Angels 3rd Company', 'Dark Angels', NULL, 'Military SF; War Epic', '{"action-packed","desperate","relentless","grim"}', '{"Dark Angels","3rd Company","orks","Ghazghkull Thraka","Nazdreg","Waaagh!","Piscina IV","Kadillus Harbour","siege warfare","planetary defence","greenskin invasion","last stand","Belial","Naaman","recruiting world"}', 'Facing an ork invasion of Piscina IV, the Dark Angels 3rd Company under Captain Belial underestimate the threat. As greenskins swarm Kadillus Harbour, Belial and Scout-Sergeant Naaman fight a desperate siege to hold the world until reinforcements arrive.', 'core', NULL, NULL, true, NULL),
  ('P0-03', 0, 'Legacy of Caliban: Ravenwing', 'Gav Thorpe', 416, 'novel', 3, NULL, 'high', 'novel', false, 'entry', 'Piscina IV (hunt begins)', 'Segmentum Obscurus', 'M41', 'Brother Annael', '{"Sammael","Belial","Telemenus"}', 'Ravenwing (Dark Angels 2nd Company)', 'Dark Angels', NULL, 'Military SF; Mystery', '{"fast-paced","action-packed","intrigue-laden","grim"}', '{"Dark Angels","Ravenwing","2nd Company","the Fallen","hunt for the Fallen","bikes and land speeders","Sammael","Annael","Telemenus","Inner Circle","secrets and conspiracy","Piscina IV","pirates","Chaos Space Marines","mobile warfare","initiation","brotherhood"}', 'The Ravenwing wage war upon bikes and speeders where their brothers cannot. When Brother Annael joins their ranks, he is drawn into shadowy intrigue and discovers the Chapter has a sacred duty far greater than hunting orks.', 'core', NULL, NULL, true, NULL),
  ('P0-04', 0, 'Legacy of Caliban: Master of Sanctity', 'Gav Thorpe', 416, 'novel', 4, NULL, 'high', 'novel', false, 'entry', 'Mobile/Fleet (Fallen hunt)', 'Mobile/Fleet', 'M41', 'Interrogator-Chaplain Asmodai', '{"Sapphon","Astelan","Annael","Telemenus"}', 'Dark Angels (Inner Circle; Deathwing & Ravenwing)', 'Dark Angels', NULL, 'Character Study; Political Thriller', '{"paranoid","tense","grim","morally murky"}', '{"Dark Angels","the Fallen","Interrogator-Chaplain","Asmodai","Sapphon","Inner Circle","hunt for the Fallen","interrogation","paranoia","secrets","Deathwing","Ravenwing","Astelan","manipulation","faith","atonement","chapter politics"}', 'The Dark Angels'' secret hunt for the Fallen continues. Interrogator-Chaplain Asmodai sees treachery everywhere, straining the Chapter''s alliances, while Brothers Annael and Telemenus are thrust into an operation that could shake the Imperium to its core.', 'core', NULL, NULL, true, NULL),
  ('P0-05', 0, 'Legacy of Caliban: The Unforgiven', 'Gav Thorpe', 416, 'novel', 5, NULL, 'medium', 'novel', false, 'entry', 'The Rock (fortress-monastery)', 'Mobile/Fleet', 'M41', 'Supreme Grand Master Azrael', '{"Cypher","Asmodai","Sammael","Belial"}', 'Dark Angels (Inner Circle)', 'Dark Angels', NULL, 'Military SF; Political Thriller', '{"tense","climactic","grim","intrigue-laden"}', '{"Dark Angels","the Fallen","Cypher","the Rock","Inner Circle","Azrael","hunt for the Fallen","atonement and redemption","secrets","Death Guard","Horus Heresy legacy","betrayal motif","chapter destiny","interrogation"}', 'The Dark Angels'' hunt for the Fallen reaches its climax. With the elusive Cypher captured after his surrender, the Chapter hopes for redemption - but what game is Cypher playing, and can the Unforgiven ever truly atone?', 'core', NULL, NULL, true, 'AbeBooks 416 PB; 1 model gave 360 (Hachette HC) - PB used'),
  ('P0-06', 0, 'Cypher: Lord of the Fallen', 'John French', 192, 'novel', 6, 2023, 'high', 'novel', false, 'entry', 'Imperial Palace, Holy Terra', 'Segmentum Solar', 'post-Great Rift (Era Indomitus, ~M42)', 'Cypher', '{"Roboute Guilliman"}', 'The Fallen', 'Dark Angels', '{"Fallen"}', 'Heist; Mystery', '{"enigmatic","mysterious","tense","grimdark"}', '{"Cypher","the Fallen","Dark Angels","Adeptus Custodes","Officio Assassinorum","Imperial Palace","Holy Terra","Great Rift","Roboute Guilliman","prison escape","infiltration","unreliable narrator","secrets and lies","the Emperor","manhunt","Era Indomitus","mystery","betrayal"}', 'As the Great Rift tears open above Terra and Guilliman returns, Cypher and his band of Fallen escape the Imperium''s most secure prison. Loose in the Imperial Palace, hunted by Dark Angels, Custodes and Assassins - but what does Cypher truly intend?', 'core', NULL, NULL, true, NULL),
  ('P0-07', 0, 'The Lion: Son of the Forest', 'Mike Brooks', 368, 'novel', 7, 2023, 'high', 'novel', false, 'entry', 'Camarth', 'Ultima Segmentum (Imperium Nihilus)', 'post-Great Rift (Era Indomitus, ~M42)', 'Lion El''Jonson', '{"Zabriel","Seraphax","Baelor"}', 'Dark Angels / the Risen (loyalist Fallen)', 'Dark Angels', NULL, 'Quest/Adventure; Character Study', '{"introspective","melancholic","reflective","grim"}', '{"Lion El''Jonson","Primarch","Dark Angels","the Fallen","the Risen","Zabriel","Seraphax","Ten Thousand Eyes","Chaos Space Marines","Imperium Nihilus","Great Rift","Camarth","redemption and forgiveness","Arthurian motifs","return of a primarch","identity","betrayal"}', 'After ten thousand years in stasis, Lion El''Jonson wakes into the nightmare of Imperium Nihilus. Alone in a galaxy beset by darkness, the Primarch must gather his long-exiled Fallen knights and confront a traitorous son''s Chaos warband.', 'core', NULL, NULL, true, NULL),
  ('P0-08', 0, 'The Talon of Horus', 'Aaron Dembski-Bowden', 416, 'novel', 8, 2014, 'high', 'novel', false, 'entry', 'The Eye of Terror', 'Eye of Terror', 'M31 (post-Horus Heresy)', 'Iskandar Khayon', '{"Ezekyle Abaddon","Fabius Bile","Lheorvine Ukris","Telemachon Lyras"}', 'Black Legion (former Sons of Horus & Thousand Sons remnants)', 'Black Legion', '{"Chaos"}', 'War Epic; Character Study', '{"dark","gothic","introspective","epic"}', '{"Black Legion","Sons of Horus","Thousand Sons","Iskandar Khayon","Ezekyle Abaddon","Chaos Space Marines","Eye of Terror","the warp","daemons","sorcery","Vengeful Spirit","origin story","unreliable narrator","Long War","brotherhood","anti-heroes","Fabius Bile","post-Heresy","warband politics"}', 'When Horus fell, his Sons fell with him - a broken Legion scattered across the Eye of Terror. When Horus''s body is taken from its resting place, a confederation of legionaries seeks the vanished Abaddon to convince him to embrace his destiny.', 'core', NULL, NULL, true, NULL),
  ('P0-09', 0, 'Black Legion', 'Aaron Dembski-Bowden', 368, 'novel', 9, 2017, 'high', 'novel', false, 'entry', 'The Eye of Terror', 'Eye of Terror', '781.M31 (First Black Crusade)', 'Iskandar Khayon', '{"Ezekyle Abaddon","Sigismund","Thagus Daravek","Moriana"}', 'Black Legion', 'Black Legion', '{"Chaos"}', 'War Epic; Character Study', '{"dark","gothic","tragic","philosophical"}', '{"Black Legion","Ezekyle Abaddon","Iskandar Khayon","Chaos Space Marines","Eye of Terror","the warp","daemons","sorcery","Thagus Daravek","Sigismund","Black Templars","First Black Crusade","Long War","unreliable narrator","assassination","warlord rivalry","the Ezekarion","brotherhood","tragedy"}', 'Abaddon and his warlords strive to bind the newborn Black Legion together. As Khayon, his most-trusted assassin, hunts the rival warlord Thagus Daravek, Abaddon turns his gaze back toward the Imperium - and a reckoning with an old enemy.', 'core', NULL, NULL, true, NULL),
  ('P1-01', 1, 'Forges of Mars (Omnibus)', 'Graham McNeill', NULL, 'omnibus', 1, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Adeptus Mechanicus', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, true, NULL),
  ('P1-02', 1, 'The Emperor''s Gift', 'Aaron Dembski-Bowden', 416, 'novel', 2, 2012, 'high', 'novel', false, 'entry', 'Armageddon', 'Segmentum Solar', '444-445.M41', 'Hyperion', '{"Logan Grimnar","Angron","Inquisitor Kysnaros","Annika Jarlsdottyr"}', 'Grey Knights (666th;Squad Castian);Ordo Malleus;Space Wolves', 'Grey Knights', '{"Ordo Malleus"}', 'Military SF;Character Study', '{"grim","emotional","tragic","character-driven"}', '{"Grey Knights","daemon hunters","Ordo Malleus","Titan","666th Chapter","First War for Armageddon","Months of Shame","Space Wolves","Inquisition","psychic powers","Chaos","daemons","first-person narration","Angron"}', 'The secretive Grey Knights, daemon-hunting Space Marines of the Ordo Malleus recruited to the fortress of Titan, stand against Chaos as the dark powers stir anew and Armageddon beckons.', 'core', NULL, NULL, true, 'PB standard; HC was 320, reprint 432 - PB value used'),
  ('P1-03', 1, 'Grey Knights (Omnibus)', 'Ben Counter', NULL, 'omnibus', 3, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Grey Knights', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, true, NULL),
  ('P1-04', 1, 'The Infinite and the Divine', 'Robert Rath', 368, 'novel', 4, 2020, 'medium', 'novel', false, 'entry', 'Serenade (Cepharil)', 'Eastern Fringe', 'c.999.M41 (spans ~10000yr)', 'Trazyn the Infinite', '{"Orikan the Diviner"}', 'Nihilakh Dynasty;Sautekh Dynasty', 'Necrons', NULL, 'Character Study;Quest/Adventure', '{"witty","humorous","tragic","epic"}', '{"Necrons","Trazyn the Infinite","Orikan the Diviner","rivalry","immortality","time manipulation","artefact hunt","Astrarium Mysterios","Solemnace","Tomb of Nephreth","necron history","biotransference","C''tan","non-human protagonists","collecting","chronomancy","Eastern Fringe"}', 'Trazyn the Infinite, a necron collector, and Orikan the Diviner, a peerless chronomancer, are eternal opposites. When an artefact promising the necrons'' next evolution emerges, their rivalry escalates into a multi-millennia game.', 'core', 'Perspective break / palate cleanser between Grey Knights and Ahriman arc', NULL, true, 'PB; some listings show 440 (edition variance) - not material for totals; Eastern Fringe confirmed by author interview (Track of Words) this session'),
  ('P1-05', 1, 'Ahriman: The Omnibus', 'John French', NULL, 'omnibus', 5, 2017, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Thousand Sons', '{"Chaos"}', NULL, NULL, NULL, NULL, 'core', NULL, NULL, true, NULL),
  ('P1-06', 1, 'Ahriman: Eternal', 'John French', 336, 'novel', 6, 2022, 'high', 'novel', false, 'entry', 'Exiles'' fleet (via webway to Necron tomb world)', 'Mobile/Fleet', 'M41', 'Ahzek Ahriman', '{"Setekh","Ctesias","Ignis","Silvanus"}', 'Thousand Sons;The Exiles', 'Thousand Sons', '{"Necrons"}', 'Quest/Adventure;Character Study', '{"layered","tragic","ominous","melancholic"}', '{"Thousand Sons","Ahriman","the Exiles","Pyrodomon","second Rubric","necrons","Setekh","time control","Harlequins","aeldari","warp","redemption","xenos technology","Helio Isidorus","memory"}', 'Doom stalks the Thousand Sons. As the Pyrodomon consumes sorcerers and Rubricae alike, Ahriman seeks the time-altering technology of the necrons, via a captured xenos, to overwrite his past.', 'core', 'Post-omnibus Necron-arc; pairs with Undying (P1-07); no omnibus exists; bridges into M42', NULL, true, NULL),
  ('P1-07', 1, 'Ahriman: Undying', 'John French', 368, 'novel', 7, 2024, 'high', 'novel', false, 'entry', 'Sub-realm ''threshold of space and time'' (Key of Infinity)', 'The Warp', 'M41', 'Ahzek Ahriman', '{"Setekh","Ctesias","Helio Isidorus"}', 'Thousand Sons;The Exiles;Hyksos Dynasty', 'Thousand Sons', '{"Necrons"}', 'Quest/Adventure;Character Study', '{"bleak","solitary","tragic","time-bending"}', '{"Thousand Sons","Ahriman","Key of Infinity","necrons","Setekh","time manipulation","Pyrodomon","the Exiles","Hyksos Dynasty","warp","sub-realm","betrayal","redemption","solitary sorcerer"}', 'Ahriman languishes at the threshold of space and time, adrift in an unknowable sub-realm. He has at last found the necron Key of Infinity, but with his Legion consumed, is it too late?', 'core', 'Pairs with Eternal (P1-06); Ahriman faces the Necrons and the decay of time itself', NULL, true, 'HC Jul 2024, PB May 2025'),
  ('P2-01', 2, 'Eisenhorn: The Omnibus', 'Dan Abnett', NULL, 'omnibus', 1, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Inquisition', '{"Ordo Xenos"}', NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, NULL),
  ('P2-02', 2, 'The Magos', 'Dan Abnett', 720, 'novel', 2, 2018, 'high', 'novel', false, 'entry', 'Gershom', NULL, NULL, 'Gregor Eisenhorn', '{"Valentin Drusher","Germaine Macks"}', 'Ordo Xenos', 'Inquisition', '{"Ordo Xenos"}', 'Mystery; Character Study', '{"contemplative","slow-burn","dark","reflective"}', '{"Inquisition","Adeptus Mechanicus (magos biologis)","Cognitae","heretics","remote world","investigation","Warp sorcery/reanimated dead","character study","Eisenhorn''s fall","third-person narration"}', 'Pursuing heretics in the remote worlds of the Imperium, the ageing Inquisitor Eisenhorn must confront the truth about himself: is he still a champion of the Throne, or has he been seduced by the very evil he hunts?', 'core', 'Eisenhorn #4; novel plus 12 connected shorts', NULL, false, 'trade PB, novel+12 shorts'),
  ('P2-03', 2, 'Lords of Blood (Omnibus)', 'Guy Haley', NULL, 'omnibus', 3, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Blood Angels', NULL, NULL, NULL, NULL, NULL, 'core', 'Complex: read Dante -> jump to Shield of Baal (P3) -> back to Devastation of Baal; SAVE Darkness in the Blood for Phase 5; Astorath also listed standalone in P5 (same novel)', NULL, false, NULL),
  ('P2-04', 2, 'Lords of Nocturne (Omnibus)', 'Nick Kyme', NULL, 'omnibus', 4, 2024, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Salamanders', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, NULL),
  ('P2-05', 2, 'Night Lords: The Omnibus', 'Aaron Dembski-Bowden', NULL, 'omnibus', 5, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Night Lords', '{"Chaos"}', NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, NULL),
  ('P3-01', 3, 'Ravenor: The Omnibus', 'Dan Abnett', NULL, 'omnibus', 1, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Inquisition', '{"Ordo Xenos"}', NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, NULL),
  ('P3-02', 3, 'Resurrection', 'John French', 368, 'novel', 2, 2017, 'high', 'novel', false, 'entry', 'Ero (Caradryad Sector)', 'Segmentum Tempestus', NULL, 'Inquisitor Covenant', '{"Viola von Castellan","Cleander von Castellan","Josef"}', 'Ordo Malleus (Covenant''s warband)', 'Inquisition', NULL, 'Mystery; Political Thriller', '{"dark","complex","paranoid","grim"}', '{"Inquisition","Horusians","Thorians","radical vs puritan","daemonhosts","conspiracy","the Unseen cult","conclave massacre","psyker","swordsman","warband","Chaos","sector war","Goldoran Talicto"}', 'War rages in the Caradryad Sector. Puritan Inquisitor Covenant prepares to denounce the heretic Talicto before an inquisitorial conclave, but when the gathering is attacked he must hunt Talicto and uncover the mysterious cult, the Unseen - trusting no one.', 'core', NULL, NULL, false, NULL),
  ('P3-03', 3, 'Incarnation', 'John French', 283, 'novel', 3, 2018, 'medium', 'novel', false, 'entry', 'Dominicus Prime', 'Segmentum Tempestus', NULL, 'Inquisitor Covenant', '{"Viola von Castellan","Josef","Inquisitor Memnon"}', 'Ordo Malleus (Covenant''s warband)', 'Inquisition', NULL, 'Political Thriller; Horror', '{"dark","gothic","claustrophobic","ominous"}', '{"shrine world","Ecclesiarchy","Monastery of the Last Candle","Season of Night","Living Saint","Triumvirate","Horusians","Chaos cult","pilgrims","Imperial Tarot","daemonic manifestation","political intrigue","von Castellan"}', 'Darkness and a Season of Night descend on shrine world Dominicus Prime. At the Monastery of the Last Candle, Inquisitor Covenant pursues the Horusian Triumvirate, who seek to raise a Living Saint. He must deny them at any cost.', 'core', NULL, NULL, false, 'single-source HC; no PB figure found'),
  ('P3-04', 3, 'Divination', 'John French', 365, 'anthology', 4, 2019, 'high', 'anthology', false, 'entry', 'Caradryad Sector (various)', 'Segmentum Tempestus', NULL, 'Inquisitor Covenant', '{"Viola von Castellan","Cleander von Castellan"}', 'Ordo Malleus (Covenant''s warband)', 'Inquisition', NULL, 'Character Study; Horror', '{"dark","varied","thoughtful","bleak"}', '{"Inquisition","Imperial Tarot","Triumvirate","warband","psykers","assassins","character studies","origin stories","anthology","Chaos","Ordo Malleus","von Castellan dynasty"}', 'An anthology of connected tales. As Inquisitor Covenant works to unpick the plans of the deadly Triumvirate, eleven stories reveal the origins, darkest moments and triumphs of the agents, psykers and killers who serve him.', 'core', 'Anthology of 11 connected shorts', NULL, false, 'anthology'),
  ('P3-05', 3, 'Valedor', 'Guy Haley', 352, 'novel', 5, 2014, 'medium', 'novel', false, 'entry', 'Duriel (Valedor System)', 'Eastern Fringe', '778999.M41', 'Prince Yriel', '{"Iyanna Arienal","Taec Silvereye"}', 'Craftworld Iyanden', 'Aeldari', '{"Tyranids"}', 'War Epic; Military SF', '{"tragic","melancholic","doomed","epic"}', '{"Tyranids","Hive Fleet Leviathan","Hive Fleet Kraken","Craftworld Iyanden","Craftworld Biel-Tan","Drukhari of Commorragh","uneasy alliance","maiden world","Spear of Twilight","Spiritseers","Wraith constructs","species decline","tragedy","Apocalypse-scale war"}', 'On the defiled maiden world of Duriel, wayward Prince Yriel of Iyanden fights to stop a returning splinter of Hive Fleet Kraken merging with Leviathan, allying with Biel-Tan and the dark eldar of Commorragh against the tyranids.', 'core', 'Iyanden vs Tyranids', NULL, false, 'PB (AbeBooks); 334 was HC'),
  ('P3-06', 3, 'Shield of Baal (Collection)', 'Various', 457, 'anthology', 6, NULL, 'high', 'collection', false, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Blood Angels', '{"Tyranids"}', NULL, NULL, NULL, NULL, 'core', 'Read between Dante and Devastation of Baal (P2 Lords of Blood)', NULL, false, 'collection'),
  ('P3-07', 3, 'Path of the Dark Eldar (Omnibus)', 'Andy Chambers', NULL, 'omnibus', 7, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Drukhari', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, NULL),
  ('P3-08', 3, 'Lelith Hesperax: Queen of Knives', 'Mike Brooks', 208, 'novel', 8, 2024, 'high', 'novel', false, 'entry', 'Commorragh', 'The Webway', 'post-Great Rift / M42 (Ynnari era)', 'Lelith Hesperax', '{"Asdrubael Vect","Yvraine","Morghana Nathrax"}', 'Wych Cult of Strife', 'Drukhari', NULL, 'Character Study; Political Thriller', '{"sleek","wicked","decadent","fast-paced"}', '{"Commorragh arenas","gladiatorial bloodsport","Wych Cult of Strife","succubus","Asdrubael Vect schemes","Ynnari","Ynnead death cultists","pretenders/rivals","intrigue","Harlequins","webway"}', 'Greatest gladiator of Commorragh, Lelith Hesperax has left the Dark City to walk with Ynnead''s death cultists. When a blade strikes from the shadows she is dragged back into Asdrubael Vect''s murderous games and tightening web of schemes.', 'core', NULL, NULL, false, NULL),
  ('P3-09', 3, 'Farsight: Crisis of Faith', 'Phil Kelly', 355, 'novel', 9, 2017, 'medium', 'novel', false, 'entry', 'Arthas Moloch / Damocles Gulf', 'Eastern Fringe', '742.M41 (Damocles Crusade era)', 'Commander Farsight (O''Shovah)', '{"Ob''lotai 3-0","Commander Bravestorm"}', 'Vior''la Sept', 'T''au', NULL, 'Military SF; War Epic', '{"tense","foreboding","action-packed","pulpy"}', '{"T''au Empire","Damocles Gulf","reclaiming lost colonies","Imperium of Man enemy","Arthas Moloch","XV8 battlesuit","Greater Good","propaganda","naivety","Scar Lords Space Marines","Ethereal caste"}', 'Fresh from victory on Arkunasha, young Commander Farsight leads a crusade across the Damocles Gulf to reclaim T''au colonies from the Imperium. Amid early successes he faces enemies he never anticipated, with courage and soul tested to the limit.', 'core', 'No omnibus exists', NULL, false, 'review-only; 281/355/393 spread, median used'),
  ('P3-10', 3, 'Farsight: Empire of Lies', 'Phil Kelly', 416, 'novel', 10, 2020, 'medium', 'novel', false, 'entry', 'Arthas Moloch', 'Eastern Fringe', 'M41 (post-742.M41)', 'Commander Farsight (O''Shovah)', '{"Aun''va","Grog Ironteef"}', 'Vior''la Sept', 'T''au', NULL, 'Military SF; Character Study', '{"obsessive","dark","conflicted","tragic"}', '{"T''au Empire","orks/greenskins","Arthas Moloch","Ethereal caste manipulation","Greater Good vs hidden truth","obsession","Farsight Enclaves","Dawn Blade","Vior''la"}', 'Victorious over the Imperium, High Commander Farsight turns to crush the orks ravaging T''au worlds. His obsessive crusade drives him toward the daemon-haunted world of Arthas Moloch and an encounter that changes how he sees the galaxy, the Empire and himself.', 'core', NULL, NULL, false, 'single source'),
  ('P3-11', 3, 'Shadowsun: The Patient Hunter', 'Phil Kelly', 288, 'novel', 11, 2023, 'medium', 'novel', false, 'entry', 'Startide Nexus / Nem''yar Atoll', 'Ultima Segmentum', 'post-Great Rift / M42 (Fifth Sphere Expansion)', 'Commander Shadowsun (O''Shaserra)', NULL, 'Vior''la Sept (Fifth Sphere Expansion)', 'T''au', NULL, 'Military SF; Horror', '{"intense","fast-paced","eerie","grim"}', '{"T''au Empire","Fifth Sphere Expansion","Startide Nexus wormhole","Chalnath Expanse","Nem''yar Atoll","Death Guard","Nurgle","daemons","plague","Kauyon Patient Hunter strategy","stealth battlesuit","Kroot/Nicassar/Charpactin allies","civil war among allies","Great Rift","Imperium Nihilus"}', 'Celebrated master of the Patient Hunter strategy, Commander Shadowsun must trap the Chaos-worshipping Death Guard whose technology tears holes in space. As her forces spread across the Great Rift and treacheries surface, civil war threatens between the t''au and their allies.', 'core', NULL, NULL, false, 'single-source HC'),
  ('P3-12', 3, 'The Dark Coil: Damnation (Omnibus)', 'Peter Fehervari', NULL, 'omnibus', 12, 2024, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Warhammer Horror', '{"T''au"}', NULL, NULL, NULL, NULL, 'core', 'Reads with Dark Coil: Ascension (P7)', NULL, false, NULL),
  ('P3-13', 3, 'Ultramarines: The First Omnibus', 'Graham McNeill', NULL, 'omnibus', 13, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Ultramarines', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, NULL),
  ('P3-14', 3, 'Ultramarines: The Second Omnibus', 'Graham McNeill', NULL, 'omnibus', 14, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Ultramarines', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, NULL),
  ('P3-15', 3, 'Kingsblade', 'Andy Clark', 368, 'novel', 15, 2017, 'high', 'novel', false, 'entry', 'Donatos Primus', 'Ultima Segmentum', 'M41', 'Danial Tan Draconis', '{"Tolwyn Tan Draconis","Luk Kar Chimaeros","Jennika Tan Draconis"}', 'House Draconis (Adrastapol)', 'Imperial Knights', NULL, 'War Epic; Military SF', '{"chivalric","heroic","tragic","action-packed"}', '{"Imperial Knights","House Draconis","Adrastapol","Donatos Primus","Word Bearers","Dark Apostle Varakh''Lorr","Chaos cult uprising","betrayal","coming-of-age","chivalry","honour","Knight Houses","Astra Militarum/Cadians","unholy ritual"}', 'When the world of Donatos falls to Word Bearers heresy, the noble Knight Houses of Adrastapol lead the reconquest. But when tragedy casts the campaign into anarchy, unblooded Knights Errant Danial and Luk must master war to stop an unholy ritual.', 'core', NULL, NULL, false, NULL),
  ('P3-16', 3, 'Knightsblade', 'Andy Clark', 363, 'novel', 16, 2018, 'high', 'novel', false, 'entry', 'Adrastapol', 'Ultima Segmentum', 'M41 (five years after the Donatos War)', 'Luk Kar Chimaeros (Knight of Ashes)', '{"Danial Tan Draconis","Alicia Kar Manticos"}', 'House Chimaeros (renounced; Freeblade)', 'Imperial Knights', NULL, 'War Epic; Quest/Adventure', '{"chivalric","tense","honour-bound","action-packed"}', '{"Imperial Knights","Freeblade","Knight of Ashes","Adrastapol","orks","WAAAGH! Killfist","siege","House Draconis","vengeance","quest","exile","honour vs heresy","internecine war","chivalry"}', 'Having renounced his fallen house to become the Freeblade Knight of Ashes, Luk has for five arduous years hunted his treacherous step-mother across the stars. As his quest nears its end, destruction descends on his homeworld Adrastapol - forcing a choice between justice and aiding the Noble Houses.', 'core', NULL, NULL, false, NULL),
  ('P3-17', 3, 'Fabius Bile: The Omnibus', 'Josh Reynolds', NULL, 'omnibus', 17, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Chaos', '{"Emperor''s Children"}', NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, NULL),
  ('P3-18', 3, 'Word Bearers: The Omnibus', 'Anthony Reynolds', NULL, 'omnibus', 18, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Word Bearers', '{"Chaos"}', NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, NULL),
  ('P3-19', 3, 'Renegades: Lord of Excess', 'Rich McCormick', 416, 'novel', 19, 2024, 'medium', 'novel', false, 'entry', 'Serrine', NULL, NULL, 'Xantine', NULL, 'The Adored (Emperor''s Children)', 'Emperor''s Children', '{"Chaos"}', 'Horror; Political Thriller', '{"hedonistic","brutal","self-deluded","darkly satirical"}', '{"Emperor''s Children","Slaanesh","S''janth (Slaaneshi daemon)","hedonism","excess","Genestealer cult","warp storms","planetary rule","perfection","betrayal","Chaos Space Marines","corruption"}', 'Xantine, proud leader of the Adored and a son of Fulgrim, seeks more than backwater raiding; he finds Serrine, a wealthy cruel world cut off by warp storms, and sets out to bring his own perfection to it.', 'core', NULL, NULL, false, 'single source'),
  ('P3-20', 3, 'Iron Warriors: The Omnibus', 'Graham McNeill', NULL, 'omnibus', 20, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Iron Warriors', '{"Chaos"}', NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, NULL),
  ('P3-21', 3, 'Renegades: Harrowmaster', 'Mike Brooks', 368, 'novel', 21, 2023, 'medium', 'novel', false, 'entry', NULL, 'Ultima Segmentum', 'post-Great Rift / M42 (Indomitus Crusade)', 'Solomon Akurra', NULL, 'The Serpent''s Teeth (Alpha Legion)', 'Alpha Legion', '{"Chaos"}', 'Political Thriller; Military SF', '{"twisty","intrigue-laden","deceptive","tense"}', '{"Alpha Legion","Chaos Space Marines","Indomitus Crusade","Primaris Marines","Great Rift","deception","infiltration","Inquisition","intrigue","betrayal","Long War"}', 'As the Indomitus Crusade pushes into the Ultima Segmentum and Solomon Akurra''s warband the Serpent''s Teeth meet the Primaris Marines, the Alpha Legion must adapt; Solomon intends to claim the title of Harrowmaster and unite his fractured Legion.', 'core', 'Solomon Akurra arc #1', NULL, false, '368 (2x) vs 282 - majority'),
  ('P3-22', 3, 'Ghost Legion', 'Mike Brooks', 359, 'novel', 22, 2026, 'medium', 'novel', false, 'entry', NULL, NULL, NULL, 'Solomon Akurra', NULL, 'The Serpent''s Teeth (Alpha Legion)', 'Alpha Legion', '{"Chaos"}', 'Military SF; Political Thriller', '{"scheming","tense","ambitious"}', '{"Alpha Legion","Chaos Space Marines","Pale Spear","Imperial assassins","empire-building","deception","Indomitus era","dissent","ambition","Long War"}', 'As Harrowmaster, Solomon Akurra has united feuding Alpha Legion forces and conquered star systems, wielding what he claims to be his primarch''s weapon, the Pale Spear; but his ambition draws the Imperium against his burgeoning new world.', 'core', 'Solomon Akurra #2', NULL, false, 'Kindle only (2026); no print yet'),
  ('P3-23', 3, 'Huron Blackheart: Master of the Maelstrom', 'Mike Brooks', 208, 'novel', 23, 2022, 'high', 'novel', false, 'entry', 'The Maelstrom', 'Ultima Segmentum', 'post-Great Rift (M42)', 'Huron Blackheart', NULL, 'Red Corsairs', 'Red Corsairs', '{"Chaos"}', 'Character Study; Political Thriller', '{"brooding","cynical","power-focused","grim"}', '{"Red Corsairs","Chaos Space Marines","the Maelstrom","piracy","Great Rift","Roboute Guilliman","power dynamics","loyalty","renegades","warp","independence"}', 'Huron Blackheart, lord of the Red Corsairs and master of the lawless Maelstrom, must adapt to an Imperium led by the returned Guilliman while struggling to retain power against dissension and fresh challengers within his own ranks.', 'core', NULL, NULL, false, NULL),
  ('P3-24', 3, 'The Soul Drinkers Omnibus (Vol. 1)', 'Ben Counter', NULL, 'omnibus', 24, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Soul Drinkers', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, NULL),
  ('P3-25', 3, 'The Soul Drinkers Omnibus II', 'Ben Counter', NULL, 'omnibus', 25, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Soul Drinkers', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, NULL),
  ('P3-26', 3, 'The Devastation of Baal', 'Guy Haley', 512, 'novel', 26, 2017, 'high', 'novel', false, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Blood Angels', NULL, NULL, NULL, NULL, NULL, 'core', NULL, 'P2-03.2 (Lords of Blood Omnibus) - SAME NOVEL, do not double-count', false, 'Cross-ref: physically counted in Phase 2; SAME as P2-03.2 (512); do NOT double-count in master'),
  ('P3-27', 3, 'Ashes of Prospero', 'Gav Thorpe', 352, 'novel', 27, 2018, 'high', 'novel', false, 'entry', 'Prospero', NULL, 'post-Great Rift (M42)', 'Njal Stormcaller', '{"Arjac Rockfist","Lukas the Trickster","Logan Grimnar"}', 'Space Wolves', 'Space Wolves', NULL, 'Quest/Adventure; Military SF', '{"saga-like","adventurous","action-packed","mythic"}', '{"Space Wolves","Thousand Sons","sorcerer Izaak","ruins of Tizca","Great Rift","lost 13th Company","Rune Priest","psyker","Portal Maze","quest","Norse saga motifs","Primaris Marines"}', 'Concerned by his Chapter''s diminishing numbers, the Great Wolf Logan Grimnar entrusts Njal Stormcaller to find a remedy. Goaded by the shade of a long-dead sorcerer, the Rune Priest gathers a disparate warband to brave the Great Rift and return to where it all began, on Prospero.', 'core', NULL, NULL, false, NULL),
  ('P3-28', 3, 'War of Secrets', 'Phil Kelly', 416, 'novel', 28, 2018, 'high', 'novel', false, 'entry', 'Saltire Vex', 'Ultima Segmentum', 'early M42 / post-Great Rift', 'Lieutenant Xedro Farren', '{"Interrogator-Chaplain Zaeroph"}', 'Dark Angels (Primaris)', 'Dark Angels', '{"T''au"}', 'Mystery; Military SF', '{"secretive","morally grey","twisty","tense"}', '{"Dark Angels","Primaris Space Marines","T''au Empire","Fourth Sphere Expansion","the Fallen","Interrogator-Chaplain","psychic curse","ocean world","conspiracy","Great Rift","loyalty and secrets"}', 'Lieutenant Xedro Farren is a Primaris Marine sent to fight alongside the Dark Angels against a trauma-scarred force of t''au. Their true quarry becomes clear: the shadowy instigator of a psychic curse, and Farren must peel back layer after layer of deceit to find an appalling truth.', 'core', NULL, NULL, false, NULL),
  ('P3-29', 3, 'Of Honour and Iron', 'Ian St. Martin', 352, 'novel', 29, 2017, 'medium', 'novel', false, 'entry', 'Quradim', NULL, 'M42', 'Chaplain Helios', '{"Roboute Guilliman","Sergeant Theron","Warsmith Bolaraphon"}', 'Ultramarines 8th Company', 'Ultramarines', '{"Word Bearers"}', 'Military SF; War Epic', '{"grim","brooding","brutal","morally grey"}', '{"Ultramarines","Ultramarines 8th Company","Iron Warriors","Genesis Chapter","Primaris Space Marines","Roboute Guilliman","Chaplain Helios","Warsmith Bolaraphon","Indomitus Crusade","Dark Imperium","Quradim","virus bombs","M42"}', 'The age of the Dark Imperium has begun. With Roboute Guilliman resurrected as Lord Commander, he dispatches Chaplain Helios of the Ultramarines ahead of his Indomitus Crusade fleets on a mission of vital importance, one that may secure victory or doom him to a millennia-old obsession.', 'core', NULL, NULL, false, 'single source'),
  ('P3-30', 3, 'Apocalypse', 'Josh Reynolds', 560, 'novel', 30, 2018, 'medium', 'novel', false, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Word Bearers', '{"Imperial Fists"}', NULL, NULL, NULL, NULL, 'core', NULL, 'Phase 5 (Faith & Secrets block) - listed there natively', false, 'single source; SMC#5'),
  ('P3-31', 3, 'Fist of the Imperium', 'Andy Clark', 416, 'novel', 31, 2020, 'medium', 'novel', false, 'entry', 'Ghyre (mining world)', 'Segmentum Solar', 'M42', 'Primaris Librarian Aster Lydorran', '{"Watch Captain Lothar Redfang","Captain Ercuros Tor"}', 'Imperial Fists 5th Company', 'Imperial Fists', NULL, 'Military SF; Mystery', '{"grim","tense","claustrophobic","foreboding"}', '{"Imperial Fists","Imperial Fists 5th Company","Primaris Space Marines","Genestealer Cult","Aster Lydorran","Lothar Redfang","Ghyre","mining world","Segmentum Solar","counter-insurgency","psychic battle","siege warfare","M42"}', 'Deep within the Segmentum Solar, an Imperial Fists honour guard lies slaughtered on the mining world of Ghyre, where a mysterious cult grows in power. The Fists dispatch Primaris Librarian Aster Lydorran to purge it, but he faces an insurgent foe whose psychic might may surpass his own.', 'core', NULL, NULL, false, 'single source'),
  ('P4-01', 4, 'The Fall of Cadia', 'Robert Rath', 656, 'novel', 1, 2023, 'high', 'novel', false, 'entry', 'Cadia', 'Segmentum Obscurus', '999.M41', 'Ursarkar E. Creed (central figure of a multi-POV ensemble)', '{"Abaddon the Despoiler","Jarran Kell"}', 'Astra Militarum (Cadian Shock Troops)', 'Astra Militarum', '{"Cadia"}', 'War Epic; Military SF', '{"grim","tragic","epic in scale","harrowing"}', '{"Cadia","Thirteenth Black Crusade","Abaddon the Despoiler","Eye of Terror","Ursarkar E. Creed","Jarran Kell","Astra Militarum","Cadian Shock Troops","pylon fields","opening of the Great Rift","doomed last stand","war epic","coalition warfare","multi-POV ensemble","Segmentum Obscurus"}', 'After the Thirteenth Black Crusade seems spent, Lord Castellan Creed senses worse is coming. As Abaddon the Despoiler emerges from the Eye of Terror at the head of a warhost unmatched in scale since the Horus Heresy, Creed must weld Cadia''s defenders into a bulwark against apocalypse.', 'core', NULL, NULL, false, NULL),
  ('P4-02', 4, 'Watchers of the Throne: The Emperor''s Legion', 'Chris Wraight', 352, 'novel', 2, 2017, 'high', 'novel', false, 'entry', 'Terra', 'Segmentum Solar', 'Late M41-early M42 (opening of the Great Rift; early Dark Imperium)', 'Valerian (Adeptus Custodes Shield-Captain)', '{"Tanau Aleya","Alexei Lev Tieron","Trajann Valoris"}', 'Adeptus Custodes', 'Adeptus Custodes', '{"Sisters of Silence"}', 'Political Thriller; Military SF', '{"tense","politically charged","action-packed","atmospheric"}', '{"Terra","Adeptus Custodes","Sisters of Silence","Golden Throne","Imperial Palace","Valerian","Tanau Aleya","Alexei Lev Tieron","Trajann Valoris","High Lords of Terra","Black Legion","daemon incursion","political intrigue","first-person multi-POV","Segmentum Solar"}', 'The Adeptus Custodes have guarded the Emperor''s Palace since the Imperium''s founding. But when an unprecedented threat arises, the golden guardians and their Sisters of Silence allies are pressed almost beyond endurance defending the Golden Throne.', 'core', 'Pairs with The Regent''s Shadow (P4-03); no omnibus exists', NULL, false, 'PB reprint (2018); 288 was HC - PB used per doctrine'),
  ('P4-03', 4, 'Watchers of the Throne: The Regent''s Shadow', 'Chris Wraight', 368, 'novel', 3, 2020, 'high', 'novel', false, 'entry', 'Terra', 'Segmentum Solar', 'M42 (post-Great Rift; Indomitus Crusade underway)', 'Valerian (Adeptus Custodes Shield-Captain)', '{"Tanau Aleya","Roboute Guilliman","Trajann Valoris"}', 'Adeptus Custodes (Argent Chamber)', 'Adeptus Custodes', NULL, 'Political Thriller', '{"brooding","tense","introspective","politically charged"}', '{"Terra","Adeptus Custodes","Argent Chamber","Sisters of Silence","Roboute Guilliman","Indomitus Crusade","Valerian","Tanau Aleya","Anna-Murza Jek","Trajann Valoris","Phalanx","Luna","Terran political intrigue","threat of civil war","Segmentum Solar"}', 'As Guilliman departs to lead the Indomitus Crusade, he leaves a Terra still in turmoil and beset by cult activity. The Custodians keep the Palace secure and the Sisters rebuild on Luna, but a new and unexpected foe stirs.', 'core', 'Pairs with The Emperor''s Legion (P4-02)', NULL, false, 'minor variance (406 outlier)'),
  ('P4-04', 4, 'Vaults of Terra: The Omnibus', 'Chris Wraight', NULL, 'omnibus', 4, 2025, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Inquisition', '{"Ordo Hereticus"}', NULL, NULL, NULL, NULL, 'core', 'Companion to Watchers of the Throne; Okira short = Niir Khazad backstory', NULL, false, NULL),
  ('P4-05', 4, 'The High Kahl''s Oath', 'Gav Thorpe', 352, 'novel', 5, 2024, 'high', 'novel', false, 'entry', 'Galactic core (coreward stars)', NULL, 'Post-Great Rift / Era Indomitus (M42); exact M-date not stated', 'Myrtun Dammergot (Hernkyn Prospect leader)', NULL, 'Kindred of the Eternal Starforge (Leagues of Votann)', 'Leagues of Votann', NULL, 'Quest/Adventure; Military SF', '{"adventurous","pragmatic","treasure-hunt","lighter grimdark"}', '{"Leagues of Votann","the Kin","first Leagues of Votann novel","Kindred of the Eternal Starforge","Myrtun Dammergot","Hernkyn Prospect","Votann Ancestor Cores","Ironkin","Grimnyr","Tyranids","Orks","coreward stars","warp storms","treasure hunt","mercantile war"}', 'Far from the Imperium, the Leagues of Votann wage capitalistic wars. Hernkyn Prospect leader Myrtun Dammergot thrives exploiting the conflict - until a messenger from her Kindred''s Hold ship upends her life, plunging her and her companions toward a deadly foe and a magnificent prize.', 'core', NULL, NULL, false, '2 retailers agree 352; 290 was vague review estimate'),
  ('P4-06', 4, 'Angron: The Red Angel', 'David Guymer', 352, 'novel', 6, 2023, 'high', 'novel', false, 'entry', 'Malakbael (Imperium Nihilus)', 'Multiple/Galaxy-wide', 'M42 (Imperium Nihilus / Era Indomitus)', 'Kossolax the Foresworn (World Eaters)', '{"Angron","Graucis Telomane","Ortan Leidis"}', 'World Eaters (Legion)', 'World Eaters', '{"Chaos"}', 'Military SF; War Epic', '{"brutal","visceral","bloody","rage-fuelled"}', '{"Angron","World Eaters","Daemon Primarch","Imperium Nihilus","Kossolax the Foresworn","the Conqueror","Grey Knights","Graucis Telomane","Khorne","the Butcher''s Nails","Ortan Leidis","Malakbael","Chaos Space Marines","Era Indomitus","berserker bloodshed"}', 'In the darkness of Imperium Nihilus a beacon is lit, and the Red Angel returns to call his scattered World Eaters to slaughter. Aboard their flagship, Kossolax the Foresworn fights to keep the Legion''s old dreams alive as his hated father''s return threatens their fragile unity.', 'core', NULL, NULL, false, NULL),
  ('P5-01', 5, 'Dark Imperium: The Omnibus', 'Guy Haley', NULL, 'omnibus', 1, NULL, NULL, NULL, true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Ultramarines', '{"Death Guard"}', NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, NULL),
  ('P5-02', 5, 'A Witch''s Fate', 'Guy Haley', NULL, 'short', 2, NULL, 'pending', 'short_story', false, 'entry', NULL, NULL, NULL, 'Leonid Rostov', NULL, 'Inquisition', 'Imperium (Inquisition)', NULL, 'Character Study', '{"dark","introspective","melancholic","intimate"}', '{"Inquisition","Inquisitor Rostov","psyker","interrogation","Dawn of Fire prequel","Indomitus Crusade","witch"}', 'A short companion to Avenging Son offering deeper insight into Inquisitor Rostov as he interrogates a captured witch in the service of the Emperor.', 'core', NULL, NULL, false, 'added in v3.0; page_count pending (Open Library pass)'),
  ('P5-03', 5, 'Dawn of Fire I: Avenging Son', 'Guy Haley', 512, 'novel', 3, 2020, 'high', 'novel', false, 'entry', 'Machorta Sound', NULL, 'post-Great Rift / M42', 'Vitrian Messinius', '{"Roboute Guilliman","Cassandra VanLeskus","Ferren Areios"}', 'White Consuls', 'Imperium', NULL, 'Military SF; War Epic', '{"epic","political","action-packed","foreboding"}', '{"Indomitus Crusade","Roboute Guilliman","White Consuls","Vitrian Messinius","Battlegroup Saint Aster","Primaris Space Marines","Terra","Machorta Sound","Fleetmistress VanLeskus","Imperial Navy","Slaughter Host","World Eaters","Cicatrix Maledictum","Inquisitor Rostov"}', 'As Guilliman launches the Indomitus Crusade from Terra, Fleetmistress VanLeskus turns to the Machorta Sound, attacked by a Slaughter Host of Chaos. The fate of the crusade may hinge on this battle and the desperate mission of Battlegroup Saint Aster, led by Lieutenant Messinius.', 'core', 'Indomitus Crusade backbone', NULL, false, NULL),
  ('P5-04', 5, 'Dawn of Fire II: The Gate of Bones', 'Andy Clark', 384, 'novel', 4, 2021, 'high', 'novel', false, 'entry', 'Gathalamor', NULL, 'post-Great Rift / M42', 'Achallor', '{"Roboute Guilliman","Abaddon the Despoiler"}', 'Adeptus Custodes', 'Imperium', NULL, 'Military SF; War Epic', '{"grim","desperate","militaristic","foreboding"}', '{"Indomitus Crusade","Adeptus Custodes","Shield-Captain Achallor","Roboute Guilliman","Gathalamor","shrine world","Abaddon the Despoiler","Iron Warriors","Adepta Sororitas","Imperium Sanctus","ancient weapon","Mordian Guard"}', 'As the Indomitus Crusade begins, Guilliman leads a force toward the shrine world of Gathalamor. When agents of Abaddon unearth an ancient weapon there, Shield-Captain Achallor of the Custodes leads a mission to a world on the brink, with the Throne of Terra itself at risk.', 'core', NULL, NULL, false, NULL),
  ('P5-05', 5, 'Dawn of Fire III: The Wolftime', 'Gav Thorpe', 368, 'novel', 5, 2021, 'high', 'novel', false, 'entry', 'Fenris', 'Segmentum Obscurus', 'post-Great Rift / M42', 'Gaius', '{"Logan Grimnar","Krom Dragongaze","Ghazghkull Mag Uruk Thraka"}', 'Space Wolves (Drakeslayers Great Company)', 'Imperium', '{"Space Wolves"}', 'Military SF; Character Study', '{"brooding","melancholic","saga-like","grim"}', '{"Space Wolves","Vlka Fenryka","Fenris","Logan Grimnar","Krom Dragongaze","Primaris Space Marines","orks","Ghazghkull Mag Uruk Thraka","Indomitus Crusade","Fleet Primus","tradition vs change","Drakeslayers"}', 'The Indomitus Crusade reaches Fenris as rampaging orks under Ghazghkull threaten Fleet Primus. Depleted and called upon by Guilliman, the Space Wolves under Logan Grimnar must decide whether to accept new allies or hold to tradition and await their primarch.', 'core', NULL, NULL, false, NULL),
  ('P5-06', 5, 'Dawn of Fire IV: Throne of Light', 'Guy Haley', 368, 'novel', 6, 2022, 'high', 'novel', false, 'entry', 'Srinagar', 'Segmentum Solar', 'post-Great Rift / M42', 'Leonid Rostov', '{"Roboute Guilliman","Kor Phaeron"}', 'Inquisition', 'Imperium', NULL, 'Military SF; Political Thriller', '{"tense","foreboding","militaristic","ominous"}', '{"Indomitus Crusade","Roboute Guilliman","Inquisitor Rostov","Word Bearers","Kor Phaeron","Segmentum Solar","Srinagar","Black Ships","astropaths","Hand of Abaddon","Tenebrus","Black Templars","rebellion"}', 'Having broken the ork threat near Fenris, Guilliman turns to defend Segmentum Solar as Kor Phaeron''s Word Bearers incite rebellion and hunt the Black Ships. Inquisitor Rostov''s search for the Hand of Abaddon is diverted by miraculous visions traced to Srinagar.', 'core', NULL, NULL, false, NULL),
  ('P5-07', 5, 'Dawn of Fire V: The Iron Kingdom', 'Nick Kyme', 480, 'novel', 7, 2022, 'high', 'novel', false, 'entry', 'Kamidar', NULL, 'post-Great Rift / M42', 'Iron Queen Orlah', '{"Magda Kesh"}', 'Imperial Knights (House of Kamidar)', 'Imperium', NULL, 'Political Thriller; Military SF', '{"political","tense","tragic","grim"}', '{"Indomitus Crusade","Imperial Knights","Kamidar","Iron Queen Orlah","Battle Group Praxis","Anaxian Line","Black Templars","Mordian Guard","Magda Kesh","agents of Abaddon","political feud","Marines Malevolent"}', 'War-weary Battle Group Praxis arrives at the Knight world of Kamidar to return the Iron Queen''s slain heir - and to strip the world for the crusade. What should be a reunion of allies becomes a bitter feud, which Abaddon''s agents move to exploit.', 'core', NULL, NULL, false, NULL),
  ('P5-08', 5, 'Dawn of Fire VI: The Martyr''s Tomb', 'Marc Collins', 368, 'novel', 8, 2023, 'high', 'novel', false, 'entry', 'Velua', NULL, 'post-Great Rift / M42', 'Irinya', '{"Gaheris","Katla Helvintr"}', 'Order of Our Martyred Lady', 'Imperium', NULL, 'Military SF; War Epic', '{"desperate","grim","zealous","bleak"}', '{"Indomitus Crusade","Adepta Sororitas","Order of Our Martyred Lady","Canoness Irinya","Black Templars","Champion Gaheris","rogue trader","Katla Helvintr","Death Guard","Nurgle cultists","Velua","shrine world","Golden Chain","faith"}', 'As the Archenemy strikes back, the shrine worlds of the Golden Chain fall until only Velua remains. Canoness Irinya and Black Templar Champion Gaheris hold the line against plague-ridden cultists, while the disgraced rogue trader Katla Helvintr may hold the world''s fate.', 'core', NULL, NULL, false, NULL),
  ('P5-09', 5, 'Dawn of Fire VII: Sea of Souls', 'Chris Wraight', 400, 'novel', 9, 2024, 'high', 'novel', false, 'entry', 'Judgement of the Void (Fleet Secundus)', 'Mobile/Fleet', 'post-Great Rift / M42', 'Iannis Kiastros', NULL, 'Imperial Navy', 'Imperium', '{"Chaos"}', 'Horror; Military SF', '{"claustrophobic","tense","dread-filled","tragic"}', '{"Indomitus Crusade","Imperial Navy","Fleet Secundus","Judgement of the Void","High Captain Kiastros","Eye of Terror","Adepta Sororitas","Iron Shades","void warfare","claustrophobic horror","treachery","Dark Mechanicum"}', 'As the Indomitus Crusade marches on, Fleet Secundus heads for the Eye of Terror. The Imperial Navy battle cruiser Judgement of the Void pushes into contested space, but as Chaos closes in, a battle for survival unfolds with ramifications for the whole galaxy.', 'core', NULL, NULL, false, NULL),
  ('P5-10', 5, 'Dawn of Fire VIII: Hand of Abaddon', 'Nick Kyme', 480, 'novel', 10, 2024, 'high', 'novel', false, 'entry', 'Anaxian Line', NULL, 'post-Great Rift / M42', 'Leonid Rostov', '{"Ferren Areios","Magda Kesh","Tharador Yheng"}', 'Inquisition', 'Imperium', '{"Chaos"}', 'Military SF; War Epic', '{"grim","sprawling","foreboding","tense"}', '{"Indomitus Crusade","Inquisitor Rostov","Hand of Abaddon","Ultramarines","Ferren Areios","Mordian 84th","Magda Kesh","Anaxian Line","Tenebrus","Tharador Yheng","Red Corsairs","Graeyl Herek","Chaos cult","ancient evil"}', 'As the crusade rages, Inquisitor Rostov uncovers intelligence on the schemes of the Hand of Abaddon and gathers allies. Along the Anaxian Line, Ultramarines Lieutenant Areios and Mordian soldier Magda Kesh fight on while Chaos acolytes vie to harness an ancient evil.', 'core', NULL, NULL, false, NULL),
  ('P5-11', 5, 'Dawn of Fire IX: The Silent King', 'Guy Haley', 560, 'novel', 11, 2024, 'high', 'novel', false, 'entry', 'Pariah Nexus', NULL, 'post-Great Rift / M42', 'Belisarius Cawl', '{"Roboute Guilliman","Vitrian Messinius","Szarekh"}', 'Adeptus Mechanicus', 'Imperium', '{"Necrons"}', 'War Epic; Military SF', '{"epic","climactic","ominous","melancholic"}', '{"Indomitus Crusade","Roboute Guilliman","Belisarius Cawl","Necrons","Szarekh the Silent King","Pariah Nexus","Battlefleet Kallides","Vitrian Messinius","Imperium Nihilus","Great Rift","xenos threat","series finale"}', 'The first phase of the Indomitus Crusade nears its end. Drawn south by the loss of Battlefleet Kallides in the Pariah Nexus, Guilliman confronts a gathering necron threat as the dynasties unite under whispers of a returning power - the Silent King.', 'core', NULL, NULL, false, NULL),
  ('P5-13', 5, 'Apocalypse', 'Josh Reynolds', NULL, 'novel', 13, 2018, NULL, 'novel', false, 'entry', 'Almace', NULL, 'post-Great Rift / M42', 'Heyd Calder', '{"Roboute Guilliman","Suboden Khan","Karros"}', 'Imperial Fists', 'Word Bearers', '{"Imperial Fists"}', 'Military SF; Political Thriller', '{"tense","political","faith-driven","wry"}', '{"Space Marine Conquests","Imperial Fists","Heyd Calder","White Scars","Suboden Khan","Raven Guard","Karros","Word Bearers","Amatnim Ur-Nabas Lash","Almace","Ecclesiarchy","Adepta Sororitas","Great Rift","siege","Primaris Space Marines"}', 'After the Great Rift, Imperial Fists, White Scars and Raven Guard mobilise to defend the Ecclesiarchy world of Almace from the Word Bearers. Primaris Lieutenant Heyd Calder plans the defence, but discovers the Cardinal-Governor is hiding something, and conquest is not the enemy''s sole aim.', 'core', 'Faith & Secrets block; read here natively in Indomitus context', 'P3-30 - SAME NOVEL do not double-count', false, 'enrichment home; P3-30 skipped'),
  ('P5-14', 5, 'Saints and Martyrs: An Adepta Sororitas Omnibus', 'Various', NULL, 'omnibus', 14, 2024, NULL, NULL, true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Adepta Sororitas', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, NULL),
  ('P5-15', 5, 'The Rose at War (Omnibus)', NULL, NULL, 'omnibus', 15, NULL, NULL, NULL, true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, NULL),
  ('P5-16', 5, 'The Rose in Darkness', 'Danie Ware', 368, 'novel', 16, 2023, 'medium', 'novel', false, 'entry', 'Opal', NULL, NULL, 'Sister Superior Augusta Santorus', NULL, 'Order of the Bloody Rose', 'Adepta Sororitas', NULL, 'Horror; Military SF', '{"melancholy","foreboding","grim","faith-driven"}', '{"Adepta Sororitas","Sister Augusta","Order of the Bloody Rose","Opal","shrine world","Genestealer Cult","Tyranids","hive fleet","Saint Veres","relic","religious festival","political intrigue","supernatural horror","faith","Sisters of Battle"}', 'Sent to the shrine world of Opal to retrieve the skull of revered Saint Veres, Augusta and her squad arrive during a holy festival. Political danger simmers, and a genestealer cult lurking beneath signals an approaching hive fleet.', 'core', 'Augusta saga continuation after Rose at War omnibus', NULL, false, NULL),
  ('P5-17', 5, 'Mark of Faith', 'Rachel Harrison', 368, 'novel', 17, 2019, 'medium', 'novel', false, 'entry', 'Ophelia VII', 'Segmentum Tempestus', 'post-Great Rift / M42', 'Sister Evangeline', '{"Inquisitor Ahri Ravara","Saint Katherine"}', 'Order of Our Martyred Lady', 'Adepta Sororitas', '{"Inquisition"}', 'Quest/Adventure; Character Study', '{"faith-driven","dark","introspective","grim"}', '{"Adepta Sororitas","Sister Evangeline","Order of Our Martyred Lady","Ophelia VII","Inquisitor Ahri Ravara","Ordo Hereticus","Shield of Saint Katherine","Great Rift","Cicatrix Maledictum","Imperium Nihilus","pilgrimage","relic quest","faith","daemons","Sisters of Battle"}', 'Denied a martyr''s death at Ophelia VII, Sister Evangeline of the Order of Our Martyred Lady embarks on a pilgrimage beyond the Great Rift to recover the Shield of Saint Katherine, accompanied by the enigmatic Inquisitor Ravara.', 'core', 'Sister Evangeline + Inquisitor Ravara; pilgrimage into Imperium Nihilus', NULL, false, NULL),
  ('P5-18', 5, 'Morvenn Vahl: Spear of Faith', 'Jude Reid', 400, 'novel', 18, 2024, 'medium', 'novel', false, 'entry', 'Ophelia VII', 'Segmentum Tempestus', NULL, 'Morvenn Vahl', NULL, 'Adepta Sororitas (Abbess Sanctorum)', 'Adepta Sororitas', '{"Night Lords"}', 'Military SF; Character Study', '{"faith vs doubt","grim","action-driven","bloody"}', '{"Adepta Sororitas","Morvenn Vahl","Abbess Sanctorum","High Lord of Terra","Ophelia VII","cardinal world","Night Lords","Kol Rakhul","Heldrake","Living Saints","Senatorum Imperialis","faith and doubt","Sisters of Battle"}', 'When a monster from myth threatens the cardinal world of Ophelia VII, Abbess Sanctorum Morvenn Vahl defies the Senatorum Imperialis to defend it against the warlord Kol Rakhul, the Death of Saints, and his Night Lords.', 'core', 'Abbess Sanctorum defending Ophelia VII', NULL, false, NULL),
  ('P5-19', 5, 'Daemonbreaker', 'Jude Reid', 255, 'novel', 19, 2024, 'low', 'novel', false, 'entry', 'Orison VIII', 'Segmentum Obscurus', '999.M41 (13th Black Crusade)', 'Celestian Sacresant Aveline', '{"Abaddon the Despoiler","Novitate Gwineth"}', 'Order of the Sacred Rose', 'Adepta Sororitas', '{"Chaos"}', 'Military SF; Horror', '{"zealous","dark","intense","faith-driven"}', '{"Adepta Sororitas","Celestian Sacresant Aveline","Order of the Sacred Rose","Orison VIII","Cadian Gate","Cadia","13th Black Crusade","Abaddon the Despoiler","Chaos sorcerer","Saint Arabella","relic sword","ancient evil","Novitate Gwineth","faith","Sisters of Battle"}', 'As Abaddon''s 13th Black Crusade falls upon Cadia, Celestian Sacresant Aveline of the Order of the Sacred Rose must secure the shrine world of Orison VIII, where hunting a Chaos sorcerer uncovers an ancient evil that knows her name.', 'core', 'Aveline of the Sacred Rose during 13th Black Crusade', NULL, false, NULL),
  ('P5-20', 5, 'Pilgrims of Fire', 'Justin D. Hill', 366, 'novel', 20, NULL, 'medium', 'novel', false, 'entry', 'Cion', NULL, 'Era Indomitus / M42 (brackets the Great Rift)', 'Sister Helewise', '{"Saint Katherine"}', 'Order of Our Martyred Lady', 'Adepta Sororitas', NULL, 'Military SF; War Epic', '{"grimdark","bleak","futile","epic","faith-tested"}', '{"Adepta Sororitas","Sister Helewise","Order of Our Martyred Lady","Cion","shrine world","Fleet Quintus","Indomitus Crusade","Imperium Nihilus","Cicatrix Maledictum","Saint Katherine","pilgrimage","Savlar Chem Dogs","Sisters Repentia","daemons","faith and martyrdom"}', 'Sister Helewise of the Order of Our Martyred Lady, determined to stay alive until her death serves a higher purpose, joins the cursed Fleet Quintus of the Indomitus Crusade to rediscover and liberate the lost shrine world of Cion.', 'core', NULL, NULL, false, 'added in v3.0; page_count: edition variance 324(print)-366(GR)'),
  ('P5-21', 5, 'Aestred Thurga: Pyre of Faith', 'Danie Ware', 300, 'novel', 21, 2026, 'low', 'novel', false, 'entry', 'Katerah', NULL, NULL, 'Aestred Thurga', NULL, 'Order Pronatus', 'Adepta Sororitas', '{"Nurgle"}', 'Military SF; Quest/Adventure', '{"zealous","vengeful","grim","faith-driven"}', '{"Adepta Sororitas","Aestred Thurga","Reliquant at Arms","Order Pronatus","Katerah","necropolis world","Sword of Saarim","relic","Nurgle","Plague God","Chaos cult","rising dead","faith and vengeance","Sisters of Battle"}', 'Aestred Thurga, the Reliquant at Arms, is ambushed while returning the legendary Sword of Saarim to the necropolis world of Katerah, losing the blade to a Plague God cult. She vows to reclaim relic and honour as the dead begin to rise.', 'core', 'Reliquant at Arms vs Nurgle on Katerah', NULL, false, NULL),
  ('P5-22', 5, 'The Lords of Silence', 'Chris Wraight', 400, 'novel', 22, 2018, 'high', 'novel', false, 'entry', 'Solace (Death Guard grand cruiser)', 'Mobile/Fleet', 'post-Great Rift / M42', 'Vorx', NULL, 'Lords of Silence (Death Guard warband)', 'Death Guard', NULL, 'Mystery; Character Study', '{"macabre","darkly humorous","atmospheric","philosophical"}', '{"Death Guard","Lords of Silence","Vorx","Solace","Nurgle","Plague Marines","Eye of Terror","Imperium Nihilus","Cadian Gate","Tallyman","Biologus Putrifier","numerology","Long War","dark humour"}', 'The Cadian Gate is broken and the galaxy riven. Among those seeking vengeance on the Imperium are the Death Guard. Aboard the living grand cruiser Solace, the philosophical Siegemaster Vorx and his warband carve through the void - but the past pursues them from the Eye of Terror.', 'core', NULL, NULL, false, NULL),
  ('P5-23', 5, 'Mephiston: Blood of Sanguinius', 'Darius Hinks', 352, 'novel', 23, 2021, 'high', 'novel', false, 'entry', 'Divinatus Prime', NULL, 'post-Great Rift / M42', 'Mephiston (Calistarius)', '{"Antros","Rhacelus"}', 'Blood Angels', 'Blood Angels', NULL, 'Military SF; Horror', '{"gothic","dark","action-packed","brooding"}', '{"Blood Angels","Mephiston","Lord of Death","Chief Librarian","Calistarius","Divinatus Prime","shrine world","Blade Petrific","Black Rage","the Flaw","blood ritual","Librarians","psychic powers","Antros","Rhacelus","religious civil war","Space Marines"}', 'The shrine world of Divinatus Prime is lost to the Astronomican. Blood Angels Chief Librarian Mephiston leads an honour guard there and finds it gripped by religious civil war over a relic, while seeking answers about how he survived the Black Rage.', 'core', NULL, NULL, false, NULL),
  ('P5-24', 5, 'Mephiston: Revenant Crusade', 'Darius Hinks', 301, 'novel', 24, 2019, 'medium', 'novel', false, 'entry', 'Morsus', NULL, 'M42 (post-Great Rift)', 'Mephiston (Calistarius)', '{"Rhacelus","Antros"}', 'Blood Angels', 'Blood Angels', NULL, 'Military SF; Horror', '{"dark","gory","brooding","ominous"}', '{"Blood Angels","Mephiston","Lord of Death","Chief Librarian","Morsus","tomb world","Necrons","Great Rift","Cicatrix Maledictum","psychic blindness","the Blood Oath","Black Rage","daemon hunt","Rhacelus","Antros","Imperium Nihilus","psychic powers"}', 'As the Great Rift tears the galaxy apart, Mephiston''s psychic sight is rendered blind. Haunted by the ghosts of the damned, he takes his ship the Blood Oath to the war-wracked world of Morsus to find the source of his blindness.', 'core', NULL, NULL, false, NULL),
  ('P5-25', 5, 'Mephiston: City of Light', 'Darius Hinks', 384, 'novel', 25, 2020, 'medium', 'novel', false, 'entry', NULL, NULL, 'M42 (post-Devastation of Baal)', 'Mephiston (Calistarius)', '{"Magnus the Red","Rhacelus"}', 'Blood Angels', 'Blood Angels', NULL, 'Military SF; Horror', '{"dark","climactic","foreboding","intense"}', '{"Blood Angels","Mephiston","Lord of Death","Chief Librarian","Imperium Nihilus","Devastation of Baal","Great Rift","Thousand Sons","Magnus the Red","Silver Towers","Chaos ritual","sorcerers","Black Rage","psychic powers","Rhacelus","Space Marines"}', 'Deep in Imperium Nihilus after the Devastation of Baal, Mephiston and his Blood Angels are drawn by cryptic visions to a war-torn world where Thousand Sons sorcerers seek to unite nine Silver Towers in a ritual to empower Magnus.', 'core', NULL, NULL, false, NULL),
  ('P5-26', 5, 'Lemartes: Guardian of the Lost', 'David Annandale', 175, 'novel', 26, NULL, 'medium', 'novella', false, 'entry', 'Phlegethon', NULL, NULL, 'Chaplain Lemartes', NULL, 'Blood Angels (Death Company)', 'Blood Angels', NULL, 'Character Study; Horror', '{"psychological","bleak","frenzied","bloody"}', '{"Blood Angels","Lemartes","Death Company","Guardian of the Lost","Black Rage","Phlegethon","Chaplain","Chaos","Blood Disciples","madness","psychological horror","Sanguinius","Space Marines","novella"}', 'Lemartes, the Blood Angels'' Guardian of the Lost, balances on the edge of the Black Rage. Awakened to lead the Death Company into battle on the war-wracked world of Phlegethon, he must master his madness against the blood-mad servants of Chaos.', 'core', NULL, NULL, false, 'added in v3.0'),
  ('P5-27', 5, 'The Twice Dead King: The Omnibus', NULL, NULL, 'omnibus', 27, NULL, NULL, NULL, true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, NULL),
  ('P5-28', 5, 'Tomb World', 'Jonathan D. Beer', 336, 'novel', 28, 2025, 'high', 'novel', false, 'entry', NULL, NULL, NULL, 'Khemet', NULL, 'Triarch Praetorians', 'Necrons', NULL, 'Political Thriller; Mystery', '{"suspenseful","tense","dread-filled","slow-burn"}', '{"Necrons","Triarch Praetorians","Khemet","cryptek","tomb world","awakening necron empire","Imperium occupation","honour","redemption","betrayal","imprisonment","planetary conquest"}', 'As the necron empire stirs, disgraced Triarch Praetorian Khemet, freed from terrible punishment, is given one chance to restore her honour by reclaiming a tomb world now infested with humans, working with an ambitious cryptek.', 'core', 'Disgraced Triarch Praetorian; complements Twice-Dead King', NULL, false, NULL),
  ('P5-29', 5, 'Cassius', 'Ben Counter', 240, 'novel', 29, NULL, 'medium', 'novella', false, 'entry', 'Kolovan', NULL, NULL, 'Ortan Cassius', '{"Mikael Fabian","Remas"}', 'Ultramarines', 'Ultramarines', NULL, 'Military SF; Character Study', '{"zealous","grim","action-packed","vengeful"}', '{"Ultramarines","Adeptus Astartes","Chaplain","Ortan Cassius","Master of Sanctity","Tyranids","Hive Fleet Kraken","Kolovan","3rd and 5th Companies","xenos hunt","zealotry","Space Marine Legends"}', 'When a tyranid hive fleet is detected dangerously close to the Sol system, two entire companies of Ultramarines, led by their legendary Chaplain Cassius, are sent to find and destroy the aliens against impossible odds.', 'core', NULL, NULL, false, 'added in v3.0'),
  ('P5-30', 5, 'Day of Ascension', 'Adrian Tchaikovsky', 368, 'novel', 30, 2022, 'high', 'novel', false, 'entry', 'Forge world Morod', NULL, NULL, 'Gammat Triskellian and Davien (dual POV)', NULL, 'Congregation of the Divine Union (Genestealer Cult)', 'Genestealer Cults', '{"Adeptus Mechanicus"}', 'Political Thriller; Horror', '{"morally ambiguous","grim","tragic","tense"}', '{"Genestealer Cults","Adeptus Mechanicus","forge world Morod","Congregation of the Divine Union","Gammat Triskellian","Davien","uprising","rebellion","transhumanism","faith","class struggle","xenos infiltration","moral ambiguity"}', 'On the forge world Morod, the Adeptus Mechanicus live in comfort while the population toils. Genetor Gammat Triskellian, seeking advantage, uncovers a hidden congregation that believes the tech-priests bar them from salvation through union with angels.', 'core', NULL, NULL, false, NULL),
  ('P5-31', 5, 'Leviathan', 'Darius Hinks', 309, 'novel', 31, 2024, 'medium', 'novel', false, 'entry', 'Regium', NULL, 'M42 (Fourth Tyrannic War)', 'Lieutenant Castamon', NULL, 'Ultramarines (First Company)', 'Tyranids', '{"Imperium"}', 'Military SF; Horror', '{"tense","apocalyptic","dread","epic"}', '{"Ultramarines","Adeptus Astartes","Tyranids","Hive Fleet Leviathan","Regium","First Company","Lieutenant Castamon","invasion","Fourth Tyrannic War","tenth edition tie-in","alien horror","last stand"}', 'The fortress world of Regium is wracked by plagues and nightmares. Ultramarines Lieutenant Castamon recognises the signs of a Tyranid invasion and launches a strike force against a new tendril of Hive Fleet Leviathan before it reaches the planet.', 'core', NULL, NULL, false, NULL),
  ('P5-32', 5, 'Deathworlder', 'Victoria Hayward', 368, 'novel', 32, 2024, 'medium', 'novel', false, 'entry', 'Lazulai', NULL, 'M42', 'Major Wulf Khan', NULL, '903rd Catachan (Night Shrikes)', 'Astra Militarum', '{"Tyranids"}', 'Military SF; Horror', '{"bleak","tense","action-packed","darkly humorous"}', '{"Astra Militarum","Catachan Jungle Fighters","903rd Catachan Night Shrikes","Major Wulf Khan","Tyranids","Great Devourer","Lazulai","deathworld","doomed world","archeotech recovery","squad survival mission"}', 'On Lazulai, a world all but lost to the tyranids, Major Wulf Khan of the Catachan 903rd is given a final mission: lead a squad through the apocalypse to recover archeotech that could doom or deliver the Lazulai System.', 'core', 'Cross-listed; primary placement Phase 5 (Fourth Tyrannic War)', NULL, false, 'enrichment home (v3.0: Deathworlder is P5-only; former v1 P6 dup resolved)'),
  ('P5-33', 5, 'Ghazghkull Thraka: Prophet of the Waaagh!', 'Nate Crowley', 272, 'novel', 33, 2022, 'high', 'novel', false, 'entry', NULL, NULL, NULL, 'Makari the Grot', '{"Ghazghkull Mag Uruk Thraka","Inquisitor Tytonida Falx"}', 'Orks (Goffs)', 'Orks', NULL, 'Character Study; War Epic', '{"darkly humorous","satirical","irreverent","epic"}', '{"Orks","Ghazghkull Mag Uruk Thraka","Makari the Grot","Inquisitor Tytonida Falx","Ordo Xenos","Waaagh!","Gork and Mork","greenskin culture","unreliable narrator","framing narrative","warboss origin","dark comedy"}', 'The full story of the dreaded ork warlord Ghazghkull Thraka, the Beast of Armageddon, told to the Inquisition by his faithful banner bearer, the grot Makari, as Lord Inquisitor Tytonida Falx seeks the truth of his rise.', 'core', 'Read after Phase 6 ''Helsreach'' for maximum effect', NULL, false, NULL),
  ('P5-34', 5, 'Brutal Kunnin''', 'Mike Brooks', 288, 'novel', 34, 2021, 'medium', 'novel', false, 'entry', 'Forge world Hephaesto', NULL, NULL, 'Ufthak Blackhawk', '{"Kaptin Badrukk","Da Meklord"}', 'Orks (Bad Moons)', 'Orks', NULL, 'Military SF', '{"darkly humorous","action-packed","irreverent","fast-paced"}', '{"Orks","Bad Moons","Ufthak Blackhawk","Kaptin Badrukk","Da Meklord","Adeptus Mechanicus","forge world Hephaesto","Freebooterz","Waaagh!","loot raid","first ork-POV novel","sinister war machine"}', 'When Ufthak Blackhawk and the green tide descend on the Adeptus Mechanicus forge world Hephaesto, they find it already besieged by the Freebooter Kaptin Badrukk. Ordered to co-operate, Ufthak schemes to claim the greatest prize.', 'core', NULL, NULL, false, NULL),
  ('P5-35', 5, 'Da Big Dakka', 'Mike Brooks', 320, 'novel', 35, 2023, 'high', 'novel', false, 'entry', 'Commorragh', 'The Webway', NULL, 'Ufthak Blackhawk', '{"Da Meklord","Archon Dhaemira"}', 'Orks (Bad Moons)', 'Orks', NULL, 'Military SF; Quest/Adventure', '{"darkly humorous","violent","madcap","action-packed"}', '{"Orks","Bad Moons","Ufthak Blackhawk","Drukhari","Commorragh","the Webway","gladiatorial combat","Archon Dhaemira","Da Meklord","kabals","haemonculus covens","xenos versus xenos","dark comedy"}', 'Out of options, Ufthak Blackhawk leads his Waaagh! through the webway to Commorragh, the Dark City, where he is thrown into gladiatorial combat against an archon determined to rule, even if it means the city''s ruin.', 'core', 'Sequel to Brutal Kunnin', NULL, false, NULL),
  ('P5-36', 5, 'Elemental Council', 'Noah Van Nguyen', 498, 'novel', 36, 2024, 'medium', 'novel', false, 'entry', 'Cao Quo', 'Ultima Segmentum', 'Fifth Sphere Expansion (M42)', 'Ensemble council: Swordlight (Fire), Ke (Earth), Sei (Air), Orr (Water)', NULL, 'T''au Empire (cross-caste council)', 'T''au', NULL, 'Military SF; Political Thriller', '{"grim","morally grey","tense","intrigue-laden"}', '{"T''au Empire","Greater Good","caste system","ethereal caste","fire caste","water caste","air caste","earth caste","Kroot","insurgency","planetary rebellion","counterinsurgency","Brother-Sergeant Artamax","Raptors Chapter","Fifth Sphere Expansion","espionage","political intrigue","colonial occupation","moral ambiguity"}', 'Since the T''au annexed Cao Quo, its human population has resisted the Greater Good. As a Space Marine-led insurgency grows, the ethereal Yor''i assembles an elite cross-caste council to quell the uprising before full planetary insurrection erupts.', 'core', 'Deep dive into T''au society and Ethereal Caste', NULL, false, NULL),
  ('P5-37', 5, 'Farsight: Blade of Truth', 'Phil Kelly', 408, 'novel', 37, 2025, 'low', 'novel', false, 'entry', 'Vior''los', 'Eastern Fringe', NULL, 'Commander Farsight (O''Shovah)', '{"Aun''Va","Torchstar"}', 'Farsight Enclaves', 'T''au', '{"Tyranids"}', 'Military SF; War Epic', '{"desperate","action-packed","introspective","last-stand"}', '{"T''au Empire","Farsight Enclaves","Commander Farsight","Vior''la Sept heritage","XV8 battlesuit","Dawn Blade","Tyranid invasion","Hive Fleet","ethereal caste","Aun''Va","exile and return","last stand","Greater Good","Eastern Fringe"}', 'In self-imposed exile on the desert world Vior''los, the legendary Commander Farsight has laid down his blade. But when a tyranid bio-fleet threatens his Enclaves and the scheming ethereal Aun''Va manoeuvres against him, he must take up arms once more.', 'core', 'Direct sequel to Phase 3 Farsight Omnibus; Fourth Tyrannic War era', NULL, false, NULL),
  ('P5-38', 5, 'Path of the Eldar (Omnibus)', NULL, NULL, 'omnibus', 38, NULL, NULL, NULL, true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, NULL),
  ('P5-39', 5, 'Asurmen: Hand of Asuryan', 'Gav Thorpe', 272, 'novel', 39, 2015, 'medium', 'novel', false, 'entry', 'Craftworld Ulthwe', 'Segmentum Obscurus', 'Dual timeline: the Fall (pre-M30) and M41', 'Asurmen', '{"Jain Zar","Maugan Ra","Karandras"}', 'Dire Avengers (Phoenix Lord)', 'Aeldari', NULL, 'War Epic; Character Study', '{"mythic","heroic","non-linear","reflective"}', '{"Aeldari","Phoenix Lords","Asurmen","Dire Avengers","Aspect Warriors","the Fall of the Eldar","founding of aspect shrines","Craftworld Ulthwe","Chaos incursion","non-linear narrative","eldar mythology","Asuryan","immortal warrior","founding myth","Slaanesh"}', 'The Phoenix Lords are demigods of battle; Asurmen, the Hand of Asuryan, was the first. This dual narrative tells of the founding of the Dire Avengers during the Fall, and of Asurmen today as he fights the forces of Chaos threatening to overwhelm Ulthwe.', 'core', 'First Phoenix Lord; Dire Avengers origin', NULL, false, NULL),
  ('P5-40', 5, 'Jain Zar: The Storm of Silence', 'Gav Thorpe', 352, 'novel', 40, NULL, 'high', 'novel', false, 'entry', 'Craftworld Ulthwe', 'Segmentum Obscurus', 'Post-Fall early eldar history (precise date UNKNOWN)', 'Jain Zar', '{"Eldrad Ulthran","Asurmen"}', 'Howling Banshees (Phoenix Lord)', 'Aeldari', NULL, 'War Epic; Character Study', '{"mythic","dual-timeline","action-packed","tragic"}', '{"Aeldari","Phoenix Lords","Jain Zar","Howling Banshees","Aspect Warriors","the Fall of the Eldar","founding of aspect shrines","Asurmen","Eldrad","Craftworld Ulthwe","Orks","foresight","dual narrative","eldar mythology"}', 'Jain Zar, the Storm of Silence, is Phoenix Lord of the Howling Banshees. When a burgeoning ork empire threatens the eldar, she travels to Craftworld Ulthwe to warn them, only to find her plans opposed by the seer Eldrad.', 'core', NULL, NULL, false, 'added in v3.0; page_count: two runs agree'),
  ('P5-41', 5, 'Ghost Warrior', 'Gav Thorpe', 368, 'novel', 41, NULL, 'medium', 'novel', false, 'entry', 'Craftworld Iyanden / Craftworld Zaisuthra', 'Ultima Segmentum', 'Post-Great Rift (M42)', 'Iyanna Arienal', '{"Yvraine","the Visarch"}', 'Craftworld Iyanden (Ynnari-aligned)', 'Aeldari', NULL, 'Quest/Adventure; Military SF', '{"dark","haunting","eerie","slow-burn"}', '{"Aeldari","Ynnari","Ynnead","Craftworld Iyanden","spiritseer","ghost warriors","wraith constructs","cronesword","lost craftworld","the Great Rift","the webway","Yvraine","god of the dead","Slaanesh''s curse","tyranids","quest for artefact"}', 'Still reeling from the Great Rift and tyranid attacks, Iyanden receives a message from the long-lost craftworld Zaisuthra. Spiritseer Iyanna and Yvraine of the Ynnari lead an expedition to make contact, secretly seeking the final cronesword needed to awaken the god Ynnead.', 'core', NULL, NULL, false, 'added in v3.0'),
  ('P5-42', 5, 'Wild Rider', 'Gav Thorpe', 384, 'novel', 42, NULL, 'medium', 'novel', false, 'entry', 'Craftworld Saim-Hann / Agarimethea', 'Segmentum Pacificus', 'Post-Great Rift / Dark Imperium (M42)', 'Nuadhu Fireheart', '{"Yvraine","Aradryan","Eldrad Ulthran"}', 'Craftworld Saim-Hann (Clan Fireheart / Wild Riders)', 'Aeldari', NULL, 'Military SF; Political Thriller', '{"character-driven","political","action-packed","tribal"}', '{"Aeldari","Ynnari","Ynnead","Craftworld Saim-Hann","Wild Riders","Clan Fireheart","jetbikes","Necrons","tomb world","awakening necrontyr","Yvraine","cronesword quest","clan politics","honour","Dark Imperium","alliance"}', 'The Wild Riders of Saim-Hann are renowned for their daring, none more than Wild Lord Nuadhu Fireheart. Having awoken a slumbering necron tomb world, Nuadhu must seek alliance with Yvraine''s Ynnari to defend his craftworld, but what are Yvraine''s true motives?', 'core', NULL, NULL, false, 'added in v3.0'),
  ('P5-43', 5, 'Voidscarred', 'Mike Brooks', 350, 'novel', 43, 2021, 'medium', 'novel', false, 'entry', 'Mobile (corsair fleet, the void)', 'Mobile/Fleet', NULL, 'Baron Myrin Stormdawn', NULL, 'Starsplinters (Aeldari Corsairs)', 'Aeldari', '{"Orks"}', 'Quest/Adventure; Political Thriller', '{"swashbuckling","darkly humorous","adventurous","rollicking"}', '{"Aeldari","Aeldari Corsairs","Starsplinters","void piracy","Craftworld Ilmaren","Taenar Leotharan","Princess Tishria","Badskab Bukkaneers","Uzgul da Magnificent","ork Freebooterz","space opera","raiders","dirty politics","freedom vs structure","exile","Drukhari","Exodites","swashbuckling","alien society"}', 'The Starsplinters are aeldari corsairs, and Baron Myrin Stormdawn one of their greatest. When his feud with ork freebooters escalates, he is forced into an alliance with Taenar, an exiled craftworld admiral, while navigating the treacherous politics of his own kind.', 'core', 'Aeldari Corsairs; Craftworld politics; first major new Aeldari novel in years', NULL, false, NULL),
  ('P5-44', 5, 'Fulgrim: The Perfect Son', 'Jude Reid', 320, 'novel', 44, 2025, 'high', 'novel', false, 'entry', 'Crucible', NULL, 'Era Indomitus (post-Great Rift, M42)', 'Marduk Tamaris', '{"Fulgrim"}', 'The Perfecti (Emperor''s Children)', 'Emperor''s Children', '{"Chaos"}', 'Military SF; War Epic', '{"decadent","treacherous","grim","tragic"}', '{"Emperor''s Children","Chaos Space Marines","Daemon Primarch Fulgrim","the Perfecti","Slaanesh","warband rivalry","siege warfare","Black Templars","Emperor''s Champion","ambition and excess","betrayal","Era Indomitus","planetary conquest","III Legion","perfectionism","internecine conflict"}', 'The Emperor''s Children have fractured into warbands. Now the ascended daemon primarch Fulgrim challenges his scattered sons to conquer the Imperial world of Crucible and slay its Black Templar defender, but his plans run deeper, and the assault becomes a gruelling siege of ambition and betrayal.', 'core', 'Daemon Primarch returns to active play', NULL, false, NULL),
  ('P6-01', 6, 'Gaunt''s Ghosts: The Founding (Omnibus)', 'Dan Abnett', 768, 'omnibus', 1, NULL, 'medium', 'omnibus', true, 'entry', 'Sabbat Worlds', NULL, NULL, NULL, NULL, 'Tanith First and Only', 'Astra Militarum', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, 'pre-project read (complete); mark complete in app; page_count: GR/S&S; new ed 880'),
