  ('P6-04', 6, 'Gaunt''s Ghosts: The Victory (Omnibus 1 & 2)', 'Dan Abnett', 1597, 'omnibus', 4, NULL, 'medium', 'omnibus', true, 'entry', 'Sabbat Worlds', NULL, NULL, NULL, NULL, 'Tanith First and Only', 'Astra Militarum', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, 'pre-project read (complete); mark complete in app; page_count: Victory Part1 960 + Part2 637'),
  ('P6-05', 6, 'Minka Lesk: The Last Whiteshield (Omnibus)', 'Justin D. Hill', NULL, 'omnibus', 5, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Astra Militarum', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, 'omnibus container; components carry data'),
  ('P6-08', 6, 'Arcady Pride', 'Justin D. Hill', NULL, 'short', 800, NULL, 'pending', 'short_story', false, 'entry', 'Malouri', NULL, 'M42', 'Minka Lesk', '{"Blanchez","Yedrin"}', 'Cadian 101st', 'Astra Militarum', NULL, 'Character Study', '{"reflective","quiet","intimate"}', '{"aftermath of battle","rest between battles","storytelling","sanitised vs true war stories","camaraderie","oral history","character vignette","Cadian memory"}', 'In the immediate aftermath of Traitor Rock, Minka Lesk drinks with comrades in the conquered city, swapping sanitised stories of old Cadia, until a colour sergeant demands to hear what really happened.', 'core', NULL, NULL, false, NULL),
  ('P6-09', 6, 'Shadow of the Eighth', 'Justin D. Hill', 300, 'novel', 900, NULL, 'medium', 'novel', false, 'entry', 'Telken''s Rest', NULL, 'M42', 'Minka Lesk', '{"Lord General Bendikt","Ursarkar E. Creed"}', 'Cadian 101st', 'Astra Militarum', NULL, 'Military SF; Quest/Adventure', '{"grim","haunting","melancholic"}', '{"missing 8th Regiment","relic","Chaos warlord Drakul-zar","icy hab-blocks","manufactoria","legacy","haunting past","quest","Cadian honour","avenging the homeworld"}', 'When the Cadian 101st recover a relic of the missing Cadian 8th, they follow its trail to Telken''s Rest, a frozen world at the core of Chaos warlord Drakul-zar''s collapsing regime, confronting their own legacy.', 'core', NULL, NULL, false, NULL),
  ('P6-10', 6, 'Fen Guard', 'Justin D. Hill', NULL, 'short', 1000, NULL, 'pending', 'short_story', false, 'entry', 'Drook (Drookian home world)', NULL, 'M42', 'Grawnya', '{"Minka Lesk"}', 'Drookian Fen Guard', 'Astra Militarum', NULL, 'Character Study', '{"somber","tragic","intimate"}', '{"frame narrative","Drookian Fen Guard","guest right broken","clan warfare","betrayal","homeworld tale","oral storytelling","sacred rites"}', 'Captain Minka Lesk sits with a Drookian Fen Guard soldier, Grawnya, who recounts a tale of her home world: a rival clan breaking guest right and trying to wipe out her clan.', 'core', NULL, NULL, false, NULL),
  ('P6-11', 6, 'Hell''s Last', 'Justin D. Hill', 416, 'novel', 1100, NULL, 'medium', 'novel', false, 'entry', 'Alia (Gallows Cluster)', NULL, 'M42', 'Minka Lesk', '{"Commissar Shand","Confessor Talbeas","Grawnya"}', 'Cadian 101st', 'Astra Militarum', NULL, 'Military SF', '{"tense","claustrophobic","grim","survival-driven"}', '{"Gallows Cluster siege","jungle death world","deadly environment","mad gambit","regiment fracturing","survival","logistics","command pressure","Cadian legacy"}', 'When a new threat surges through the Gallows Cluster, Captain Minka Lesk''s company leads a desperate gambit on the world of Alia, where the jungle itself is as deadly as any enemy and the regiment fractures around her.', 'core', NULL, NULL, false, NULL),
  ('P6-12', 6, 'Creed: Ashes of Cadia', 'Jude Reid', 400, 'novel', 1200, NULL, 'high', 'novel', false, 'entry', 'Cadia (ruins)', 'Segmentum Obscurus', 'M42', 'Ursula Creed', '{"Roboute Guilliman","Ursarkar E. Creed"}', 'Cadian Shock Troops', 'Astra Militarum', NULL, 'Military SF; Horror', '{"bleak","harrowing","gory","introspective"}', '{"burden of legacy","daughter of Creed","Lord Castellan","mission to ruined Cadia","propaganda","ruins of Cadia","what became of those left behind","Cadian identity","penal legionnaire","medical horror"}', 'Lord Castellan Ursula Creed, dispatched by Roboute Guilliman, returns to the shattered ruins of her father''s homeworld to recover Ursarkar Creed''s final battle plans, finding the planet a hellscape of deadly secrets.', 'core', NULL, NULL, false, NULL),
  ('P6-13', 6, 'Leontus: Lord Solar', 'Rob Young', 208, 'novel', 1300, NULL, 'high', 'novel', false, 'entry', 'Fortuna Minor', NULL, 'M42 (Indomitus Crusade)', 'Arcadian Leontus', NULL, 'Mixed Astra Militarum task force (Catachan; Death Korps; Attilan Rough Riders)', 'Astra Militarum', NULL, 'Military SF; Character Study', '{"fast-paced","grim","desperate"}', '{"stranded commander","orks","Speed Waaagh!","survival against odds","guerrilla campaign","ragtag survivors","tactical genius","saviour pod","enslaved population","ork effigies","rebuilding an army","Belgutei","Keori Arnetz","steed Konstantin"}', 'After his fleet is undone by orkish cunning, Lord Commander of the Segmentum Solar Arcadian Leontus crash-lands on ork-overrun Fortuna Minor and, stripped of his armies, sets out not merely to survive but to win.', 'core', NULL, NULL, false, NULL),
  ('P6-14', 6, 'Krieg', 'Steve Lyons', 304, 'novel', 1400, NULL, 'medium', 'novel', false, 'entry', 'Hive Arathron (Octarius War Zone)', NULL, 'Octarius War (M41/M42)', 'Renick', NULL, 'Death Korps of Krieg', 'Astra Militarum', NULL, 'Military SF; War Epic', '{"grim","haunting","bleak","mournful"}', '{"Death Korps origins","split timeline","Krieg civil war","nuclear devastation","atonement","guilt","Octarius War","siege","attrition","dehumanisation","faceless soldiers","duty and sacrifice","Colonel Drakon","Inquisitor Ven Bruin"}', 'The Death Korps of Krieg lay siege to a captured hive city on the edge of the Octarius War, securing the cordon against orks and tyranids, in a tale interwoven with the nuclear civil war that forged their dead world.', 'core', NULL, NULL, false, 'CORR: segmentum was Ultima in run -> UNKNOWN (Octarius not segmentum-sourced, no chain-inference); protagonist Renick to verify (multi-POV blurb)'),
  ('P6-15', 6, 'Siege of Vraks', 'Steve Lyons', 304, 'novel', 1500, NULL, 'high', 'novel', false, 'entry', 'Vraks Prime', 'Segmentum Obscurus', '812.M41 (18-year siege)', 'Tyborc', NULL, 'Death Korps of Krieg (88th Siege Army)', 'Astra Militarum', NULL, 'Military SF; War Epic', '{"bleak","brutal","attritional","immersive"}', '{"seventeen-year siege","armoury world","Apostate Cardinal-Astra Xaphan","heresy","trench warfare","attrition","daemons and heretics","defiant loyalty","self-sacrifice","WWI-scale","Scarus Sector","bleak"}', 'After the armoury world Vraks falls to an apostate cardinal, the Astra Militarum musters the Death Korps of Krieg for a seventeen-year siege to reclaim it, won inch by bloody inch against heretics and daemons.', 'core', NULL, NULL, false, 'CORR: date run said 813.M41/17yr -> 812.M41/18yr per Lexicanum (arrival 790812.M41, 18-year siege)'),
  ('P6-17', 6, 'Honour Imperialis (Omnibus)', 'multi-author', NULL, 'omnibus', 17, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Astra Militarum', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, 'omnibus container; components carry data'),
  ('P6-18', 6, 'Glory Imperialis (Omnibus)', 'multi-author', NULL, 'omnibus', 18, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Astra Militarum', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, 'omnibus container; components carry data'),
  ('P6-19', 6, 'Baneblade', 'Guy Haley', 416, 'novel', 1900, NULL, 'high', 'novel', false, 'entry', 'Kalidar IV (Kalidar system)', 'Segmentum Tempestus', 'M41', 'Colaron Lo Bannick', NULL, 'Paragonian 7th (super-heavy tank company)', 'Astra Militarum', NULL, 'Military SF', '{"fast-paced","hard-hitting","action-packed","grim"}', '{"super-heavy tank warfare","Baneblade","Astra Militarum armour","Orks","tank crew","clan rivalry","redemption","Kalidar","Adeptus Mechanicus","Paragonian nobility","siege warfare","machine spirit","class conflict"}', 'From the forges of Mars comes the Baneblade Mars Triumphant. As part of the Paragonian 7th, Honoured Lieutenant Bannick commands the super-heavy tank in a bitter war against orks in the Kalidar system, as old clan prejudices resurface.', 'core', NULL, NULL, false, 'CORR: protagonist run said Marken Cortein Lo Bannick -> Colaron Lo Bannick (Lexicanum: Colaron Vor Artem Lo Bannick; titlelist hint wrong)'),
  ('P6-20', 6, 'Shadowsword', 'Guy Haley', 398, 'novel', 2000, NULL, 'medium', 'novel', false, 'entry', 'Geratomro', 'Segmentum Tempestus', 'M41', 'Colaron Lo Bannick', NULL, 'Paragonian 7th (super-heavy tank company)', 'Astra Militarum', NULL, 'Military SF', '{"tense","twisty","grimdark","action-packed"}', '{"super-heavy tank warfare","Shadowsword","Baneblade","Titan-hunters","Astra Militarum armour","planetary rebellion","Inquisition","faith and doubt","Geratomro","Paragonian 7th","crisis of faith"}', 'Arriving in the Geratomro warzone, Honoured Lieutenant Bannick and the crew of the Baneblade Cortein''s Honour support a company of Shadowsword Titan-hunters in a deadly battle for three star systems, as new allies cast doubt on all Bannick knows.', 'core', NULL, NULL, false, 'CORR: protagonist -> Colaron Lo Bannick (s.o.); REMOVED roster-bleed tags ''Black Templars'',''Space Marines'' (unsourced for this book); page_count: HC 304 / PB 398'),
  ('P6-21', 6, 'Steel Tread', 'Andy Clark', 368, 'novel', 2100, NULL, 'high', 'novel', false, 'entry', 'Croatoas', NULL, 'M42 (post-Great Rift)', 'Hadeya Etsul', NULL, 'Cadian armoured regiment', 'Astra Militarum', NULL, 'Military SF', '{"tense","claustrophobic","gritty"}', '{"tank warfare","Leman Russ Demolisher","Cadians","consolidated regiment","dysfunctional crew","Chaos","Great Rift","machine spirit","leadership","trust","Croatoas","regimental culture","redemption"}', 'On war-torn Croatoas, the Astra Militarum battle the servants of Chaos. Tanker Hadeya Etsul is consolidated into a Cadian regiment and given command of the Leman Russ Demolisher Steel Tread, leading a dysfunctional crew into a death-or-glory offensive.', 'core', NULL, NULL, false, NULL),
  ('P6-22', 6, 'Catachan Devil', 'Justin Woolley', 336, 'novel', 2200, NULL, 'high', 'novel', false, 'entry', 'Gondwa VI', NULL, NULL, 'Colonel Haskell ''Hell Fist'' Aldalon', NULL, 'Catachan 57th Jungle Fighters', 'Astra Militarum', NULL, 'Military SF', '{"action-packed","brutal","darkly humorous","visceral"}', '{"jungle warfare","Catachan Jungle Fighters","Orks","greenskins","deathworld soldiers","raw recruit","trial by fire","ork kommandos","Gondwa VI","survival","military comedy","Imperial propaganda","courage and cowardice","outpost assault"}', 'Colonel Haskell ''Hell Fist'' Aldalon and the Catachan 57th Jungle Fighters arrive on quagmire world Gondwa VI to fight a growing greenskin threat, going on the offensive to retake an outpost while saddled with barely-trained Trooper Torvin of the Skadi Second Infantry.', 'core', NULL, NULL, false, NULL),
  ('P6-23', 6, 'Witchbringer', 'Steven B. Fischer', 304, 'novel', 2300, NULL, 'medium', 'novel', false, 'entry', 'Visage', NULL, 'M42 (post-Great Rift)', 'Glavia Aerand', NULL, 'Scholastica Psykana; Cadian 900th Regiment', 'Astra Militarum', NULL, 'Horror; Character Study', '{"bleak","eerie","isolating","dread"}', '{"sanctioned psyker","Scholastica Psykana","Cadians","psychic powers","warp","cosmic horror","isolation","fear of the other","premonition","haunted world","Traitor Guard","mist and fog","psychic artefact","alienation"}', 'On the eve of her sanctioning as a primaris psyker, former Cadian captain Glavia Aerand receives a premonition about her old regiment and a dangerous artefact, sending her into a vicious campaign on the psychically active, fog-shrouded world of Visage.', 'core', NULL, NULL, false, NULL),
  ('P6-24', 6, 'Longshot', 'Rob Young', 368, 'novel', 2400, NULL, 'high', 'novel', false, 'entry', 'Attruso (manufactorum world)', NULL, 'Indomitus Crusade (M42)', 'Sergeant Darya Nevic', NULL, 'Cadian 217th (sniper squad)', 'Astra Militarum', NULL, 'Military SF', '{"gritty","tense","brutal"}', '{"sniper warfare","Cadians","T''au Empire","counter-sniping","manufactorum world","propaganda","heroism and fame","transplant soldier","winter warfare","city fighting","morale","doubt","Attruso","psychological pressure","Indomitus Crusade"}', 'Transplant, Cadian, sniper, legend - Sergeant Darya Nevic is all of these. During the Cadian 217th''s assault on the manufactorum world of Attruso, she must confront her doubts and an impossible choice as winter closes in and her soldiers die.', 'core', NULL, NULL, false, NULL),
  ('P6-25', 6, 'Kasrkin', 'Edoardo Albert', 416, 'novel', 2500, NULL, 'high', 'novel', false, 'entry', 'Dasht i-Kevar', NULL, NULL, 'Captain Bharath Obeysekera', NULL, 'Cadian Kasrkin', 'Astra Militarum', NULL, 'Military SF; Quest/Adventure', '{"tense","gritty","atmospheric","tragic"}', '{"special forces","Cadian Kasrkin","T''au Empire","desert survival","rescue mission","behind enemy lines","elite soldiers","commissar","squad dynamics","ancient buried threat","sandstorms","Dasht i-Kevar","hostile terrain","missing general"}', 'When the t''au down a Valkyrie carrying an Astra Militarum general on besieged Dasht i-Kevar, only an elite Cadian Kasrkin squad can retrieve him. Captain Obeysekera and his soldiers must cross an endless, implacable desert that hides something ancient.', 'core', NULL, NULL, false, NULL),
  ('P6-26', 6, 'Honourbound', 'Rachel Harrison', 496, 'novel', 2600, NULL, 'high', 'novel', false, 'entry', 'Bale Stars', NULL, NULL, 'Commissar Severina Raine', '{"Andren Fel","Daven Wyck","Lydia Zane"}', '11th Antari Rifles', 'Astra Militarum', NULL, 'Military SF; Character Study', '{"grim","gritty","intense","character-driven"}', '{"commissar","Astra Militarum","Bale Stars Crusade","Chaos cult","the Sighted","faith and duty","loyalty","family","troubled past","attritional warfare","military discipline","mystery","11th Antari Rifles","psyker","stormtroopers","character study"}', 'Uncompromising Commissar Severina Raine, attached to the 11th Antari Rifles, instils order amid the Bale Stars Crusade led by Lord-General Militant Alar Serek against the Chaos cult known as the Sighted. As the campaign grinds on, dark secrets surface that touch her own past.', 'core', NULL, NULL, false, NULL),
  ('P6-27', 6, 'Demolisher', 'Andy Clark', 368, 'novel', 2700, NULL, 'low', 'novel', false, 'entry', 'Croatoas (Ruega Front)', NULL, 'M42 (post-Great Rift)', 'Lieutenant Commander Hadeya Etsul', NULL, 'Cadian armoured regiment', 'Astra Militarum', NULL, 'Military SF', '{"tense","claustrophobic","haunting"}', '{"tank warfare","Leman Russ Demolisher","Cadians","convoy escort","lord commissar","Chaos","Great Rift","fog of war","leadership","crew dynamics","nemesis","duty","Croatoas","sequel","command pressure"}', 'The war for warp-cursed Croatoas rages on. Hailed as ''Giant-killers'' after Operation Jotunn, Hadeya Etsul and the crew of the Leman Russ Demolisher Steel Tread escort a legendary lord commissar through contested territory, facing an unseen nemesis.', 'core', NULL, NULL, false, NULL),
  ('P6-29', 6, 'Last Chancers (Omnibus)', 'Gav Thorpe', NULL, 'omnibus', 29, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Astra Militarum', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, 'omnibus container; components carry data'),
