  ('P6-31', 6, 'Ciaphas Cain: Defender of the Imperium (Omnibus 2)', 'Sandy Mitchell', NULL, 'omnibus', 31, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Astra Militarum', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, 'omnibus container; components carry data'),
