  ('P6-33', 6, 'Choose Your Enemies', 'Sandy Mitchell', 400, 'novel', 3300, NULL, 'low', 'novel', false, 'entry', 'Ironfound (forge world)', NULL, NULL, 'Ciaphas Cain', '{"Jurgen","Amberley Vail","Regina Kasteen","Jenit Sulla"}', 'Valhallan 597th', 'Astra Militarum', NULL, 'Military SF; Mystery', '{"comedic","action-packed","dry wit"}', '{"Ciaphas Cain","Astra Militarum","Valhallan 597th","Chaos cult","forge world","Ironfound","heresy","munitions","Eldar raiders","traitor hunt","investigation","dark comedy"}', 'After crushing a Chaos cult uprising on a mining world, Cain and the Valhallan 597th find evidence the corruption has reached the vital munitions forge world of Ironfound, and must root out heresy amid allies and enemies old and new.', 'core', NULL, NULL, false, NULL),
  ('P6-34', 6, 'Vainglorious', 'Sandy Mitchell', 400, 'novel', 3400, NULL, 'low', 'novel', false, 'entry', 'Newly founded forge world (Damocles Gulf region)', 'Eastern Fringe', '992.M41', 'Ciaphas Cain', '{"Jurgen","Amberley Vail"}', NULL, NULL, NULL, 'Political Thriller; Military SF', '{"satirical","comedic","action-packed"}', '{"Ciaphas Cain","Astra Militarum","Commissariat","Adeptus Mechanicus","forge world","skitarii","tech-heresy","assassination","conspiracy","Damocles Gulf","political intrigue","satire"}', 'With weapon shipments from a new forge world drying up, the retirement-seeking Cain investigates, navigating assassination attempts, mutinous skitarii and heresy within the Adeptus Mechanicus, and a hidden foe threatening Imperial rule in the Damocles Gulf.', 'core', NULL, NULL, false, NULL),
  ('P6-35', 6, 'Double Eagle', 'Dan Abnett', 416, 'novel', 3500, NULL, 'high', 'novel', false, 'entry', 'Enothis', 'Segmentum Pacificus', '773.M41', 'Bree Jagdea', '{"Oskar Viltry","Vander Marquall","August Kaminsky"}', 'Phantine XX (Phantine Fighter Corps)', 'Astra Militarum', NULL, 'Military SF; War Epic', '{"intense","tense","tragic","adrenaline-fuelled"}', '{"Aeronautica Imperialis","Imperial Navy","Phantine Air Corps","Phantine XX","Sabbat Worlds Crusade","Enothis","aerial dogfights","fighter pilots","Chaos archenemy","Blood Pact","ace pilot","ensemble cast","attrition warfare"}', 'On the beleaguered Sabbat world of Enothis, the elite fighter pilots of the Phantine XX and Imperial Navy wings fight a desperate aerial war to hold back closing Chaos forces and a feared Chaos ace as refugees flee below.', 'core', NULL, NULL, false, NULL),
  ('P6-36', 6, 'Interceptor City', 'Dan Abnett', 407, 'novel', 3600, NULL, 'medium', 'novel', false, 'entry', 'Vesperus (Lysander)', 'Segmentum Pacificus', 'M41 (Sabbat Worlds; 22 years after Double Eagle)', 'Bree Jagdea', '{"Oskar Viltry"}', 'Circus 66 squadron (Imperial Navy / Aeronautica)', 'Astra Militarum', NULL, 'Military SF; Character Study', '{"claustrophobic","tense","melancholic","gripping"}', '{"Aeronautica Imperialis","Imperial Navy","Circus 66","Sabbat Worlds Crusade","Lysander","Vesperus hive","aerial combat","interception runs","ruined hive city","veteran pilot","trauma","suspected traitor"}', 'Set 22 years after Double Eagle, burned-out former ace Bree Jagdea is pulled from safe cargo runs into the infamous Circus 66 squadron, flying lethal interception runs through the ruined hive city of Vesperus on Lysander.', 'core', NULL, NULL, false, NULL),
  ('P6-37', 6, 'Enforcer: The Shira Calpurnia Omnibus', 'Matthew Farrer', NULL, 'omnibus', 37, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Adeptus Arbites', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, 'omnibus container; components carry data'),
  ('P6-38', 6, 'Flesh and Steel', 'Guy Haley', 312, 'novel', 3800, NULL, 'medium', 'novel', false, 'entry', 'Varangantua (Alecto)', NULL, 'M41/M42 (deliberately ambiguous)', 'Probator Symeon Noctis', '{"Rho-1 Lux"}', 'Varangantua Enforcers', 'Enforcers', NULL, 'Mystery; Political Thriller', '{"noir","grim","atmospheric","tense"}', '{"Warhammer Crime","Varangantua","Alecto","Adeptus Mechanicus","Collegiate Extremis","probator","murder investigation","tech-heresy","illegal servitors","odd-couple detectives","hive city","corruption","noir"}', 'Wealthy-born probator Symeon Noctis, championing Nearsteel''s powerless, investigates a bisected corpse found in the neutral zone beside an Adeptus Mechanicus enclave, partnering tech-priest Rho-1 Lux and uncovering tech-heresy and exploitation.', 'core', NULL, NULL, false, 'CORR: segmentum run said Tempestus -> UNKNOWN (Alecto segmentum not sourced); author Guy Haley verified by run (corrects earlier Hinks assumption)'),
  ('P6-39', 6, 'Bloodlines', 'Chris Wraight', 320, 'novel', 3900, NULL, 'medium', 'novel', false, 'entry', 'Varangantua (Alecto)', NULL, 'M41/M42 (deliberately ambiguous)', 'Probator Agusto Zidarov', NULL, 'Varangantua Enforcers', 'Enforcers', NULL, 'Mystery; Political Thriller', '{"noir","gritty","grounded","slow-burn"}', '{"Warhammer Crime","Varangantua","Alecto","Varangantuan Enforcers","probator","missing-person case","criminal cartels","corporate warfare","corruption","noir detective","hive city underbelly","family secrets"}', 'In the vast hive city of Varangantua, enforcer-probator Agusto Zidarov is tasked with finding the missing scion of a wealthy family, a search that draws him into criminal cartels, corporate warfare and buried secrets kept by powerful hands.', 'core', NULL, NULL, false, 'CORR: segmentum run said Tempestus -> UNKNOWN; author Chris Wraight verified by run'),
  ('P6-40', 6, 'Hive: Part I', 'Dan Abnett', 368, 'novel', 4000, NULL, 'low', 'novel', false, 'entry', 'Sacramentus (hive city)', NULL, NULL, NULL, NULL, NULL, 'Adeptus Arbites', NULL, 'Political Thriller; Mystery', '{"oppressive","grim","conspiratorial","atmospheric"}', '{"hive city","Adeptus Arbites","Lex Imperialis","planetary governor","political scandal","austerity","rebellion","outsider ruler","civic collapse","underclass unrest","conspiracy","vertical slum society","lurking threat"}', 'Beneath the smog of the hive city Sacramentus, the planetary governor has fallen in scandal and an outsider is crowned. Adeptus Arbites enforce the Lex Imperialis without mercy as whispers of rebellion rise from the depths.', 'core', NULL, NULL, false, '2026 release; sparse sourcing, most fields UNKNOWN (acceptable - lieber Luecke als Erfindung)'),
  ('P6-41', 6, 'Hive: Part II', 'Dan Abnett', 400, 'novel', 4100, NULL, 'low', 'novel', false, 'entry', 'Sacramentus (hive city)', NULL, NULL, NULL, NULL, NULL, 'Adeptus Arbites', NULL, 'Political Thriller; Mystery', '{"oppressive","grim","conspiratorial","atmospheric"}', '{"hive city","Adeptus Arbites","Lex Imperialis","political scandal","rebellion","austerity","civic collapse","underclass unrest","conspiracy","order versus anarchy","lurking threat","two-part novel"}', 'The second half of Abnett''s two-part tale of Sacramentus, as the divided hive city teeters between order and anarchy, the Adeptus Arbites enforce Imperial law without pity, and a deeper threat stirs in the depths below.', 'core', NULL, NULL, false, '2026 release; sparse sourcing'),
  ('P6-42', 6, 'Titanicus', 'Dan Abnett', 400, 'novel', 4200, NULL, 'medium', 'novel', false, 'entry', 'Orestes (forge world)', 'Segmentum Pacificus', '779.M41 (Time of Ending)', 'Ensemble cast (multiple POV)', '{"Erik Varco","Cally Samstag","Tolemy"}', 'Adeptus Mechanicus, Legio Invicta', 'Adeptus Mechanicus', NULL, 'War Epic; Political Thriller', '{"epic","grim","cerebral","brutal"}', '{"forge world","Titan Legion","god-machines","Adeptus Mechanicus","Chaos Titans","Machine Cult theology","Omnissiah","Skitarii","Imperial politics","schism","common soldiery","apocalyptic war","Princeps"}', 'When the vital forge world Orestes is attacked by a legion of Chaos Titans, it appeals for help. Titan Legio Invicta, battle-worn and in need of repair, commits its god-machines to a war whose devastation could destroy the world they defend.', 'core', NULL, NULL, false, NULL),
  ('P6-43', 6, 'Deathwatch: The Omnibus', 'Steve Parker / Justin D. Hill / Ian St Martin et al.', NULL, 'omnibus', 43, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Deathwatch', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, 'omnibus container; components carry data'),
  ('P6-44', 6, 'Space Wolf: The First Omnibus', 'William King', NULL, 'omnibus', 44, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Space Wolves', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, 'omnibus container; components carry data'),
  ('P6-45', 6, 'Wolfblade', 'William King', 416, 'novel', 4500, NULL, 'medium', 'novel', false, 'entry', 'Terra', 'Segmentum Solar', 'M41', 'Ragnar Blackmane', '{"Gabriella Belisarius","Torin","Haegr"}', 'Space Wolves, Wolfblade', 'Adeptus Astartes', NULL, 'Political Thriller; Military SF', '{"intrigue-laden","political","fish-out-of-water","tense"}', '{"Space Wolves","Wolfblade","Navigator House Belisarius","Holy Terra","exile","political intrigue","assassination plot","Navigator Houses","bodyguard duty","Throneworld","culture shock","undercity","honour and redemption"}', 'Exiled to Terra for losing the Spear of Russ, Ragnar joins the Wolfblade, honour guard to the Navigator House of Belisarius. Unused to the Throneworld''s deadly politics, he is soon embroiled in an assassination plot reaching into the Imperium''s depths.', 'core', NULL, NULL, false, NULL),
  ('P6-46', 6, 'Legends of the Wolf (Omnibus)', 'Chris Wraight', NULL, 'omnibus', 46, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Space Wolves', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, 'omnibus container; components carry data'),
  ('P6-47', 6, 'Battle of the Fang', 'Chris Wraight', 416, 'novel', 4700, NULL, 'high', 'novel', false, 'entry', 'The Fang, Fenris', 'Segmentum Obscurus', 'M32 (a thousand years after the Horus Heresy)', 'Vaer Greyloc', '{"Harek Ironhelm","Bjorn the Fell-Handed","Magnus the Red","Haakon Gylfasson"}', 'Space Wolves, Twelfth Great Company', 'Adeptus Astartes', NULL, 'War Epic; Military SF', '{"epic","desperate","brutal","tense"}', '{"Space Wolves","the Fang","Fenris","Thousand Sons","Magnus the Red","daemon primarch","siege","fortress defence","blood feud","Bjorn the Fell-Handed","Dreadnought","Rune Priest","last stand","gene-seed secret"}', 'In M32, a thousand years after the Heresy, the Thousand Sons besiege the Fang on Fenris while Great Wolf Harek Ironhelm is lured away to Gangava Prime hunting Magnus the Red. Wolf Lord Greyloc''s skeleton garrison must hold the fortress against overwhelming hosts.', 'core', NULL, NULL, false, 'Note: War of the Fang omnibus pairs this with novella The Hunt for Magnus (optional upgrade per v3.0)'),
  ('P6-48', 6, 'Krakenblood', 'Marc Collins', 400, 'novel', 4800, NULL, 'high', 'novel', false, 'entry', 'Fenris (and deep-void expedition)', NULL, NULL, 'Ivar Krakenblood', '{"Ulrik the Slayer"}', 'Space Wolves', 'Adeptus Astartes', NULL, 'Quest/Adventure; Character Study', '{"lush","mythic","brooding","saga-like"}', '{"Space Wolves","Wolf Priest","Fenris","quest for glory","lost relic","Ulrik the Slayer","Rogue Trader","House Helvintr","Iron Priest","Navigator","saga and destiny","hubris","deep-space expedition","fate"}', 'Born on Fenris and anointed a Wolf Priest, Ivar Krakenblood has never found true legend. Tasked by Ulrik the Slayer to recover a lost Chapter relic, he gathers warriors and allies and sets out into the darkness to forge his own saga.', 'core', NULL, NULL, false, NULL),
  ('P6-49', 6, 'Red Tithe', 'Robbie MacNiven', 368, 'novel', 4900, NULL, 'high', 'novel', false, 'entry', 'Zartak (penal mining world)', NULL, NULL, 'Bail Sharr', '{"Te Kahurangi","Skell","Amon Cull","Rannik"}', 'Carcharodons Astra', 'Adeptus Astartes', NULL, 'Horror; Military SF', '{"brutal","grimdark","visceral","terror-laden"}', '{"prison world","mining colony","Space Sharks","void-born Space Marines","Night Lords warband","psyker","predators","gene-seed mutation","Adeptus Arbites","chapter in decline","Chaos Space Marines","abducted recruits"}', 'On the prison world of Zartak the Night Lords arrive, bringing fear and pain. From the void another fleet emerges - the white-faced Carcharodon Astra. Two packs of merciless predators stalk the colony, both hunting a single young inmate with unnatural talents.', 'core', NULL, NULL, false, NULL),
  ('P6-50', 6, 'Outer Dark', 'Robbie MacNiven', 400, 'novel', 5000, NULL, 'high', 'novel', false, 'entry', 'Piety V (shrine world)', 'Segmentum Obscurus', NULL, 'Bail Sharr', '{"Te Kahurangi","Tyberos the Red Wake","Inquisitor Nzogwu"}', 'Carcharodons Astra, 3rd Company', 'Adeptus Astartes', NULL, 'Military SF; Horror', '{"brutal","grim","tense"}', '{"tyranids","hive fleet","shrine world","Space Sharks","void-born","xenos invasion","last stand","Ashen Claws renegades","Inquisition","dreadnought","Genestealer cults","Astra Militarum"}', 'With tyranid hive fleets approaching, the Carcharodons make a stand on the shrine world of Piety V to halt the xenos before the menace begins - and come to learn what the value of mankind truly is.', 'core', NULL, NULL, false, NULL),
  ('P6-51', 6, 'Void Exile', 'Robbie MacNiven', 384, 'novel', 5100, NULL, 'medium', 'novel', false, 'entry', 'Diamantus (forge world)', NULL, 'Era Indomitus', 'Bail Sharr', '{"Voldire","Vashtorr the Arkifane"}', 'Carcharodons Astra, 3rd Company', 'Adeptus Astartes', NULL, 'Military SF; Horror', '{"atmospheric","claustrophobic","oppressive","grim"}', '{"forge world","space hulk","Chaos","Vashtorr the Arkifane","datagnost","Adeptus Mechanicus alliance","Primaris Marines","void combat","boarding action","siege","Space Sharks","Indomitus era"}', 'The isolated forge world of Diamantus faces a Chaos-warped space hulk commanded by the datagnost Voldire, disciple of Vashtorr. Battle-weary, Bail Sharr''s Carcharodons make their stand alongside the Adeptus Mechanicus to destroy the hulk.', 'core', NULL, NULL, false, 'page_count: HC 314'),
  ('P6-52', 6, 'Shrike', 'George Mann', 207, 'novel', 5200, NULL, 'medium', 'novel', false, 'entry', 'Multiple worlds (incl. Kiavahr)', 'Multiple/Galaxy-wide', 'Targus campaign (862.M41) to Prefectia (999.M41)', 'Kayvaan Shrike', '{"Gorkrusha"}', 'Raven Guard, 3rd Company', 'Adeptus Astartes', NULL, 'Military SF; Character Study', '{"obsessive","vengeance-driven","fast-paced","action-focused"}', '{"Raven Guard","orks","vendetta","guerrilla warfare","shadow tactics","ritual","Kiavahr","rise through ranks","greenskin warlord","Chapter Master","stealth","ambush"}', 'Across many campaigns Kayvaan Shrike of the Raven Guard rises from veteran to Shadow Captain to Chapter Master, pursuing a decades-long feud with the ork warlord Gorkrusha - a tale of obsession and vengeance.', 'core', NULL, NULL, false, NULL),
