  ('P6-55', 6, 'Spear of the Emperor', 'Aaron Dembski-Bowden', 368, 'novel', 5500, NULL, 'high', 'novel', false, 'entry', 'Elara''s Veil nebula (Nemeton; Kouris)', 'Ultima Segmentum', 'Era Indomitus (after the Great Rift)', 'Amadeus Kaias Incarius', '{"Anuradha","High King Arucatas"}', 'Mentor Legion; Emperor''s Spears', 'Adeptus Astartes', NULL, 'Military SF; Character Study', '{"bleak","isolated","emotional","thought-provoking"}', '{"Emperor''s Spears","Mentor Legion","Adeptus Vaelarii","Imperium Nihilus","Great Rift","Elara''s Veil","barbarian homeworld","Nemeton","helots","Chaos warband","the Pure","Exilarchy","Celestial Lions","Black Templars","brotherhood","isolation","Primaris Marines","frontier vigil","outsider perspective"}', 'The Elara''s Veil nebula was once guarded by the Adeptus Vaelarii - the Emperor''s Spears, Celestial Lions and Star Scorpions; now only the Emperor''s Spears keep their vigil. Amadeus Kaias Incarius of the Mentor Legion crosses the Great Rift to assess the Spears.', 'core', NULL, NULL, false, NULL),
  ('P6-56', 6, 'Sisters of Battle: The Omnibus', 'James Swallow', NULL, 'omnibus', 56, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Adepta Sororitas', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, 'omnibus container; components carry data'),
  ('P6-57', 6, 'The Eye of Medusa', 'David Guymer', 432, 'novel', 5700, NULL, 'high', 'novel', false, 'entry', 'Thennos', 'Segmentum Obscurus', NULL, 'Sergeant Kardan Stronos', '{"Arven Rauth","Jalenghaal","Iron Father Kristos"}', 'Iron Hands, Clan Garrsak', 'Adeptus Astartes', NULL, 'Military SF; Character Study', '{"cold","clinical","bleak","brutal","lore-dense"}', '{"Iron Hands","Clan Garrsak","Adeptus Mechanicus","Thennos","insurrection","flesh is weak","cybernetics","man vs machine","Medusa","Ferrus Manus","neophytes","Kristos schism","cold logic","Chaos taint","First Founding"}', 'When the Adeptus Mechanicus world of Thennos falls into insurrection, the Iron Hands answer with cold extermination. Newly inducted into Clan Garrsak, Sergeant Stronos leads his squad into battle - but Thennos hides something dark, and a struggle for the Chapter''s soul looms.', 'core', NULL, NULL, false, NULL),
  ('P6-58', 6, 'The Voice of Mars', 'David Guymer', 320, 'novel', 5800, NULL, 'low', 'novel', false, 'entry', 'Mars; Fabris Calivant; Medusa', 'Multiple/Galaxy-wide', 'Mid-M41', 'Kardan Stronos', '{"Iron Father Kristos","Arven Rauth","Melitan Yolanis"}', 'Iron Hands, Clan Garrsak', 'Adeptus Astartes', NULL, 'Military SF; Political Thriller', '{"cold","politically intricate","lore-dense","slow-burn"}', '{"Iron Hands","Clan Garrsak","Clan Raukaan","Mars","Adeptus Mechanicus","Iron Council","Voice of Mars","Dawnbreak Technologies","eldar","orks","Knight World","Fabris Calivant","Medusa","internal schism","flesh is weak","Techmarine","intrigue","xenos technology"}', 'The Voice of Mars is a secretive seat on the Iron Council. Iron Father Kristos is charged with unlocking the mysterious Aeldari Dawnbreak Technologies, but the eldar orchestrate a greenskin invasion of a Knight World - and Kristos''s own brothers seek the power for themselves, pitting Clan against Clan.', 'core', NULL, NULL, false, NULL),
  ('P7-01', 7, 'The Cawl Trilogy', 'Guy Haley', NULL, 'omnibus', 1, NULL, NULL, 'series', false, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Adeptus Mechanicus', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, 'series group; component novels carry data'),
  ('P7-02', 7, 'Valdor: Birth of the Imperium', 'Chris Wraight', 208, 'novel', 200, NULL, 'high', 'novel', false, 'entry', 'Terra', 'Segmentum Solar', 'End of the Unification Wars (M30)', 'Constantin Valdor', '{"Uwoma Kandawire","Amar Astarte","Malcador"}', 'Legio Custodes', 'Adeptus Custodes', NULL, 'Political Thriller; War Epic', '{"sombre","intrigue-laden","tragic","reflective"}', '{"Legio Custodes","Constantin Valdor","the Emperor","Unification Wars","Thunder Warriors","nascent Imperium","Terra","Imperial Palace","palace intrigue","High Lords","duty","secrets","political conspiracy","birth of the Imperium"}', 'At the end of the Wars of Unity, Constantin Valdor, Captain-General of the Legio Custodes, faces his greatest test as the nascent Imperium confronts the fate of its forgotten soldiers - the Thunder Warriors - and darker deeds needed to secure progress.', 'core', NULL, NULL, false, NULL),
  ('P7-03', 7, 'Bequin (Series)', 'Dan Abnett', NULL, 'omnibus', 3, NULL, NULL, 'series', false, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Inquisition', NULL, NULL, NULL, NULL, NULL, 'core', NULL, NULL, false, 'series group; component novels carry data'),
  ('P7-04', 7, 'Assassinorum: Kingmaker', 'Robert Rath', 464, 'novel', 400, NULL, 'high', 'novel', false, 'entry', 'Knight World of Dominion', NULL, 'Era Indomitus (Age of the Dark Imperium)', 'Absolom Raithe', '{"Sycorax","Avaaris Koln","Lucien Yavarius-Khau"}', 'Officio Assassinorum (Vindicare)', 'Officio Assassinorum', NULL, 'Political Thriller; Military SF', '{"tense","cloak-and-dagger","intrigue-laden","thrilling"}', '{"Officio Assassinorum","Vindicare","Callidus","Vanus","assassins","Imperial Knights","Knight World","Dominion","succession crisis","secession","espionage","infiltration","chivalric codes","court intrigue","Houses Stryder and Rau","execution force"}', 'Vindicare assassin Absolom Raithe is tasked with the hardest mission of his career: on the Knight World of Dominion, teetering on secession, he must remove its unhinged monarch and steer a pro-Imperial candidate to the throne through a brutal succession crisis.', 'core', NULL, NULL, false, NULL),
  ('P7-05', 7, 'Rites of Passage', 'Mike Brooks', 336, 'novel', 500, NULL, 'medium', 'novel', false, 'entry', 'Vorlese', 'Segmentum Solar', 'M41', 'Lady Chettamandey Brobantis', '{"Radimir Niklau","Inquisitor Zaretta Ngiri"}', 'Navigator House Brobantis', 'Navis Nobilite', NULL, 'Political Thriller; Mystery', '{"scheming","gothic","character-driven","wry"}', '{"Navis Nobilite","Navigator","House Brobantis","Chettamandey","warp navigation","third eye","inheritance struggle","inter-house politics","Chaos cult","ritual murder","Vorlese","warp","mutant nobility","domestic intrigue","succession"}', 'After arranging her own husband''s death, Lady Chettamandey Brobantis stands to inherit leadership of Navigator House Brobantis, but her plans are derailed by ritual killings, cult murders and the looming threat of entire worlds being dragged into the warp.', 'core', NULL, NULL, false, NULL),
  ('P7-06', 7, 'Blackstone Fortress', 'Darius Hinks', 384, 'novel', 600, NULL, 'high', 'novel', false, 'entry', 'Precipice / Blackstone Fortress (Western Reaches)', 'Segmentum Pacificus', 'Era Indomitus (after the Great Rift)', 'Janus Draik', '{"Taddeus","Grekh","Audus","Isola"}', 'UNKNOWN (Rogue Trader retinue)', NULL, NULL, 'Quest/Adventure; Mystery', '{"atmospheric","adventurous","eclectic","perilous"}', '{"rogue trader","Janus Draik","Precipice","Blackstone Fortress","Western Reaches","dungeon-crawl","archeotech","xenos","uneasy alliance","kroot","treasure-hunters","void station","ancient mystery","Warhammer Quest","Great Rift","misfit crew"}', 'Disgraced rogue trader Janus Draik gathers a motley band of companions at the lawless void-station Precipice and ventures deep into the mysterious, shifting Blackstone Fortress, seeking riches and a prize that could change the Imperium.', 'core', NULL, NULL, false, NULL),
