  ('P7-13', 7, 'Straken', 'Toby Frost', 432, 'novel', 1300, NULL, 'high', 'novel', false, 'entry', 'Dulma''lin', NULL, NULL, 'Colonel ''Iron Hand'' Straken', '{"Commissar Morrell","Sly Marbo"}', 'Catachan Jungle Fighters', 'Astra Militarum', NULL, 'Military SF', '{"brutal","action-packed","gritty","larger-than-life"}', '{"Astra Militarum","Catachan Jungle Fighters","orks","cavern world","guerrilla warfare","commissar tension","veteran leader","bionics","siege","greenskin horde","internal division"}', 'Pulled from a war against the tyranids, Colonel ''Iron Hand'' Straken and his Catachan Jungle Fighters are sent to the cavern world of Dulma''lin to clear an ork infestation, while a hostile commissar dogs their every move.', 'optional', NULL, NULL, false, 'v3.0 Backlog/Optional — enriched, not active reading'),
  ('P7-14', 7, 'Defiant', 'Andy Clark', NULL, 'short', 1400, NULL, 'pending', 'short_story', false, 'entry', 'Pyrodiah', NULL, NULL, 'Lady Jennika Tan Draconis', NULL, 'Imperial Knights of House Adrastapol', 'Imperial Knights', NULL, 'Military SF', '{"desperate","explosive","heroic"}', '{"Imperial Knights","House Adrastapol","necrons","Knight pilot","hive cities","war machines","defence","short story","xenos invasion"}', 'On Pyrodiah, where risen necrons swarm across burning hive cities, the Imperial Knights of Adrastapol arrive to turn the war, led by Lady Jennika Tan Draconis, pilot of the storied Knight Fire Defiant.', 'optional', NULL, NULL, false, 'format: short story/eshort per BL; v3.0 Backlog/Optional — enriched, not active reading; page_count: Opus returned 31 (likely wrong match — full novel); VERIFY manually'),
  ('P7-15', 7, 'Salamanders: Rebirth', 'Nick Kyme', 464, 'novel', 1500, NULL, 'medium', 'novel', false, 'entry', 'Heletine', NULL, 'Five years after the Promethean War began', 'Brother-Captain Drakgaard', NULL, 'Salamanders (Fifth Company)', 'Adeptus Astartes', NULL, 'Military SF; War Epic', '{"vengeful","fiery","martial","grim"}', '{"Space Marines","Salamanders","Black Legion","Chaos","Promethean War","Heletine","Tome of Fire prophecy","Vulkan","volcanic chapter","siege","faith","ten-thousand-year hatred","Order of the Ebon Chalice"}', 'Five years after war came to Nocturne, the Salamanders'' Fifth Company under Brother-Captain Drakgaard face the Black Legion on Heletine in the Promethean War, where the enemy''s true motives run deeper than conquest.', 'optional', NULL, NULL, false, 'Tome of Fire series Book 4 (standalone novel, NOT omnibus - verified Lexicanum); v3.0 Backlog/Optional — enriched, not active reading'),
  ('P7-16', 7, 'Space Marine Conquests: For Glory and Honour (Anthology)', 'multi-author', NULL, 'anthology', 1600, NULL, NULL, 'anthology', false, 'entry', 'Multiple/Galaxy-wide', 'Multiple/Galaxy-wide', NULL, NULL, NULL, NULL, NULL, NULL, 'Military SF; War Epic', '{"heroic","martial","action-packed"}', '{"Primaris Space Marines","Imperial Fists","Raven Guard","White Scars","Ultramarines","Indomitus Crusade","Roboute Guilliman","Word Bearers","Chaos","anthology","Dark Imperium"}', 'A bumper anthology of three Space Marine Conquests novels of the Primaris Space Marines: Andy Clark''s Fist of the Imperium, Josh Reynolds''s Apocalypse, and Ian St. Martin''s Of Honour and Iron.', 'optional', NULL, NULL, false, 'anthology parent; 3 component novels -> optional sub-items at merge if desired; v3.0 Backlog/Optional — enriched, not active reading'),
  ('P7-17', 7, 'Bastion Wars: The Omnibus', 'Henry Zou', NULL, 'omnibus', 17, NULL, NULL, 'omnibus', true, 'entry', NULL, NULL, NULL, NULL, NULL, NULL, 'Multiple', NULL, NULL, NULL, NULL, NULL, 'optional', NULL, NULL, false, 'omnibus container; components carry data (v3.0 Backlog)'),
  ('P7-18', 7, 'Ragnar Blackmane', 'Aaron Dembski-Bowden', 208, 'novel', 1800, NULL, 'medium', 'novel', false, 'entry', 'Cadia', 'Segmentum Obscurus', '13th Black Crusade (999.M41)', 'Ragnar Blackmane', '{"Ulrik the Slayer","Berek Thunderfist"}', 'Space Wolves', 'Adeptus Astartes', NULL, 'War Epic; Character Study', '{"introspective","honour-bound","violent","complex"}', '{"Space Marines","Space Wolves","Wolf Lord","13th Black Crusade","Cadia","Abaddon the Despoiler","honour duel","chapter rivalry","sagas","Dark Angels","Flesh Tearers","temper"}', 'As he battles Abaddon''s forces on war-ravaged Cadia, Space Wolf Wolf Lord Ragnar Blackmane recalls two sagas from his past, each bringing him into conflict with the secretive Dark Angels and the savage Flesh Tearers.', 'optional', NULL, NULL, false, 'Space Marine Legends; v3.0 Backlog/Optional — enriched, not active reading'),
  ('P7-19', 7, 'Azrael', 'Gav Thorpe', 256, 'novel', 1900, NULL, 'medium', 'novel', false, 'entry', 'Rhamiel', NULL, NULL, 'Azrael', '{"Belial","Ezekiel"}', 'Dark Angels', 'Adeptus Astartes', NULL, 'War Epic; Character Study', '{"secretive","melodramatic","cerebral","brooding"}', '{"Space Marines","Dark Angels","Supreme Grand Master","chapter secrets","the Fallen","eldar alliance","First Legion","Unforgiven","Deathwing","ten thousand years","loyalty"}', 'Supreme Grand Master Azrael of the Dark Angels, keeper of his Chapter''s darkest secrets, must forge an uneasy alliance with the alien eldar - walking a fine line between victory and keeping the Chapter''s murky past buried.', 'optional', NULL, NULL, false, 'Space Marine Legends; v3.0 Backlog/Optional — enriched, not active reading'),
  ('P7-20', 7, 'The Reskard Purgation', 'Jude Reid', 19, 'short', 2000, NULL, 'medium', 'short_story', false, 'entry', NULL, NULL, NULL, 'Morvenn Vahl', NULL, 'Adepta Sororitas', 'Adepta Sororitas', NULL, 'Character Study', '{"introspective","reflective","solemn"}', '{"Adepta Sororitas","Abbess Sanctorum","High Lords of Terra","faith","ascension","reflection","leadership","short story","devotion","introspection"}', 'On the precipice of ascending to Abbess Sanctorum, Morvenn Vahl reflects on the faith-testing events that brought her to this point and what it truly means to become a High Lord of Terra.', 'optional', NULL, NULL, false, 'short story; v3.0 Backlog/Optional — enriched, not active reading; page_count: v3.0 list: 19pp eShort'),
  ('P7-21', 7, 'Armageddon: The Return of Yarrick', 'Games Workshop', NULL, 'novel', 2100, NULL, 'pending', 'tabletop', false, 'entry', 'Armageddon', 'Segmentum Solar', NULL, NULL, '{"Commissar Yarrick","Ghazghkull Thraka","Wazdakka Gutsmek"}', 'Astra Militarum', 'Astra Militarum', NULL, 'War Epic', '{"nostalgic","large-scale","grim","defiant"}', '{"Astra Militarum","Orks","Armageddon","Commissar Yarrick","Ghazghkull Thraka","Wazdakka Gutsmek","hive world","campaign supplement","tank warfare","Waaagh","siege"}', 'A campaign supplement: the Season of Fire has passed and a new Ork invasion under Ghazghkull Thraka looms over Armageddon, but a commander thought lost - Commissar Yarrick - returns to rally the Imperium''s defence.', 'optional', NULL, NULL, false, 'tabletop campaign book, not a BL novel; not counted'),
  ('P7-22', 7, 'World Ablaze (Anthology)', 'multi-author', NULL, 'anthology', 2200, NULL, NULL, 'anthology', false, 'entry', 'Armageddon', 'Segmentum Solar', NULL, NULL, NULL, NULL, NULL, NULL, 'War Epic; Military SF', '{"ferocious","chaotic","martial","grim"}', '{"Space Marines","Orks","Armageddon","war anthology","Black Templars","Ultramarines","Blood Angels","Space Wolves","Crimson Fists","Waaagh","carnage"}', 'An anthology of eleven new tales chronicling the Imperium''s eternal war against the ork menace, from Black Library authors including Mike Vincent, Denny Flowers, Jude Reid, Guy Haley, Robbie MacNiven, Richard Swan and Marc Collins.', 'optional', NULL, NULL, false, 'unreleased (anthology, May 2026)'),
  ('P7-23', 7, 'Death World (20th Anniversary Edition)', 'Steve Lyons', NULL, 'novel', 2300, NULL, NULL, 'novel', false, 'entry', 'Rogar III', NULL, NULL, 'Trooper Lorenzo', '{"Sergeant Greiss","Braxton"}', 'Catachan Jungle Fighters (Catachan XIV)', 'Astra Militarum', NULL, 'Military SF; Horror', '{"tense","horror-tinged","grim","survival"}', '{"Astra Militarum","Catachan Jungle Fighters","death world","orks","sentient planet","jungle warfare","survival horror","reissue","anniversary edition"}', 'Steve Lyons''s anniversary hardback reissue (with a new foreword) of the Catachan novel: a squad of Catachan Jungle Fighters deploys to the death world of Rogar III against an ork incursion.', 'optional', NULL, 'P7-11.2', false, '20th-anniversary reissue = duplicate of P7-11.2 Death World; do not double-count')
INSERT INTO public.books (entry_id, phase_id, title, author, pages, type, sort_order, pub_year, page_count_confidence, format, is_omnibus, row_type, location_primary, location_segmentum, in_universe_date, protagonist, key_characters, sub_faction, faction_primary, faction_secondary, sub_genre, mood_tags, semantic_tags, spoiler_free_summary, track, reading_order_note, also_in, acquired, research_note, parent_book_id) VALUES
  ('P1-01.1', 1, 'Priests of Mars', 'Graham McNeill', 416, 'novel', 1, 2012, 'high', 'novel', false, 'sub_item', 'The Speranza (Kotov''s explorator fleet)', 'Mobile/Fleet', 'M41', 'Archmagos Lexell Kotov', '{"Roboute Surcouf","Vitali Tychon","Tarkis Blaylock","Vettius Telok"}', 'Kotov Explorator Fleet;Cadian 71st;Black Templars;Legio Sirius', 'Adeptus Mechanicus', NULL, 'Quest/Adventure;Military SF', '{"adventurous","exploratory","ominous","grand-scale"}', '{"Adeptus Mechanicus","explorator fleet","quest for knowledge","archeotech","Halo Worlds","Breath of the Gods","Ark Mechanicus Speranza","rogue trader","Titan Legion","Cadian Guard","Black Templars","eldar pursuit","exploration","tech-priests","voyage-into-unknown"}', 'Ambitious Archmagos Kotov musters an Adeptus Mechanicus Explorator fleet, with Imperial Guard and Space Marines, to follow the lost Magos Telok beyond the Halo Worlds in search of the ''Breath of the Gods''.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P1-01')),
  ('P1-01.2', 1, 'Lords of Mars', 'Graham McNeill', 416, 'novel', 2, 2013, 'high', 'novel', false, 'sub_item', 'The Speranza (crossing the Halo Scar)', 'Mobile/Fleet', 'M41', 'Archmagos Lexell Kotov', '{"Roboute Surcouf","Linya Tychon","Tarkis Blaylock","Bielanna"}', 'Kotov Explorator Fleet;Black Templars;Cadian 71st;Legio Sirius', 'Adeptus Mechanicus', NULL, 'Quest/Adventure;Military SF', '{"adventurous","tense","cosmic-horror undertones"}', '{"Adeptus Mechanicus","explorator fleet","eldar","insurrection","ancient secrets","Ark Mechanicus Speranza","Black Templars","voyage","archeotech","shipboard intrigue"}', 'Pursued by vengeful eldar, Kotov''s Explorator armada presses into a newly revealed region chasing ancient secrets, as Mechanicus forces and Black Templars confront alien threats and shipboard insurrection.', 'core', NULL, NULL, false, 'PB; 1 stray HC value (320) ignored', (SELECT id FROM public.books WHERE entry_id='P1-01')),
  ('P1-01.3', 1, 'Gods of Mars', 'Graham McNeill', 416, 'novel', 3, 2014, 'high', 'novel', false, 'sub_item', 'Beyond the galaxy''s edge (Telok''s domain)', 'Multiple/Galaxy-wide', 'M41', 'Archmagos Lexell Kotov', '{"Vettius Telok","Roboute Surcouf","Linya Tychon","Bielanna"}', 'Kotov Explorator Fleet;Black Templars;Cadian 71st;Legio Sirius', 'Adeptus Mechanicus', NULL, 'War Epic;Quest/Adventure', '{"epic","cosmic-horror","trippy","climactic"}', '{"Adeptus Mechanicus","Breath of the Gods","reality-threatening technology","time anomalies","eldar allies","forge world","cosmic horror","salvation of Mars","Void Dragon","Ark Mechanicus Speranza"}', 'Beyond the galaxy''s edge, Kotov''s voyage reaches the long-lost Magos Telok, who still lives. As wonders unfold, darker designs emerge and impossible technologies threaten reality.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P1-01')),
  ('P1-01.4', 1, 'Zero Day Exploit', 'Graham McNeill', NULL, 'short', 4, NULL, NULL, 'short_story', false, 'sub_item', 'Mars (Basiri forge complex)', 'Segmentum Solar', NULL, 'Adept Hydraq', NULL, NULL, 'Adeptus Mechanicus', NULL, 'Heist', '{"thrilling","tense","edge-of-seat"}', '{"Adeptus Mechanicus","heist","data theft","Mars","ash wastes","tech-priest","spikers","infocytes","forge complex","infiltration"}', 'Amid the toxic ash wastes of Mars, spiker-for-hire Adept Hydraq is hired to infiltrate the Basiri forge complex and steal data, only to find his haul more dangerous than imagined.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P1-01')),
  ('P1-03.1', 1, 'Grey Knights', 'Ben Counter', 416, 'novel', 1, NULL, 'medium', 'novel', false, 'sub_item', 'Trail of Saint Evisser', 'Segmentum Solar', '999.M41', 'Justicar Alaric', '{"Inquisitor Ligeia","Inquisitor Nyxos","Ghargatuloth"}', 'Grey Knights;Ordo Malleus', 'Grey Knights', NULL, 'Military SF;Mystery', '{"dark","action-packed","grim","faith-tested"}', '{"Grey Knights","daemonhunters","Ordo Malleus","daemon prince","Tzeentch","prophecy","banishment","True Name","Inquisition","Sisters of Battle","Imperial Guard","faith","investigation","Halo Zone"}', 'Justicar Alaric and an elite Grey Knights team join an Inquisitor to investigate a prophecy on the Trail of Saint Evisser heralding the return of the daemon prince Ghargatuloth, even as a traitor works against them.', 'core', NULL, NULL, false, 'PB; single-source but consistent with BL format; GK segmentum corrected Obscurus->Solar (verified Lexicanum: Trail W edge Seg Solar)', (SELECT id FROM public.books WHERE entry_id='P1-03')),
  ('P1-03.2', 1, 'Dark Adeptus', 'Ben Counter', 416, 'novel', 2, NULL, 'high', 'novel', false, 'sub_item', 'Chaeroneia (forge world)', 'Ultima Segmentum', '999.M41', 'Justicar Alaric', '{"Inquisitor Nyxos","Magos Antigonus","Urkrathos"}', 'Grey Knights;Adeptus Mechanicus (corrupted);Black Legion', 'Grey Knights', '{"Adeptus Mechanicus"}', 'Horror;Military SF', '{"grim","claustrophobic","body-horror","oppressive"}', '{"Grey Knights","daemonhunters","forge world","Adeptus Mechanicus","Chaos corruption","possessed machines","warp","13th Black Crusade","Black Legion","flesh-metal-daemon fusion","faith","behind-enemy-lines"}', 'A century after vanishing, the forge world Chaeroneia returns, silent and adrift. Captain Alaric and his daemonhunters investigate, finding the engineer-priests corrupted beyond imagining and their machines monstrous.', 'core', NULL, NULL, false, 'segmentum inferred via Borosis System (Chaeroneia page itself unsourced)', (SELECT id FROM public.books WHERE entry_id='P1-03')),
  ('P1-03.3', 1, 'Hammer of Daemons', 'Ben Counter', 415, 'novel', 3, NULL, 'high', 'novel', false, 'sub_item', 'Drakaasi (daemon world)', 'Eye of Terror', '999.M41', 'Justicar Alaric', '{"Duke Venalitor","Lord Ebondrake","Inquisitor Nyxos"}', 'Grey Knights;Khorne worshippers', 'Grey Knights', NULL, 'Quest/Adventure;Military SF', '{"brutal","visceral","bleak","relentless"}', '{"Grey Knights","daemon world","Eye of Terror","Khorne","gladiatorial arena","captivity","Hammer of Daemons","daemons","escape","slavery","ultraviolence","faith"}', 'Captured by Chaos and taken to a daemon world in the Eye of Terror, Grey Knight Alaric is stripped of armour and forced to fight as a gladiator for Khorne-worshipping masters. His only hope is a legendary weapon.', 'core', NULL, NULL, false, '415 not 416 - real edition value', (SELECT id FROM public.books WHERE entry_id='P1-03')),
  ('P1-05.1', 1, 'All is Dust', 'John French', NULL, 'short', 1, 2013, NULL, 'short_story', false, 'sub_item', 'UNKNOWN (Rubric Marine interior POV)', NULL, NULL, 'Helio Isidorus', '{"Ahzek Ahriman"}', 'Thousand Sons (Rubricae)', 'Thousand Sons', NULL, 'Character Study;Horror', '{"melancholy","fractured","haunting","tragic"}', '{"Thousand Sons","Rubricae","Rubric Marine","fractured mind","Burning of Prospero","dust","memory","psychic enslavement","tragedy","first-person","Ahriman"}', 'A micro-short glimpse into the fractured mind of Helio Isidorus, once a proud Thousand Sons legionary, now a dust-filled Rubric Marine, stirred to a strange semblance of life by a voice from his past.', 'core', 'Mood-setter; read first', NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P1-05')),
  ('P1-05.2', 1, 'Ahriman: Exile', 'John French', 416, 'novel', 2, 2013, 'high', 'novel', false, 'sub_item', 'The Titan Child / Eye of Terror', 'Eye of Terror', 'M41 (post-Heresy)', 'Ahzek Ahriman', '{"Astraeos","Amon","Ctesias","Carmenta"}', 'Thousand Sons;The Harrowing;Brotherhood of Dust', 'Thousand Sons', NULL, 'Character Study;Quest/Adventure', '{"bleak","dark","atmospheric","tragic"}', '{"Thousand Sons","Ahriman","Tzeentch","sorcery","exile","Eye of Terror","the Rubric","Rubricae","Magnus the Red","warband","redemption","guilt","warp","renegade Space Marines","daemons","architect of fate"}', 'Spurned by his brothers and his father Magnus, Ahriman, a sorcerer of Tzeentch whose actions doomed his Legion, wanders the Eye of Terror as an outcast, scheming his return to power.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P1-05')),
  ('P1-05.3', 1, 'Ahriman: Sorcerer', 'John French', 416, 'novel', 3, 2014, 'high', 'novel', false, 'sub_item', 'Eye of Terror / the Warp', 'Eye of Terror', 'M41', 'Ahzek Ahriman', '{"Ctesias","Sanakht","Ignis","Inquisitor Iobel"}', 'Thousand Sons;Prodigal Sons', 'Thousand Sons', NULL, 'Political Thriller;Character Study', '{"intricate","mysterious","manipulative","dark"}', '{"Thousand Sons","Ahriman","Tzeentch","sorcery","the Rubric","Athenaeum of Kallimakus","Book of Magnus","Prodigal Sons","manipulation","warp","time","Inquisition","Grey Knights","Space Wolves","schemes","betrayal"}', 'Ahriman, architect of the Rubric that laid his Legion low, walks the path toward salvation or damnation, hunting the Athenaeum of Kallimakus said to hold the lost words of Magnus the Red.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P1-05')),
  ('P1-05.4', 1, 'Hand of Dust', 'John French', NULL, 'short', 4, 2013, NULL, 'short_story', false, 'sub_item', 'Prospero', 'Ultima Segmentum', 'M41', 'Ahzek Ahriman', '{"Magnus the Red"}', 'Thousand Sons', 'Thousand Sons', NULL, 'Character Study', '{"melancholy","reflective","sorrowful","tragic"}', '{"Thousand Sons","Ahriman","Prospero","ashes","memory","flesh change","banishment","Magnus the Red","redemption","tragedy","reflection","sorcery"}', 'Standing among the ashes of long-dead Prospero, the sorcerer Ahriman falls into a reflective mood, revisiting the events that set him on what he believes is the path to redemption.', 'core', 'Bridge; read between Sorcerer and Unchanged', NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P1-05')),
  ('P1-05.5', 1, 'Ahriman: Unchanged', 'John French', 416, 'novel', 5, 2015, 'high', 'novel', false, 'sub_item', 'Prospero', 'Ultima Segmentum', 'M41', 'Ahzek Ahriman', '{"Magnus the Red","Astraeos","Ctesias","Ignis"}', 'Thousand Sons;Prodigal Sons/Exiles', 'Thousand Sons', NULL, 'War Epic;Character Study', '{"epic","tragic","dark","climactic"}', '{"Thousand Sons","Ahriman","the Rubric","second Rubric","Planet of the Sorcerers","Prospero","Magnus the Red","Eye of Terror","redemption","warband","villain","warp","set-piece battles","Inquisition"}', 'After long years and countless sacrifices, Ahriman, former Chief Librarian of the Thousand Sons turned exile and sorcerer, readies his most audacious feat: undoing his greatest failure and reversing the Rubric.', 'core', 'Concludes the main ''Second Rubric'' storyline', NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P1-05')),
  ('P2-01.1', 2, 'Xenos', 'Dan Abnett', 416, 'novel', 1, 2001, 'high', 'novel', false, 'sub_item', 'Gudrun (Helican subsector)', 'Segmentum Obscurus', '240.M41', 'Gregor Eisenhorn', '{"Alizebeth Bequin","Godwyn Fischig","Uber Aemos"}', 'Ordo Xenos', 'Inquisition', NULL, 'Mystery; Quest/Adventure', '{"grimdark","noir","action-packed","atmospheric"}', '{"Inquisition","Ordo Xenos","Chaos cult","daemon","xenos (saruthi)","forbidden tome (Necroteuch)","conspiracy","manhunt","detective/investigation","ice world","House Glaw","psyker","pariah/untouchable","first-person narration","corruption","Helican subsector"}', 'Inquisitor Gregor Eisenhorn of the Ordo Xenos tracks an old enemy to the ice world Hubris, only to uncover a far-reaching Chaos conspiracy and a race to claim a forbidden tome, the Necroteuch.', 'core', NULL, NULL, false, '2015 reprint PB (verified Amazon)', (SELECT id FROM public.books WHERE entry_id='P2-01')),
  ('P2-01.2', 2, 'Malleus', 'Dan Abnett', 416, 'novel', 2, 2001, 'high', 'novel', false, 'sub_item', 'Thracian Primaris (Helican subsector)', 'Segmentum Obscurus', 'c.338-345.M41', 'Gregor Eisenhorn', '{"Cherubael","Gideon Ravenor","Alizebeth Bequin"}', 'Ordo Xenos', 'Inquisition', NULL, 'Mystery; Political Thriller', '{"dark","noir","tense","melancholic"}', '{"Inquisition","Ordo Xenos","daemonhost (Cherubael)","Chaos","rogue psykers","conspiracy","betrayal","noir","manhunt","Thracian Primaris","Cadia","pylons","moral ambiguity","radicalism","interrogator"}', 'A century after the Necroteuch affair, celebrated Inquisitor Eisenhorn is implicated in a catastrophe on Thracian Primaris as a face from his past returns. The daemon Cherubael seeks his ruin.', 'core', NULL, NULL, false, '2015 reprint PB (verified); older eds were 288-320', (SELECT id FROM public.books WHERE entry_id='P2-01')),
  ('P2-01.3', 2, 'Hereticus', 'Dan Abnett', 416, 'novel', 3, 2002, 'high', 'novel', false, 'sub_item', 'Gudrun (Helican subsector)', 'Segmentum Obscurus', '386.M41', 'Gregor Eisenhorn', '{"Cherubael","Gideon Ravenor","Harlon Nayl"}', 'Ordo Xenos', 'Inquisition', NULL, 'Character Study; Quest/Adventure', '{"dark","morally grey","desperate","brooding"}', '{"Inquisition","Ordo Xenos","radical Inquisitor","heretic hunt","daemonhost Cherubael","forbidden knowledge","Titan","moral fall","redemption/damnation","manhunt","Quixos","Gudrun","first-person narration"}', 'Hunted by former allies as a radical, Inquisitor Eisenhorn must prove his loyalty while tracking a heretic believed dead - the dread former Inquisitor Quixos - using ever darker means that risk making him the enemy he hunts.', 'core', NULL, NULL, false, '2015 reprint PB (verified)', (SELECT id FROM public.books WHERE entry_id='P2-01')),
  ('P2-03.1', 2, 'Dante', 'Guy Haley', 368, 'novel', 1, 2017, 'high', 'novel', false, 'sub_item', 'Baal / Baal Secundus', 'Ultima Segmentum', '447.M40-c.999.M41 (dual timeline)', 'Dante (Luis Dante)', NULL, 'Blood Angels', 'Blood Angels', NULL, 'Character Study; War Epic', '{"melancholic","tragic","epic","bittersweet"}', '{"Blood Angels","Sanguinius","Chapter Master","Baal Secundus","recruitment trials","the Flaw (Red Thirst/Black Rage)","origin story","dual timeline","Cryptus system","Armageddon","character study","melancholy"}', 'Dante, longest-lived Chapter Master of the Blood Angels, is chronicled from his birth in the rad-scarred wastes of Baal Secundus through war against the Imperium''s enemies - and his struggle against the darkness within all sons of Sanguinius.', 'core', 'Read first, then jump to Shield of Baal (P3)', NULL, false, 'PB 2018 reprint; 304 was HC', (SELECT id FROM public.books WHERE entry_id='P2-03')),
  ('P2-03.2', 2, 'Devastation of Baal', 'Guy Haley', 512, 'novel', 2, 2017, 'high', 'novel', false, 'sub_item', 'Baal (Baal system)', 'Ultima Segmentum', 'c.999.M41', 'Commander Dante', '{"Mephiston","Gabriel Seth","Ka''Bandha"}', 'Blood Angels (and successor Chapters)', 'Blood Angels', '{"Tyranids"}', 'War Epic; Military SF', '{"epic","grim","desperate","tragic"}', '{"Blood Angels","successor Chapters","Sanguinius","Hive Fleet Leviathan","Tyranids","Baal","siege/defence","the Flaw (Red Thirst/Black Rage)","Mephiston","Flesh Tearers","Khorne daemon","Great Rift","Primaris Marines","war epic","Ultima Segmentum"}', 'The largest tendril of Hive Fleet Leviathan bears down on Baal. Commander Dante summons the successor Chapters of the Ninth Legion - thirty thousand Space Marines - to save the Blood Angels'' homeworld, even as a greater evil stirs.', 'core', 'Read after Shield of Baal; also SMC #1', 'Space Marine Conquests #1 (P3 SMC subsection)', false, NULL, (SELECT id FROM public.books WHERE entry_id='P2-03')),
  ('P2-03.3', 2, 'Darkness in the Blood', 'Guy Haley', 336, 'novel', 3, 2019, 'high', 'novel', false, 'sub_item', 'Baal (Baal system)', 'Ultima Segmentum', 'post-Great Rift / M42 (Era Indomitus)', 'Commander Dante', '{"Mephiston","Roboute Guilliman","Belisarius Cawl"}', 'Blood Angels', 'Blood Angels', NULL, 'Character Study; Military SF', '{"dark","operatic","melancholic","tense"}', '{"Blood Angels","Imperium Nihilus","Great Rift","Roboute Guilliman","Mephiston","Belisarius Cawl","the Flaw (Red Thirst/Black Rage)","Baal","regency","transformation","character study"}', 'With the Great Rift splitting the Imperium, Dante - appointed by Guilliman as Regent and Warden of Imperium Nihilus - plans to retake half an empire from rebuilt Baal. But the Flaw grows, and the gravest ordeal falls upon Mephiston, Lord of Death.', 'core', 'SAVE for Phase 5 per reading plan', NULL, false, 'PB 2021 (single-source but solid ISBN)', (SELECT id FROM public.books WHERE entry_id='P2-03')),
  ('P2-03.4', 2, 'Astorath: Angel of Mercy', 'Guy Haley', 208, 'novel', 4, 2021, 'high', 'novel', false, 'sub_item', 'Dulcis', NULL, 'post-Devastation of Baal / Era Indomitus (M42)', 'Astorath the Grim', '{"Commander Dante","Roboute Guilliman"}', 'Red Wings (Blood Angels successor)', 'Blood Angels', NULL, 'Horror; Mystery', '{"grim","dark","eerie","foreboding"}', '{"Blood Angels","Red Wings (successor)","Astorath the Grim","High Chaplain","Black Rage","Redeemer of the Lost","Dulcis (swamp world)","Cicatrix Maledictum","Red Scar","Imperium Nihilus","Primaris Marines","xenos threat","psychic phenomena","Indomitus Crusade","hunt"}', 'Scouting the Red Scar for reconquest, the tyranid-decimated Red Wings reach the foetid world of Dulcis, dangerously near the Cicatrix Maledictum. Drawn by the Black Rage, Astorath the Grim arrives to aid them - and uncovers a revelation that will shake all the Blood.', 'core', NULL, 'Listed standalone in Phase 5 (P5) - same novel', false, 'standalone ed; mostly exists in omnibus', (SELECT id FROM public.books WHERE entry_id='P2-03')),
  ('P2-04.1', 2, 'Salamander', 'Nick Kyme', 448, 'novel', 1, 2009, 'high', 'novel', false, 'sub_item', 'Scoria (Veiled Region)', 'Segmentum Tempestus', NULL, 'Dak''ir (Hazon Dak''ir)', '{"Tsu''gan","Nihilan","Pyriel"}', 'Salamanders (3rd Company)', 'Salamanders', NULL, 'Military SF; Quest/Adventure', '{"grimdark","brooding","character-driven","action-packed"}', '{"Salamanders","Space Marines","Nocturne","Scoria","Veiled Region","Archimedes Rex","Ork WAAAGH","Dragon Warriors","Marines Malevolent","Chaos","ancient artefact","prophecy","Tome of Fire","rivalry","Vulkan''s legacy","prophetic visions","fire/forge motifs"}', 'Space Marines of the Salamanders Chapter, hailing from volcanic Nocturne, hunt an ancient artefact that leads them to a world overrun by Chaos. A more dangerous foe emerges as bitter rivalries break out among the fire-born, testing their endurance.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P2-04')),
  ('P2-04.2', 2, 'Firedrake', 'Nick Kyme', 416, 'novel', 2, 2010, 'high', 'novel', false, 'sub_item', 'Geviox', NULL, NULL, 'Dak''ir (Hazon Dak''ir)', '{"Tsu''gan","Chaplain Elysius","Vulkan He''stan"}', 'Salamanders (Firedrakes / 1st Company)', 'Salamanders', NULL, 'Military SF; Quest/Adventure', '{"grim","brutal","suspenseful","character-driven"}', '{"Salamanders","Firedrakes","Space Marines","Dark Eldar","webway","Port of Anguish","Geviox","Moribar","Nocturne","Mount Deathfire","rescue mission","captivity","Librarian training","psychic powers","prophecy","Tome of Fire","Vulkan''s relics"}', 'When Chaplain Elysius is captured by Dark Eldar, the Firedrakes of 1st Company mount a daring rescue - but more than his life is at stake. He holds secrets buried beneath Mount Deathfire, while Dak''ir endures brutal Librarian training.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P2-04')),
  ('P2-04.3', 2, 'Nocturne', 'Nick Kyme', 416, 'novel', 3, 2011, 'high', 'novel', false, 'sub_item', 'Nocturne', 'Ultima Segmentum', '975.M41 (Defense of Nocturne / Dragon Strife)', 'Dak''ir (Hazon Dak''ir)', '{"Tsu''gan","Nihilan","Vulkan He''stan"}', 'Salamanders', 'Salamanders', NULL, 'Military SF; War Epic', '{"epic","apocalyptic","action-packed","climactic"}', '{"Nocturne","Prometheus","Salamanders","Dragon Warriors","Dark Eldar","Chaos renegades","homeworld invasion","prophecy","Tome of Fire","psyker/Librarian","saviour-or-destroyer","rivalry","vengeance","Vulkan''s legacy","siege"}', 'War comes to Nocturne. After decades of planning, Nihilan musters an armada of Dragon Warriors, dark eldar and Chaos renegades against the Salamanders'' homeworld. A prophecy names the Librarian Dak''ir saviour or destroyer as the invasion begins.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P2-04')),
  ('P2-05.1', 2, 'Soul Hunter', 'Aaron Dembski-Bowden', 416, 'novel', 1, 2010, 'high', 'novel', false, 'sub_item', 'Crythe Primus', NULL, 'M41', 'Talos (Talos Valcoran)', '{"The Exalted (Vandred Anrathi)","Abaddon the Despoiler","Cyrion","Septimus"}', 'Night Lords (First Claw, 10th Company)', 'Night Lords', NULL, 'Military SF; Character Study', '{"grimdark","brooding","brutal","morally grey"}', '{"Night Lords","Chaos Space Marines","traitor legion","First Claw","10th Company","Black Legion","Abaddon","Crythe Primus","Konrad Curze","prophetic visions","the Long War","fear as weapon","vengeance","Blood Angels","human slaves","loyalty/betrayal"}', 'Remorseless hunters who wield terror as a weapon, the Night Lords battle the Imperium to avenge their primarch''s death. Their dark crusade takes them to the valuable world of Crythe Primus, where their alliance with the Black Legion may not hold.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P2-05')),
  ('P2-05.2', 2, 'Blood Reaver', 'Aaron Dembski-Bowden', 416, 'novel', 2, 2011, 'high', 'novel', false, 'sub_item', 'Vilamus', NULL, 'M41', 'Talos (Talos Valcoran)', '{"Huron Blackheart","The Exalted (Vandred Anrathi)","Septimus","Octavia"}', 'Night Lords (First Claw, 10th Company)', 'Night Lords', NULL, 'Military SF; Heist', '{"grimdark","tense","treacherous","character-driven"}', '{"Night Lords","Chaos Space Marines","First Claw","10th Company","Red Corsairs","Huron Blackheart","Marines Errant","Vilamus","gene-seed theft","raid","alliance/betrayal","the Long War","Echo of Damnation","human slaves","vengeance"}', 'Driven by hatred of the False Emperor, the Night Lords forge a fractious alliance with the Red Corsairs. Together these renegades bring destruction to the fortress-monastery of the Marines Errant, intent on stealing the loyalists'' gene-seed.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P2-05')),
  ('P2-05.3', 2, 'Void Stalker', 'Aaron Dembski-Bowden', 416, 'novel', 3, 2012, 'high', 'novel', false, 'sub_item', 'Tsagualsa', 'Eastern Fringe', 'late M41 (just before the 13th Black Crusade)', 'Talos (Talos Valcoran)', '{"Septimus","Octavia","Variel"}', 'Night Lords (First Claw, 10th Company)', 'Night Lords', NULL, 'Military SF; Character Study', '{"grimdark","tragic","climactic","foreboding"}', '{"Night Lords","Chaos Space Marines","First Claw","10th Company","Tsagualsa","carrion world","Eastern Fringe","Craftworld Ulthwe","Eldar","assassin/hunt","Konrad Curze","prophetic visions","the Long War","human slaves","tragedy","series finale"}', 'The hunters become the hunted. Fleeing the eldar of Craftworld Ulthwe, the Night Lords retreat to the carrion world of Tsagualsa - where their primarch died and their Legion was broken - as a deadly assassin stalks the shadows.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P2-05')),
  ('P2-02.1', 2, 'Missing in Action', NULL, NULL, 'short', 1, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Sameter (hive city)', NULL, '241.M41', 'Gregor Eisenhorn', NULL, 'Ordo Xenos', NULL, NULL, 'Mystery', '{"grim","bleak","poignant","detective"}', '{"Inquisition","Ordo Xenos","hive city","ritual murders","serial killings","Chaos cult","detective/investigation","military brainwashing/PTSD (theme)","grimdark","mystery"}', 'A series of mysterious murders in a hive city draws Inquisitor Eisenhorn''s interest. The killings share a commonality hinting at something far deeper than a crazed killer - with grave implications for the entire city.', 'optional', NULL, NULL, false, 'omnibus short, enriched but not progress-trackable', (SELECT id FROM public.books WHERE entry_id='P2-02')),
  ('P2-02.2', 2, 'Backcloth for a Crown Additional', NULL, NULL, 'short', 2, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Gudrun (Drunner region)', 'Segmentum Obscurus', '355.M41', 'Gregor Eisenhorn', '{"Alizebeth Bequin"}', 'Ordo Xenos', NULL, NULL, 'Mystery; Horror', '{"creepy","eerie","low-key","melancholic"}', '{"Inquisition","Gudrun","noble house (Froigre)","travelling carnival/fair","haunting","warpcraft","disappearances","ghost story","force sword (Barbarisater)","pariah Bequin","mystery","eerie"}', 'The death of an old friend brings Inquisitor Eisenhorn and his companions to Sunsable''s Touring Fair, where something sinister haunts the portraits tent - and a taint of the warp threatens to doom an entire world.', 'optional', NULL, NULL, false, 'omnibus short, enriched but not progress-trackable', (SELECT id FROM public.books WHERE entry_id='P2-02')),
  ('P2-02.3', 2, 'Redeemer', NULL, NULL, 'short', 3, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Asque', NULL, 'post-Great Rift / M42', 'Astorath the Grim', NULL, 'Blood Angels', NULL, NULL, 'Character Study; Quest/Adventure', '{"grim","melancholic","sombre","introspective"}', '{"Blood Angels","Astorath the Grim","High Chaplain","Black Rage","Redeemer of the Lost","Asque (fungal forest world)","xenos creatures","Primaris Marines","the Flaw","mercy-killing","character study","Dark Imperium"}', 'It falls to High Chaplain Astorath to bring peace to those of Sanguinius''s blood lost to the Black Rage. He comes to Asque, a world of towering fungal forests, to hunt and redeem a battle-brother gripped by madness.', 'optional', NULL, NULL, false, 'omnibus short, enriched but not progress-trackable', (SELECT id FROM public.books WHERE entry_id='P2-02')),
  ('P2-04.4', 2, 'Tome of Fire (Anthology)', NULL, NULL, 'anthology', 4, NULL, NULL, 'anthology', false, 'sub_item_optional', 'Multiple/Galaxy-wide', 'Multiple/Galaxy-wide', NULL, NULL, '{"Tsu''gan","Dak''ir","Vulkan He''stan"}', 'Salamanders (incl. Firedrakes / 1st Company)', NULL, NULL, 'Military SF; Character Study', '{"grim","mythic","brooding"}', '{"Salamanders","Space Marines","Nocturne","Tome of Fire","prophecy","Vulkan''s legacy","Promethean Cult","short story collection","Firedrakes","fire/forge motifs","honour","self-sacrifice"}', 'Guided by their lost primarch''s wisdom in the mysterious Tome of Fire, the Salamanders face a new prophecy that tests them to destruction - one of their number will save or damn them. A collection expanding the trilogy with untold tales.', 'optional', NULL, NULL, false, 'omnibus short, enriched but not progress-trackable', (SELECT id FROM public.books WHERE entry_id='P2-04')),
  ('P2-05.4', 2, 'Shadow Knight', NULL, NULL, 'short', 4, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Derelict Imperial ship', 'Mobile/Fleet', NULL, 'Talos (Talos Valcoran)', '{"Xarl","Cyrion","Uzas"}', 'Night Lords (First Claw, 10th Company)', NULL, NULL, 'Military SF; Character Study', '{"dark","tense","foreboding"}', '{"Night Lords","Chaos Space Marines","First Claw","10th Company","Blood Angels","derelict ship","salvage mission","hunt","prophetic visions","Konrad Curze","prequel","terror tactics"}', 'A prequel: on a salvage mission aboard a derelict Imperial ship, Talos and First Claw encounter Blood Angels cut off from escape and must hunt fast to survive, while Talos is tormented by visions of grim prophecy.', 'optional', NULL, NULL, false, 'omnibus short, enriched but not progress-trackable', (SELECT id FROM public.books WHERE entry_id='P2-05')),
  ('P2-05.5', 2, 'Throne of Lies', NULL, NULL, 'short', 5, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Tyrias Secundus', NULL, NULL, 'Talos (Talos Valcoran)', '{"The Exalted (Vandred Anrathi)","Octavia","Septimus"}', 'Night Lords (First Claw, 10th Company)', NULL, NULL, 'Mystery; Military SF', '{"dark","atmospheric","tense","vengeful"}', '{"Night Lords","Chaos Space Marines","First Claw","10th Company","Callidus assassin","Covenant of Blood","Konrad Curze","primarch''s death","vengeance","truth/secrets","hololith","navigator","warp travel","audio drama"}', 'Recovering from the events at Crythe Primus aboard the Covenant of Blood, the Exalted''s warband continues its crusade. First Claw hunt an Imperial assassin, seeking the truth behind the death of their primarch, the Night Haunter.', 'optional', NULL, NULL, false, 'omnibus short, enriched but not progress-trackable', (SELECT id FROM public.books WHERE entry_id='P2-05')),
  ('P2-05.6', 2, 'The Core', NULL, NULL, 'short', 6, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Space hulk', 'Mobile/Fleet', NULL, 'Talos (Talos Valcoran)', '{"Deltrian","Septimus","Lucoryphus"}', 'Night Lords (First Claw, 10th Company)', NULL, NULL, 'Military SF; Horror', '{"tense","claustrophobic","suspenseful","dark"}', '{"Night Lords","Chaos Space Marines","First Claw","10th Company","space hulk","genestealers","Salamanders","Deltrian","Echo of Damnation","Bleeding Eyes/Raptors","salvage mission","survival horror","predator/hunt","Mechanicus lore"}', 'After Blood Reaver, Talos and First Claw board a dangerous space hulk to protect the traitor tech-priest Deltrian on a secret mission. Harried by genestealers and Salamanders, they must survive a predator hunting them through the shadows.', 'optional', NULL, NULL, false, 'omnibus short, enriched but not progress-trackable', (SELECT id FROM public.books WHERE entry_id='P2-05')),
  ('P3-01.1', 3, 'Ravenor', 'Dan Abnett', 414, 'novel', 1, 2004, 'medium', 'novel', false, 'sub_item', 'Eustis Majoris', 'Segmentum Obscurus', '402.M41', 'Gideon Ravenor', '{"Harlon Nayl","Kara Swole","Patience Kys"}', 'Ordo Xenos (Ravenor''s warband)', 'Inquisition', NULL, 'Mystery; Political Thriller', '{"dark","gritty","atmospheric","domestic-40k"}', '{"Inquisition","flects","xenos-tainted narcotics","drug trade","conspiracy","suspensor chair","psyker","warband/retinue","hive world","Helican subsector","Cognitae","Zygmunt Molotch","ensemble cast","investigation"}', 'Crippled in the Thracian Primaris atrocity and confined to a life-support chair, Ordo Xenos Inquisitor Gideon Ravenor uses his psychic powers and a retinue of warriors and assassins to investigate an illicit trade in xenos-tainted narcotics that hides a deeper conspiracy.', 'core', NULL, NULL, false, '#1 single-source 320 (HC); set to 414 PB consistent with series', (SELECT id FROM public.books WHERE entry_id='P3-01')),
  ('P3-01.2', 3, 'Ravenor Returned', 'Dan Abnett', 414, 'novel', 2, 2005, 'high', 'novel', false, 'sub_item', 'Eustis Majoris', 'Segmentum Obscurus', 'M41', 'Gideon Ravenor', '{"Harlon Nayl","Kara Swole","Patience Kys","Maud Plyton"}', 'Ordo Xenos (Ravenor''s warband)', 'Inquisition', NULL, 'Mystery; Political Thriller', '{"dark","intricate","gothic","tense"}', '{"Inquisition","undercover investigation","smuggling","arcane technology","cogitators","Enuncia","Chaos cults","conspiracy","hive world","Administratum","psyker","warband"}', 'Believed dead, Inquisitor Ravenor and his retinue return undercover to Eustis Majoris to investigate a ring smuggling stolen arcane technology. Descending deeper, they uncover a terrible plot whose machines hold secrets touching Chaos itself.', 'core', NULL, NULL, false, 'PB; 320 was 2005 HC', (SELECT id FROM public.books WHERE entry_id='P3-01')),
  ('P3-01.3', 3, 'Ravenor Rogue', 'Dan Abnett', 414, 'novel', 3, 2006, 'high', 'novel', false, 'sub_item', 'Multiple/Galaxy-wide', 'Multiple/Galaxy-wide', '404.M41', 'Gideon Ravenor', '{"Harlon Nayl","Kara Swole","Patience Kys"}', 'Ordo Xenos (Ravenor''s warband)', 'Inquisition', NULL, 'Quest/Adventure; Mystery', '{"relentless","dark","obsessive"}', '{"Inquisition","manhunt","going rogue","obsession","time and space travel","Zygmunt Molotch","Gudrun","warband","psyker","Chaos"}', 'Inquisitor Ravenor''s hunt for the arch-heretic Zygmunt Molotch becomes an obsession. Defying Inquisition orders, he and his team go rogue, pursuing their quarry across time and space against enemies of limitless power and cunning.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P3-01')),
  ('P3-01.4', 3, 'Thorn Wishes Talon', NULL, NULL, 'short', 4, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Malinter', 'Segmentum Obscurus', 'c.402.M41', 'Gideon Ravenor', '{"Gregor Eisenhorn","Harlon Nayl","Patience Kys"}', 'Ordo Xenos (Ravenor''s warband)', NULL, NULL, 'Horror; Mystery', '{"mysterious","atmospheric","tense","action-packed"}', '{"Divine Fratery","Chaos cult","daemonhosts","Cherubael","prophecy","Glossia code","Eisenhorn crossover","storm","Chaos Dreadnought","Inquisition","backwater world"}', 'On Malinter, Inquisitor Ravenor and his companions battle the Divine Fratery, servants of the Ruinous Powers. Amid daemonhosts and gunfire, Ravenor meets an old friend, summoned by a simple message: Thorn Wishes Talon.', 'optional', NULL, NULL, false, 'omnibus component, enriched but not progress-trackable (parent counts)', (SELECT id FROM public.books WHERE entry_id='P3-01')),
  ('P3-01.5', 3, 'Playing Patience', NULL, NULL, 'short', 5, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Sameter', 'Segmentum Obscurus', NULL, 'Patience Kys', '{"Gideon Ravenor"}', NULL, NULL, NULL, 'Character Study; Mystery', '{"bleak","dark","grim","gripping"}', '{"psyker","telekinesis","precognition","origin story","poverty","Kindred Youth Scholam","untrained psyker","Cognitae","Inquisition recruitment","coming-of-age","dark"}', 'On the dismal world of Sameter, impoverished young Patience Kys hides a remarkable gift - she senses others'' intentions and moves objects with her mind. When her life unravels, an encounter with Inquisitor Ravenor offers a chance to serve the Imperium.', 'optional', NULL, NULL, false, 'omnibus component, enriched but not progress-trackable (parent counts)', (SELECT id FROM public.books WHERE entry_id='P3-01')),
  ('P3-06.1', 3, 'Shield of Baal: Tempestus', NULL, NULL, 'novel', 1, NULL, NULL, 'novella', false, 'sub_item_optional', 'Lysios (Cryptus System)', 'Ultima Segmentum', '999.M41', 'Tempestor Chavis', '{"Inquisitor Ulrich"}', 'Militarum Tempestus', NULL, NULL, 'Military SF; Horror', '{"grim","Lovecraftian","tense","foreboding"}', '{"Militarum Tempestus","Tempestus Scions","Astra Militarum","Ordo Xenos Inquisition","Adepta Sororitas","Tyranids","Hive Fleet Leviathan","Cryptus System","Lysios","Lovecraftian horror","999.M41"}', 'A tendril of Hive Fleet Leviathan reaches the radioactive Cryptus shieldworlds. On Lysios, as the Adepta Sororitas defend the world, a platoon of Tempestus Scions is seconded to Inquisitor Ulrich to capture a unique tyranid bioform, whatever the cost.', 'optional', NULL, NULL, false, 'omnibus component, enriched but not progress-trackable (parent counts)', (SELECT id FROM public.books WHERE entry_id='P3-06')),
  ('P3-06.2', 3, 'The Word of the Silent King', NULL, NULL, 'short', 2, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Gehenna system (Devil''s Crag)', NULL, NULL, 'Commander Dante', '{"Szarekh the Silent King"}', 'Blood Angels', NULL, NULL, 'Military SF', '{"uneasy","somber","contemplative"}', '{"Blood Angels","Necrons","Szarekh the Silent King","Commander Dante","Tyranids","Gehenna system","Devil''s Crag","unlikely alliance","Space Marines"}', 'The Blood Angels and necrons, long locked in war for the Gehenna system, are both imperilled by arriving tyranids. When the Silent King offers alliance, Commander Dante enacts a dangerous plan that could destroy the necron lord forever, until the two leaders meet at Devil''s Crag.', 'optional', NULL, NULL, false, 'omnibus component, enriched but not progress-trackable (parent counts)', (SELECT id FROM public.books WHERE entry_id='P3-06')),
  ('P3-06.3', 3, 'Wraithflight', NULL, NULL, 'short', 3, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Void / Iyanden fleet', 'Mobile/Fleet', '999.M41', 'Iyanna Arienal', NULL, 'Craftworld Iyanden', NULL, NULL, 'Military SF', '{"dreamlike","eerie","bitter","melancholic"}', '{"Aeldari","Craftworld Iyanden","Spiritseer","wraith constructs","wraithfighters","Tyranids","Hive Fleet Leviathan","void warfare","Iyanna Arienal","ties to Valedor"}', 'As Hive Fleet Leviathan spreads across the galaxy, the eldar of Iyanden enact a desperate plan to halt a splinter that could doom their ravaged craftworld. Iyanna Arienal leads an armada of wraithfighters to aid a human fleet against the tyranids, though her true motives may be darker.', 'optional', NULL, NULL, false, 'omnibus component, enriched but not progress-trackable (parent counts)', (SELECT id FROM public.books WHERE entry_id='P3-06')),
  ('P3-06.4', 3, 'Dread Night', NULL, NULL, 'short', 4, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Unnamed devastated world', NULL, NULL, 'Siegus Mortlock (Grey Knight)', NULL, 'Grey Knights', NULL, NULL, 'Horror; Military SF', '{"grim","horror","desperate","isolated"}', '{"Grey Knights","Daemons","Chaos","Tyranids","Hive Fleet Leviathan","Dreadknight","lone survivor","devastated world","horror"}', 'A lone Grey Knight awakens on a devastated world. As a long night unfolds, he is trapped between daemons and tyranids. Salvaging a Dreadknight warsuit from a fallen comrade, he sets out in search of Salvation, though what Salvation is remains unclear.', 'optional', NULL, NULL, false, 'omnibus component, enriched but not progress-trackable (parent counts)', (SELECT id FROM public.books WHERE entry_id='P3-06')),
  ('P3-06.5', 3, 'Shield of Baal: Devourer', NULL, NULL, 'novel', 5, NULL, NULL, 'novella', false, 'sub_item_optional', 'Cryptus System (dead world)', 'Ultima Segmentum', '999.M41', 'Sergeant Jatiel', '{"Anrakyr the Traveller"}', 'Blood Angels', NULL, NULL, 'Military SF', '{"grim","tense","bleak"}', '{"Blood Angels","Necrons","Anrakyr the Traveller","Sergeant Jatiel","Tyranids","Hive Fleet Leviathan","Cryptus System","tomb world","uneasy alliance","999.M41"}', 'As war rolls across the Cryptus System, Blood Angels Sergeant Jatiel and his squad stand sentinel over a dead world far from the fighting. Across the galaxy, necron overlord Anrakyr the Traveller seeks to awaken a tomb world, drawing him toward a desperate alliance with the sons of Sanguinius.', 'optional', NULL, NULL, false, 'omnibus component, enriched but not progress-trackable (parent counts)', (SELECT id FROM public.books WHERE entry_id='P3-06')),
  ('P3-06.6', 3, 'Shield of Baal: Deathstorm', NULL, NULL, 'novel', 6, NULL, NULL, 'novella', false, 'sub_item_optional', 'Asphodex / Phodia (Cryptus System)', 'Ultima Segmentum', '999.M41', 'First Captain Karlaen', '{"Commander Dante","Brother Corbulo"}', 'Blood Angels First Company', NULL, NULL, 'Military SF; Horror', '{"grim","visceral","desperate","brooding"}', '{"Blood Angels","Blood Angels First Company","Flesh Tearers","Commander Dante","Brother Corbulo","Tyranids","Hive Fleet Leviathan","Spawn of Cryptus","Red Thirst","Black Rage","Death Company","Cryptus System","Asphodex","999.M41"}', 'The sons of Sanguinius land upon Phodia, led by First Captain Karlaen, the Shield of Baal. Their mission: secure the planetary governor, whose blood may hold the key to curing the Chapter''s twin curses. But the Spawn of Cryptus, a sinister tyranid, also hunts the governor.', 'optional', NULL, NULL, false, 'omnibus component, enriched but not progress-trackable (parent counts)', (SELECT id FROM public.books WHERE entry_id='P3-06')),
  ('P3-06.7', 3, 'Shadow of the Leviathan', NULL, NULL, 'short', 7, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Unnamed Ultramarines world', NULL, NULL, 'Chief Librarian Tigurius', NULL, 'Ultramarines', NULL, NULL, 'Military SF; Horror', '{"tense","ominous","cautionary"}', '{"Ultramarines","Varro Tigurius","Chief Librarian","psyker","Tyranids","Hive Fleet Leviathan","Hive Mind","evacuation","rearguard","Space Marines"}', 'Far from the war-torn Cryptus System, the shadow of Hive Fleet Leviathan falls on a world protected by the Ultramarines. As his warriors fight a desperate rearguard to evacuate the population, Chief Librarian Tigurius confronts a monstrous new psychic presence that threatens to overwhelm even him.', 'optional', NULL, NULL, false, 'omnibus component, enriched but not progress-trackable (parent counts)', (SELECT id FROM public.books WHERE entry_id='P3-06')),
  ('P3-06.8', 3, 'A Son''s Burden', NULL, NULL, 'short', 8, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Nekkaris', NULL, '999.M41', 'Sergeant Eschiros', '{"Gabriel Seth","Chaplain Appollus"}', 'Flesh Tearers', NULL, NULL, 'Military SF; Character Study', '{"grim","tragic","brutal","tense"}', '{"Flesh Tearers","Blood Angels successor","Gabriel Seth","Chaplain Appollus","Scout squad","Chaos cultists","Nekkaris","behind enemy lines","sacrifice"}', 'The Blood Angels call for aid and the Flesh Tearers answer, but Gabriel Seth''s warriors are already battling traitor cultists on the dark world of Nekkaris. As Seth and Chaplain Appollus prepare to depart for Cryptus, Sergeant Eschiros and his Scouts fight behind enemy lines, facing a terrible sacrifice.', 'optional', NULL, NULL, false, 'omnibus component, enriched but not progress-trackable (parent counts)', (SELECT id FROM public.books WHERE entry_id='P3-06')),
  ('P3-07.1', 3, 'Path of the Renegade', 'Andy Chambers', 416, 'novel', 1, 2012, 'high', 'novel', false, 'sub_item', 'Commorragh', 'The Webway', '842.M41', 'Nyos Yllithian', '{"Asdrubael Vect","Bellathonis","Motley"}', 'Kabal of the White Flames', 'Drukhari', NULL, 'Political Thriller', '{"dark","treacherous","decadent","sinister"}', '{"Commorragh","Asdrubael Vect tyranny","Kabal of the White Flames","haemonculus","resurrection of El''uriaq","political conspiracy","coup","Harlequins","Exodite soul/pain-bride","incubi","succubus","the Dysjunction","betrayal","decadence"}', 'Beneath Asdrubael Vect''s iron rule of Commorragh, ambitious archon Yllithian allies with a twisted haemonculus to resurrect a long-dead warrior and unseat the tyrant - but his scheming may itself be summoning a coming cataclysm.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P3-07')),
  ('P3-07.2', 3, 'Path of the Incubus', 'Andy Chambers', 414, 'novel', 2, 2013, 'high', 'novel', false, 'sub_item', 'Commorragh', 'The Webway', '842.M41', 'Morr', '{"Asdrubael Vect","Motley","Nyos Yllithian","Bellathonis"}', 'Incubi (Silent Brotherhood)', 'Drukhari', NULL, 'Political Thriller; Horror', '{"dark","chaotic","grim","desperate"}', '{"The Dysjunction","daemonic invasion","Commorragh","incubi","Silent Brotherhood","redemption","atonement","honour","Asdrubael Vect","kabal war","Harlequin Motley","klaive","webway"}', 'The Dysjunction throws Commorragh into turmoil as horrors pour through the veil and Vect fights to hold the riven city. A disgraced incubus, wrongly blamed for the cataclysm, seeks to reclaim his honour amid daemonic invasion and archon warfare.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P3-07')),
  ('P3-07.3', 3, 'Path of the Archon', 'Andy Chambers', 416, 'novel', 3, 2014, 'high', 'novel', false, 'sub_item', 'Commorragh', 'The Webway', '842.M41', 'Nyos Yllithian', '{"Asdrubael Vect","Bellathonis","Kharbyr","Xelian"}', 'Kabal of the White Flames', 'Drukhari', NULL, 'Political Thriller', '{"dark","anarchic","tense","climactic"}', '{"Commorragh","Asdrubael Vect","Mandrake kings","open civil war","Kabal of the White Flames","conspiracy","webway","dark eldar politics"}', 'With the Dysjunction passed but its scars remaining, Vect moves to reassert control over an anarchic Commorragh. Yllithian seeks new allies against the overlord''s wrath, the Mandrake kings muster, and the dark city erupts into open war.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P3-07')),
  ('P3-07.4', 3, 'Midnight on the Street of Knives', NULL, NULL, 'short', 4, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Commorragh', 'The Webway', '842.M41', 'Kharbyr', '{"Bellathonis","Nyos Yllithian"}', 'Kabal of the White Flames', NULL, NULL, 'Mystery', '{"dark","tense","sinister"}', '{"Commorragh","Street of Knives","assassin","cat-and-mouse hunt","haemonculus''s servant","package","webway","dark eldar"}', 'Sent to capture a package, the assassin Kharbyr stalks a haemonculus''s servant through the warrens of Commorragh. But his prey behaves strangely, and a simple game of cat and mouse on the Street of Knives may lead anywhere.', 'optional', NULL, NULL, false, 'omnibus short, enriched but not progress-trackable', (SELECT id FROM public.books WHERE entry_id='P3-07')),
  ('P3-12.1', 3, 'Fire Caste', 'Peter Fehervari', 409, 'novel', 1, 2013, 'medium', 'novel', false, 'sub_item', 'Phaedra (Dolorosa Coil)', 'Eastern Fringe', NULL, 'Commissar Holt Iverson', NULL, '19th Arkan Confederates', 'Astra Militarum', '{"T''au"}', 'Horror; Military SF', '{"bleak","psychological horror","atmospheric","haunting"}', '{"Astra Militarum","Imperial Guard","19th Arkan Confederates","Colonel Ensor Cutler","T''au Empire","Phaedra","Dolorosa Coil","jungle deathworld","human deserters","guerrilla warfare","commissar","Dark Coil","psychological horror","Lovecraftian","Heart of Darkness influence"}', 'In the jungles of the Dolorosa Coil, a coalition of tau and human deserters has warred on the Imperium for years. Fresh Arkan Confederates Guardsmen are sent to break the stalemate, but as they are scattered into a desperate guerrilla war, their hope rests with a disgraced, vengeful commissar.', 'core', '''Apocalypse Now in 40k''', NULL, false, 'single source', (SELECT id FROM public.books WHERE entry_id='P3-12')),
  ('P3-12.2', 3, 'Cult of the Spiral Dawn', 'Peter Fehervari', NULL, 'novel', 2, 2018, NULL, 'novel', false, 'sub_item', 'Redemption (shrine world)', NULL, NULL, 'Captain Cross', NULL, 'Vassago Black Flags', 'Adepta Sororitas', NULL, 'Horror; Mystery', '{"bleak","sinister","creepy","paranoid"}', '{"Genestealer Cult","Adepta Sororitas","Astra Militarum","Vassago Black Flags","Redemption","Imperial Cult sect","pilgrimage","promethium mining world","Dark Coil","genestealers","psychological horror","body horror","Lovecraftian","cult uprising"}', 'The Spiral Dawn is a sanctioned sect of the Imperial Cult. When its pilgrims journey to Redemption, their order''s birthworld, they find not enlightenment but a soot-choked hellhole where their founders and an unorthodox Astra Militarum regiment uneasily coexist, and dark secrets lie at the heart of their faith.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P3-12')),
  ('P3-13.1', 3, 'Nightbringer', 'Graham McNeill', 320, 'novel', 1, 2002, 'high', 'novel', false, 'sub_item', 'Pavonis', 'Ultima Segmentum', NULL, 'Uriel Ventris', '{"Pasanius Lysane","Lord Admiral Tiberius"}', 'Ultramarines 4th Company', 'Ultramarines', NULL, 'Military SF; Political Thriller', '{"politically intricate","slow-building","action-packed","grimdark"}', '{"Necrons","Nightbringer C''tan","renegade eldar raiders","Dark Eldar","mining world","civil unrest","political conspiracy","ancient evil","Codex Astartes","newly promoted captain","Ultima Segmentum"}', 'Newly promoted to captain of the Ultramarines Fourth Company, Uriel Ventris leads his warriors to Pavonis, an Imperial world plagued by civil disorder and renegade eldar raiders. Nothing is straightforward, and he is drawn into a race to destroy a shadowy enemy.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P3-13')),
  ('P3-13.2', 3, 'Warriors of Ultramar', 'Graham McNeill', 320, 'novel', 2, 2003, 'high', 'novel', false, 'sub_item', 'Tarsis Ultra', 'Ultima Segmentum', '999.M41', 'Uriel Ventris', '{"Pasanius Lysane","Learchus","Inquisitor Kryptman"}', 'Ultramarines 4th Company', 'Ultramarines', NULL, 'Military SF; Horror', '{"relentless","horror-tinged","large-scale","bleak"}', '{"Tyranids","Hive Fleet Leviathan","Mortifactors Chapter","Imperial Guard","planetary invasion","Codex Astartes dilemma","bio-horror","alliance","Eastern Fringe"}', 'The Great Devourer descends on Tarsis Ultra. Captain Uriel Ventris and his warriors, allied with the barbaric Mortifactors Chapter, rally the planet''s defenders against the tyranids. To defeat the xenos horror, Uriel may have to turn his back on the Ultramarines'' teachings.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P3-13')),
  ('P3-13.3', 3, 'Dead Sky Black Sun', 'Graham McNeill', 410, 'novel', 3, 2004, 'high', 'novel', false, 'sub_item', 'Medrengard', 'Eye of Terror', NULL, 'Uriel Ventris', '{"Pasanius Lysane","Honsou","Ardaric Vaanes"}', 'Ultramarines 4th Company (in exile)', 'Ultramarines', NULL, 'Horror; Quest/Adventure', '{"grim","nightmarish","body-horror","oppressive"}', '{"Iron Warriors","Chaos Space Marines","Medrengard","daemon engines","Daemonculaba","the Unfleshed","Honsou","daemon world","quest for atonement","the Warp"}', 'Exiled from their Chapter, former captain Uriel Ventris and battle-brother Pasanius embark on a deadly quest into the daemon world Medrengard. There they must destroy a facility creating new warriors for the Traitor Legions, while Warsmith Honsou''s Iron Warriors stand in their way.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P3-13')),
  ('P3-13.4', 3, 'Chains of Command', NULL, NULL, 'short', 4, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Thracia', NULL, '999.M41', 'Uriel Ventris', '{"Captain Idaeus"}', 'Ultramarines 4th Company', NULL, NULL, 'Military SF', '{"fast-paced","action-heavy","brutal","sacrificial"}', '{"Night Lords","Traitor Legion","Codex Astartes","bridge demolition","command and leadership","mentor''s sacrifice","origin story","Thracia"}', 'Uriel Ventris is a warrior who fights every battle according to the Codex Astartes. When a mission to destroy a vital bridge goes wrong, he must quickly learn to work outside the codes and rely on his own initiative.', 'optional', NULL, NULL, false, 'omnibus component, enriched but not progress-trackable (parent counts)', (SELECT id FROM public.books WHERE entry_id='P3-13')),
  ('P3-13.5', 3, 'Leviathan', NULL, NULL, 'short', 5, NULL, NULL, 'short_story', false, 'sub_item_optional', 'space hulk', 'Mobile/Fleet', NULL, 'Uriel Ventris', '{"Pasanius Lysane"}', 'Ultramarines 4th Company', NULL, NULL, 'Horror; Military SF', '{"claustrophobic","tense","creepy","action"}', '{"space hulk","Orks","Genestealers","Tyranid vanguard","zero-gravity combat","boarding action"}', 'Uriel Ventris returns to action after Pavonis. He and his company are charged to destroy a space hulk that may carry an Ork warband, but a deadlier foe awaits them in its dark corridors.', 'optional', NULL, NULL, false, 'omnibus component, enriched but not progress-trackable (parent counts)', (SELECT id FROM public.books WHERE entry_id='P3-13')),
  ('P3-13.6', 3, 'Consequences', NULL, NULL, 'short', 6, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Macragge', 'Ultima Segmentum', NULL, 'Uriel Ventris', '{"Pasanius Lysane","Marneus Calgar","Learchus"}', 'Ultramarines 4th Company', NULL, NULL, 'Political Thriller; Character Study', '{"tense","introspective","somber","dialogue-driven"}', '{"Codex Astartes","trial and judgement","Death Oath","exile","Fortress of Hera","Macragge","chapter politics","honour"}', 'Uriel Ventris has saved Tarsis Ultra from the tyranids, but at the cost of his honour, having broken faith with the Codex Astartes. The masters of the Chapter call for his death, but one last chance may remain to reclaim his honour and his life.', 'optional', NULL, NULL, false, 'omnibus component, enriched but not progress-trackable (parent counts)', (SELECT id FROM public.books WHERE entry_id='P3-13')),
  ('P3-14.1', 3, 'The Killing Ground', 'Graham McNeill', 320, 'novel', 1, 2008, 'medium', 'novel', false, 'sub_item', 'Salinas', NULL, NULL, 'Uriel Ventris', '{"Pasanius Lysane","Leto Barbaden"}', 'Ultramarines 4th Company (in exile)', 'Ultramarines', NULL, 'Horror; Quest/Adventure', '{"haunting","ghostly","bleak","melancholy"}', '{"ghosts and hauntings","thin Warp","Imperial Guard conquest world","rebellion (Sons of Salinas)","the Unfleshed","Grey Knights","Chaos taint","psyker","massacre","war trauma","redemption quest"}', 'Returning to the Imperium after a deadly mission in the Eye of Terror, Ultramarines exiles Uriel Ventris and Pasanius find themselves on a war-torn world where warp-tainted rebels hold power, and where they themselves are suspected of serving the Dark Gods.', 'core', NULL, NULL, false, '320 (2x) vs 416 reprint - mass market used', (SELECT id FROM public.books WHERE entry_id='P3-14')),
  ('P3-14.2', 3, 'Courage and Honour', 'Graham McNeill', 320, 'novel', 2, 2009, 'medium', 'novel', false, 'sub_item', 'Pavonis', 'Ultima Segmentum', NULL, 'Uriel Ventris', '{"Pasanius Lysane","Learchus"}', 'Ultramarines 4th Company', 'Ultramarines', NULL, 'Military SF; War Epic', '{"classic heroic","action-packed","redemptive","disciplined"}', '{"Tau Empire","Kroot","Pavonis","planetary invasion","Codex Astartes","Ethereal","Imperial Guard","redemption","set-piece warfare","Ultima Segmentum"}', 'Newly reinstated as captain of the Ultramarines Fourth Company, Uriel Ventris leads his warriors on Pavonis, now a target of the upstart Tau Empire. With the Chapter watching, he must win by following the Codex Astartes, lest he be exiled once more.', 'core', NULL, NULL, false, '318/320 orig vs 416 reprint - orig used', (SELECT id FROM public.books WHERE entry_id='P3-14')),
  ('P3-14.3', 3, 'The Chapter''s Due', 'Graham McNeill', 320, 'novel', 3, 2010, 'high', 'novel', false, 'sub_item', 'Ultramar', 'Ultima Segmentum', '999.M41', 'Uriel Ventris', '{"Pasanius Lysane","Marneus Calgar","Honsou","Varro Tigurius"}', 'Ultramarines 4th Company', 'Ultramarines', NULL, 'War Epic; Military SF', '{"epic","large-scale","desperate","bittersweet"}', '{"Iron Warriors","Chaos Space Marines","Daemon Prince M''kar","the Bloodborn","Honsou","invasion of Ultramar","Calth","Talassar","daemons","void warfare","Raven Guard","Inquisition","final showdown"}', 'After defeating the tau, Uriel Ventris returns to Macragge to little respite. The traitorous Iron Warriors, led by Warsmith Honsou, have gathered a massive warband to annihilate the realm of Ultramar. It falls to Uriel to take on Honsou and save his Chapter''s homeworld.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P3-14')),
  ('P3-17.1', 3, 'Primogenitor', 'Josh Reynolds', 352, 'novel', 1, 2016, 'high', 'novel', false, 'sub_item', 'Eye of Terror (Crone World of Urum)', 'Eye of Terror', 'M41', 'Fabius Bile', '{"Igori","Oleander Koh"}', 'The Consortium', 'Chaos', NULL, 'Character Study; Quest/Adventure', '{"darkly humorous","macabre","twisted","fun"}', '{"genetic experimentation","mad scientist","Chaos Space Marines","Emperor''s Children","New Men","Gland-hounds","cloning","Eye of Terror","Shattering of Lugganath","renegade","transhumanism","dark humour","obsession","antihero"}', 'Once Chief Apothecary of the Emperor''s Children, the renegade geneticist Fabius Bile, exiled deep in the Eye of Terror, is lured from his experiments when a former student brings word of an irresistible prize.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P3-17')),
  ('P3-17.2', 3, 'Clonelord', 'Josh Reynolds', 360, 'novel', 2, 2018, 'medium', 'novel', false, 'sub_item', 'Solemnace', 'Eastern Fringe', NULL, 'Fabius Bile', '{"Igori","Savona","Trazyn the Infinite"}', 'The Consortium', 'Chaos', NULL, 'Character Study; Quest/Adventure', '{"dark","ironic","subversive","character-driven"}', '{"genetic manipulation","cloning","Emperor''s Children","Necrons","Trazyn the Infinite","Eastern Fringe","New Men","Gland-hounds","betrayal","obsession","Chaos Space Marines","quest"}', 'Loathing the Legion he once served, Fabius Bile is drawn back into the machinations of the Emperor''s Children when a former comrade requests his aid, leading him into the wilds of the Eastern Fringe toward a world called Solemnace.', 'core', NULL, NULL, false, '360 vs 432 - lower used', (SELECT id FROM public.books WHERE entry_id='P3-17')),
  ('P3-17.3', 3, 'Manflayer', 'Josh Reynolds', 368, 'novel', 3, 2020, 'high', 'novel', false, 'sub_item', NULL, NULL, NULL, 'Fabius Bile', '{"Igori"}', 'The Consortium', 'Chaos', NULL, 'Character Study; War Epic', '{"tragic","dramatic","bleak","twisted"}', '{"Homo Novus","New Men","Dark Eldar","haemonculi","Thirteen Scars","Commorragh","cloning","genetic experimentation","Chaos Space Marines","survival","legacy","trilogy conclusion"}', 'As his Homo Novus project comes to fruition, Fabius Bile faces a deadly new threat from the haemonculi of the Thirteen Scars, forcing him to seek out new allies and old enemies to preserve all he has built.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P3-17')),
  ('P3-18.1', 3, 'Dark Apostle', 'Anthony Reynolds', 256, 'novel', 1, 2007, 'high', 'novel', false, 'sub_item', 'Tanakreg', NULL, 'M41', 'Marduk', '{"Jarulek","Kol Badar","Burias"}', '34th Host (Word Bearers)', 'Word Bearers', NULL, 'Military SF; War Epic', '{"grim","relentless","brutal","bleak"}', '{"Word Bearers","Chaos Space Marines","daemon worship","gehemehnet (tower)","siege","enslavement","Necrons","Nexus Arrangement","Imperial Guard","Adeptus Mechanicus","faith/zealotry","invasion","Long War"}', 'Driven on by dark visions, Dark Apostle Jarulek of the Word Bearers lays waste to the Imperial planet of Tanakreg; after brutally enslaving the population they set them to work building a monstrous tower before Imperial forces can reclaim the world.', 'core', NULL, NULL, false, '~245-256 review range', (SELECT id FROM public.books WHERE entry_id='P3-18')),
  ('P3-18.2', 3, 'Dark Disciple', 'Anthony Reynolds', 413, 'novel', 2, 2008, 'medium', 'novel', false, 'sub_item', NULL, NULL, NULL, 'Marduk', '{"Kol Badar","Burias","Darioq"}', '34th Host (Word Bearers)', 'Word Bearers', NULL, 'Military SF; Quest/Adventure', '{"dark","sickly","grim","action-driven"}', '{"Word Bearers","Chaos Space Marines","Tyranids","Dark Eldar","xenos artefact","ambition","faith","warzone","Long War","quest"}', 'Driven by lust for power, aspiring Dark Apostle Marduk strives to unlock the secrets of an ancient artefact, throwing the Word Bearers into a warzone caught between their Imperial enemies, the Tyranids and a third sadistic faction.', 'core', NULL, NULL, false, 'single source', (SELECT id FROM public.books WHERE entry_id='P3-18')),
  ('P3-18.3', 3, 'Dark Creed', 'Anthony Reynolds', 413, 'novel', 3, 2009, 'medium', 'novel', false, 'sub_item', 'Boros Gate (Boros System)', 'Segmentum Obscurus', NULL, 'Marduk', '{"Kol Badar","Burias","Erebus"}', '34th Host (Word Bearers)', 'Word Bearers', NULL, 'War Epic; Military SF', '{"epic","grand-scale","bloody","ambitious"}', '{"Word Bearers","Chaos Space Marines","White Consuls","Necrons","Nexus Arrangement","13th Black Crusade","space battle","ambition","betrayal","Long War"}', 'Dark Apostle Marduk wages war against the White Consuls while harnessing the Nexus Arrangement, but as victory nears an old enemy returns, forcing him to survive the Necrons, the White Consuls and his own Legion.', 'core', NULL, NULL, false, 'single source', (SELECT id FROM public.books WHERE entry_id='P3-18')),
  ('P3-18.4', 3, 'Torment', NULL, NULL, 'short', 4, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Eye of Terror (daemon world)', 'Eye of Terror', NULL, 'Marduk', '{"Kol Badar","Burias"}', '34th Host (Word Bearers)', NULL, NULL, 'Horror; Military SF', '{"grim","psychological","horror-tinged"}', '{"Word Bearers","Chaos Space Marines","Eye of Terror","daemon world","Nurgle","the Tallyman","rescue","horror","Long War"}', 'Stranded above a daemon world in the heart of the Eye of Terror, Marduk and the 34th Host venture onto the tainted planet in search of missing legionaries, only to encounter the daemonic servant of the Plague God known as the Tallyman.', 'optional', NULL, NULL, false, 'omnibus short, enriched but not progress-trackable', (SELECT id FROM public.books WHERE entry_id='P3-18')),
  ('P3-20.1', 3, 'Storm of Iron', 'Graham McNeill', 320, 'novel', 1, 2002, 'medium', 'novel', false, 'sub_item', 'Hydra Cordatus', 'Segmentum Obscurus', 'Late M41 (990s.M41)', 'Honsou', '{"Forrix","Kroeger"}', 'Iron Warriors Grand Company', 'Iron Warriors', NULL, 'Military SF; War Epic', '{"grim","brutal","tense","morally grey"}', '{"Iron Warriors","Chaos Space Marines","siege warfare","Imperial Guard","Adeptus Mechanicus","Titans","daemonic possession","fortress","attrition","half-breed","gene-seed","Long War"}', 'Few foes inspire more dread than the Chaos Space Marines, and hell has come to Hydra Cordatus as a massive force of Iron Warriors invades the planet and lays siege to its mighty Imperial citadel.', 'core', NULL, NULL, false, 'single source', (SELECT id FROM public.books WHERE entry_id='P3-20')),
  ('P3-20.2', 3, 'Iron Warrior', NULL, NULL, 'novel', 2, NULL, NULL, 'novella', false, 'sub_item_optional', 'The Indomitable (Ultramarines star fort, Ultramar)', 'Ultima Segmentum', '999.M41', 'Honsou', '{"Uriel Ventris","M''kar"}', 'Iron Warriors Grand Company', NULL, NULL, 'Military SF', '{"brutal","action-packed","grim"}', '{"Iron Warriors","Chaos Space Marines","Ultramarines","revenge","siege warfare","star fort","Daemon Prince","vendetta","Long War"}', 'Of all the enemies Warmaster Honsou has made, one stands above all others - Uriel Ventris - and his hatred burns so brightly he attempts the near-impossible: capturing the most heavily defended of the Ultramarines star forts.', 'optional', NULL, NULL, false, 'omnibus component, enriched but not progress-trackable (parent counts)', (SELECT id FROM public.books WHERE entry_id='P3-20')),
  ('P3-24.1', 3, 'Soul Drinker', 'Ben Counter', 288, 'novel', 1, 2002, 'high', 'novel', false, 'sub_item', 'Lakonia (Van Skorvold star fort)', NULL, NULL, 'Sarpedon', '{"Tellos","Luko"}', 'Soul Drinkers Chapter (Imperial Fists successor)', 'Soul Drinkers', NULL, 'Military SF; War Epic', '{"dark","brutal","fast-paced","action-packed"}', '{"Space Marines","Imperial Fists successor","Adeptus Mechanicus","relic/Soulspear","mutation","Chaos","Inquisition","honour","rebellion","loyalty","daemon"}', 'The Soul Drinkers have served the Emperor loyally for millennia, but their obsessive desire to retrieve an ancient relic throws them into conflict with those they are honour-bound to obey, forcing an impossible choice.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P3-24')),
  ('P3-24.2', 3, 'The Bleeding Chalice', 'Ben Counter', 413, 'novel', 2, 2003, 'high', 'novel', false, 'sub_item', 'Stratix Luminae', NULL, NULL, 'Sarpedon', '{"Tellos","Inquisitor Thaddeus","Teturact"}', 'Soul Drinkers Chapter (Imperial Fists successor)', 'Soul Drinkers', NULL, 'Military SF; Horror', '{"dark","grim","horror-tinged","sobering"}', '{"Space Marines","mutation","gene-seed","Inquisition","Nurgle","zombie plague","Teturact","renegades","corruption","pursuit","horror"}', 'Fighting a losing battle against mutation, the Soul Drinkers track leads toward pure genetic material that might stave off their corruption, while Inquisitor Thaddeus pursues them and a heretic psyker schemes to raise an empire of plague and death.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P3-24')),
  ('P3-24.3', 3, 'Crimson Tears', 'Ben Counter', 416, 'novel', 3, 2004, 'high', 'novel', false, 'sub_item', 'Entymion IV', NULL, NULL, 'Sarpedon', '{"Tellos","Reinez","Eumenes"}', 'Soul Drinkers Chapter (Imperial Fists successor)', 'Soul Drinkers', NULL, 'Military SF; War Epic', '{"fast-paced","combat-heavy","bloody","grim"}', '{"Space Marines","excommunication","Crimson Fists","Dark Eldar","Khorne","Chaos","mutation","renegades","pursuit","war"}', 'Betrayed by those they fought to protect and declared heretics, the Soul Drinkers - caught between the dark forces of Chaos and the Crimson Fists Space Marines - have no choice but to come out fighting.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P3-24')),
  ('P3-25.1', 3, 'Chapter War', 'Ben Counter', 413, 'novel', 1, 2007, 'high', 'novel', false, 'sub_item', 'Vanqualis', 'Segmentum Tempestus', 'M41', 'Sarpedon', '{"Eumenes","Iktinos","Luko"}', 'Soul Drinkers Chapter', 'Soul Drinkers', NULL, 'Military SF; Political Thriller', '{"chaotic","internecine","tense","action-heavy"}', '{"Orks","Howling Griffons Chapter","901st Penal Legion","hive world","chapter civil war","mutation","renegade Space Marines","Imperial Fists successor","loyalty versus Chaos"}', 'Excommunicate and led by Sarpedon, the Soul Drinkers are desperate to restore their standing. When Vanqualis is attacked by orks, Sarpedon answers, seeing a chance to prove their loyalty, but factions within the Chapter move against him, and the Howling Griffons arrive too.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P3-25')),
  ('P3-25.2', 3, 'Hellforged', 'Ben Counter', 416, 'novel', 2, 2009, 'high', 'novel', false, 'sub_item', 'Selaaca / Veiled Region', 'Segmentum Tempestus', NULL, 'Sarpedon', '{"Iktinos","Luko","Archmagos Voar"}', 'Soul Drinkers Chapter', 'Soul Drinkers', NULL, 'Horror; Military SF', '{"nihilistic","dread","dwindling","atmospheric"}', '{"Necrons","Adeptus Mechanicus","Selaaca tomb world","Veiled Regions","the Soulspear","pursuit","renegade chapter","Imperial Fists","Segmentum Tempestus"}', 'When a Chapter falls from grace, the Imperium will stop at nothing to hunt them down. The disgraced Soul Drinkers attempt to elude their pursuers in a desolate region of space, but Sarpedon and his battle-brothers soon find themselves fighting for their lives against the necrons.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P3-25')),
  ('P3-25.3', 3, 'Phalanx', 'Ben Counter', 416, 'novel', 3, 2012, 'high', 'novel', false, 'sub_item', 'Phalanx (star fort)', 'Mobile/Fleet', NULL, 'Sarpedon', '{"Iktinos","Darnath Lysander","Luko"}', 'Soul Drinkers Chapter', 'Soul Drinkers', NULL, 'Political Thriller; Military SF', '{"climactic","poignant","tense","reflective"}', '{"Imperial Fists","the Phalanx star fort","trial and judgement","Sisters of Battle","Inquisition","Adeptus Mechanicus","daemons","multiple Chapters","renegade chapter","Chaos incursion"}', 'The Imperial Fists'' star fort Phalanx hosts Space Marines from half a dozen Chapters, Inquisitors, Sisters of Battle and Mechanicus agents to witness the end of a Chapter, as the renegade Soul Drinkers are put on trial. But dark forces stir, and even this might may not suffice.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P3-25')),
  ('P3-25.4', 3, 'Daenyathos', NULL, NULL, 'novel', 4, NULL, NULL, 'novella', false, 'sub_item_optional', NULL, NULL, 'M36 / Age of Apostasy', 'Daenyathos', NULL, 'Soul Drinkers Chapter', NULL, NULL, 'Character Study; Horror', '{"dark","philosophical","tragic","foreboding"}', '{"Soul Drinkers","Chaplain","Catechism Martial","Age of Apostasy","corruption","prelude and origin","philosopher-soldier","damnation","Imperial Fists successor"}', 'For millennia the writings of Chaplain Daenyathos have guided the Soul Drinkers. This is the story of the philosopher-soldier''s life, of his rise and tragic fall, and of the dark secret at the heart of his Catechisms Martial that would one day damn the Chapter.', 'optional', NULL, NULL, false, 'omnibus component, enriched but not progress-trackable (parent counts)', (SELECT id FROM public.books WHERE entry_id='P3-25')),
  ('P4-04.1', 4, 'The Carrion Throne', 'Chris Wraight', 384, 'novel', 1, 2017, 'high', 'novel', false, 'sub_item', 'Terra', 'Segmentum Solar', 'Late M41 (end of the 41st Millennium, before the Great Rift)', 'Erasmus Crowl (Ordo Hereticus Inquisitor)', '{"Luce Spinoza","Navradaran","Adamara Rassilo"}', 'Inquisition (Ordo Hereticus)', 'Inquisition', NULL, 'Mystery; Political Thriller', '{"dark","grim","claustrophobic","atmospheric"}', '{"Terra","Imperial Palace","Inquisition","Ordo Hereticus","Erasmus Crowl","Luce Spinoza","Adeptus Custodes","Navradaran","Adamara Rassilo","Sanguinala festival","conspiracy investigation","Drukhari threat","gothic atmosphere","Segmentum Solar"}', 'In the hellish sprawl of Imperial Terra, Ordo Hereticus Inquisitor Erasmus Crowl uncovers a dark conspiracy reaching into the Imperial Palace. As he and his acolyte Spinoza dig deeper, hidden forces begin hunting them across the Throneworld.', 'core', NULL, NULL, false, 'PB (S&S); 304 was HC - PB used', (SELECT id FROM public.books WHERE entry_id='P4-04')),
  ('P4-04.2', 4, 'The Hollow Mountain', 'Chris Wraight', 352, 'novel', 2, 2019, 'high', 'novel', false, 'sub_item', 'Terra', 'Segmentum Solar', 'End of M41 (Great Rift becoming manifest)', 'Erasmus Crowl (Ordo Hereticus Inquisitor)', '{"Luce Spinoza","Niir Khazad","Revus"}', 'Inquisition (Ordo Hereticus)', 'Inquisition', NULL, 'Mystery; Political Thriller', '{"darker","tense","oppressive","brooding"}', '{"Terra","Imperial Palace","Inquisition","Ordo Hereticus","Erasmus Crowl","Luce Spinoza","Revus","Niir Khazad","High Lords of Terra","conspiracy","opening of the Great Rift","investigation thriller","gothic atmosphere","Segmentum Solar"}', 'Inquisitor Crowl has uncovered a terrible plot rooted in Terra''s highest levels. He and acolyte Spinoza pursue their leads in secret, every move inviting danger - even as a greater peril looms in the skies and the Great Rift becomes manifest.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P4-04')),
  ('P4-04.3', 4, 'The Dark City', 'Chris Wraight', 368, 'novel', 3, 2022, 'high', 'novel', false, 'sub_item', 'Terra', 'Segmentum Solar', 'M42 (opening of the Great Rift; failure of the Astronomican)', 'Luce Spinoza (Ordo Hereticus Interrogator)', '{"Erasmus Crowl","Niir Khazad","Navradaran"}', 'Inquisition (Ordo Hereticus)', 'Inquisition', NULL, 'Mystery; Quest/Adventure', '{"desperate","dark","twisting","atmospheric"}', '{"Terra","the Webway","Commorragh","Drukhari","Inquisition","Ordo Hereticus","Luce Spinoza","Erasmus Crowl","Niir Khazad","Navradaran","failure of the Astronomican","opening of the Great Rift","Adeptus Mechanicus","Luna","trilogy finale"}', 'The Throneworld reels from the opening of the Great Rift and the failure of the Astronomican. With Inquisitor Crowl missing, his interrogator Spinoza must choose whether to seek him out or defend their diminished domain as enemies close in.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P4-04')),
  ('P4-04.4', 4, 'Argent', NULL, NULL, 'short', 4, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Forfoda', NULL, NULL, 'Luce Spinoza (Ordo Hereticus Interrogator)', NULL, 'Inquisition (Ordo Hereticus)', NULL, NULL, 'Military SF; Character Study', '{"tense","gritty","reverent"}', '{"Forfoda","Imperial Fists","Inquisition","Interrogator Luce Spinoza","traitor-held hive","Space Marines","Vaults of Terra prequel","origin story"}', 'Interrogator Luce Spinoza''s hunt for a traitor brings her to Forfoda and into the company of the Imperial Fists. Unearthing a den of corruption, she learns what it means to fight beside the Emperor''s Angels - and vows to prove herself worthy.', 'optional', NULL, NULL, false, 'omnibus short, enriched but not progress-trackable', (SELECT id FROM public.books WHERE entry_id='P4-04')),
  ('P4-04.5', 4, 'Sanguine', NULL, NULL, 'short', 5, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Terra', 'Segmentum Solar', NULL, 'Erasmus Crowl (Ordo Hereticus Inquisitor)', NULL, 'Inquisition (Ordo Hereticus)', NULL, NULL, 'Mystery; Character Study', '{"introspective","brooding","character-focused"}', '{"Terra","Inquisition","Ordo Hereticus","Erasmus Crowl","mercantile interests","locked-room mystery","Vaults of Terra prequel","Segmentum Solar"}', 'Inquisitor Erasmus Crowl receives a message from an old friend and soon finds himself entangled with powerful mercantile interests.', 'optional', NULL, NULL, false, 'omnibus short, enriched but not progress-trackable', (SELECT id FROM public.books WHERE entry_id='P4-04')),
  ('P4-04.6', 4, 'Okira', NULL, NULL, 'short', 6, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Shoba', NULL, NULL, 'Niir Khazad (death cult assassin)', '{"Hovash Phaelias"}', 'Death Cult (Inquisition)', NULL, NULL, 'Character Study', '{"introspective","origin-tale","sombre"}', '{"Shoba","Niir Khazad","death cult assassin","Inquisition","Hovash Phaelias","Schola training","origin story"}', 'The tale follows the early life of death cult assassin Niir Khazad - from her childhood among the scavenger tribes of the death world Shoba, through training at the Schola of the Inquisition, to entering the service of Inquisitor Hovash Phaelias.', 'optional', NULL, NULL, false, 'omnibus short, enriched but not progress-trackable', (SELECT id FROM public.books WHERE entry_id='P4-04')),
  ('P5-01.1', 5, 'Dark Imperium', 'Guy Haley', 336, 'novel', 1, 2017, 'high', 'novel', false, 'sub_item', 'Macragge (Ultramar)', 'Ultima Segmentum', 'post-Great Rift / 012.M42', 'Roboute Guilliman', '{"Mortarion","Marneus Calgar","Belisarius Cawl"}', 'Ultramarines', 'Ultramarines', '{"Death Guard"}', 'War Epic; Character Study', '{"grimdark","introspective","melancholic","epic"}', '{"Ultramarines","Roboute Guilliman","Death Guard","Mortarion","Nurgle","Plague War","Indomitus Crusade","Macragge","Ultramar","Primaris Space Marines","Great Rift","Scourge Stars","Belisarius Cawl","primarch introspection"}', 'Cadia has fallen and the Great Rift has split the galaxy. The reborn primarch Roboute Guilliman leads the Indomitus Crusade, but Nurgle''s Death Guard pour from the Scourge Stars toward Macragge, drawing him to Ultramar and a confrontation with the plague god''s hosts.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P5-01')),
  ('P5-01.2', 5, 'Plague War', 'Guy Haley', 416, 'novel', 2, 2018, 'high', 'novel', false, 'sub_item', 'Parmenio (Ultramar)', 'Ultima Segmentum', 'post-Great Rift / M42', 'Roboute Guilliman', '{"Mortarion","Marneus Calgar"}', 'Ultramarines', 'Ultramarines', '{"Death Guard"}', 'Military SF; War Epic', '{"grim","brooding","militaristic","tense"}', '{"Ultramarines","Roboute Guilliman","Mortarion","Death Guard","Nurgle","Parmenio","Ultramar","Plague War","Indomitus Crusade","Primaris Space Marines","primarch clash","faith vs reason"}', 'Across the worlds of Ultramar the war grinds on. Guilliman seeks to drive Mortarion and his Death Guard from his realm, but when the brothers clash on Parmenio the intervention of a greater power threatens to upend the Imperial Regent''s understanding of the galaxy.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P5-01')),
  ('P5-01.3', 5, 'Godblight', 'Guy Haley', 448, 'novel', 3, 2021, 'high', 'novel', false, 'sub_item', 'Iax (Ultramar)', 'Ultima Segmentum', 'post-Great Rift / M42', 'Roboute Guilliman', '{"Mortarion","Marneus Calgar"}', 'Ultramarines', 'Ultramarines', '{"Death Guard"}', 'War Epic; Military SF', '{"epic","visceral","climactic","grim"}', '{"Ultramarines","Roboute Guilliman","Mortarion","Death Guard","Nurgle","Iax","Ultramar","Godblight","Plague War","Cauldron of Nurgle","primarch duel","climactic battle"}', 'The paths of Guilliman and his fallen brother Mortarion converge on the dying garden world of Iax, where Mortarion wields the Godblight - a disease created in the Cauldron of Nurgle with the power to destroy a son of the Emperor - as the climactic battle of the Plague War decides the fate of Ultramar.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P5-01')),
  ('P5-14.1', 5, 'Celestine: The Living Saint', 'Andy Clark', 175, 'novel', 1, NULL, 'medium', 'novella', false, 'sub_item', NULL, NULL, 'M41', 'Saint Celestine', NULL, 'Adepta Sororitas', 'Adepta Sororitas', NULL, 'Character Study; Horror', '{"dark","unsettling","faith-driven","grim"}', '{"Adepta Sororitas","Saint Celestine","Living Saint","death and rebirth","resurrection","the Warp","daemons","heretics","God-Emperor","faith and martyrdom","sacrifice","character study","Andy Clark"}', 'Saint Celestine is the living embodiment of the God-Emperor''s wrath, leading the faithful to victory. But each time she falls in battle she is trapped in a realm of torment where her faith is tested so she may live again.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P5-14')),
  ('P5-14.2', 5, 'Celestine: Revelation', 'Andy Clark', 23, 'novel', 2, NULL, 'low', 'novella', false, 'sub_item_optional', 'Machoria', NULL, NULL, 'Saint Celestine', NULL, 'Adepta Sororitas', 'Adepta Sororitas', NULL, 'Character Study; Military SF', '{"fervent","reflective","action-driven","faithful"}', '{"Adepta Sororitas","Saint Celestine","Machoria","Arnokh the Bloodlord","Chaos Lord","single combat","Sisters of Battle","Astra Militarum","faith","siege","short story"}', 'The war for Machoria goes poorly; of the Sisters who defended it only Celestine remains. As she battles a rampaging Chaos foe in single combat, she recalls her life before death and rebirth.', 'optional', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P5-14')),
  ('P5-14.3', 5, 'Ephrael Stern: The Heretic Saint', 'David Annandale', 196, 'novel', 3, 2019, 'medium', 'novel', false, 'sub_item', NULL, NULL, 'post-Great Rift / M42', 'Ephrael Stern', '{"Inquisitor Otto Dagover","Kyganil"}', 'Order of Our Martyred Lady', 'Adepta Sororitas', NULL, 'Horror; Quest/Adventure', '{"bleak","desperate","faith-tested","ominous"}', '{"Adepta Sororitas","Ephrael Stern","Daemonifuge","Thrice-Born","Heretic Saint","Order of Our Martyred Lady","Imperium Nihilus","Great Rift","Chaos","Inquisitor Otto Dagover","Kyganil","Harlequin","living weapon against Chaos","faith"}', 'Trapped deep in Imperium Nihilus after the Great Rift, the maligned Sister Ephrael Stern fears the Imperium is lost until a mysterious stranger offers a new destiny, one that may yet see it saved.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P5-14')),
  ('P5-14.4', 5, 'The Triumph of Saint Katherine', 'Danie Ware', 181, 'novel', 4, 2020, 'high', 'novel', false, 'sub_item', 'Kiros', NULL, NULL, 'Sister Avra', '{"Saint Katherine"}', 'Order of Our Martyred Lady', 'Adepta Sororitas', NULL, 'War Epic; Character Study', '{"reverent","mythic","faithful","hopeful-amid-darkness"}', '{"Adepta Sororitas","Sister Avra","Saint Katherine","Triumph of Saint Katherine","funerary procession","Order of Our Martyred Lady","Major Orders","Kiros","relics","faith and martyrdom","heresy","hymns","oral tradition"}', 'Carried by six Sisters each embodying a revered saint, the funerary procession of Saint Katherine marches world to world. Young Sister Avra, defending Kiros, harbours a secret shame and is overcome by a vision of greater purpose.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P5-14')),
  ('P5-15.1', 5, 'The Bloodied Rose', 'Danie Ware', 105, 'novel', 1, 2018, 'low', 'novel', false, 'sub_item', 'Lautis', NULL, NULL, 'Sister Superior Augusta', '{"Jatoya","Viola","Akemi"}', 'Order of the Bloody Rose', 'Adepta Sororitas', NULL, 'Horror; Military SF', '{"tense","creepy","bombastic","faith-driven"}', '{"Adepta Sororitas","Sister Augusta","Order of the Bloody Rose","Lautis","jungle world","cathedral","crypts","Chaos","horror","Sisters of Battle","squad","faith and fire","novella"}', 'On the fetid jungle world of Lautis a horror rises from a crumbling cathedral. Sister Superior Augusta and her squad of the Bloody Rose are sent to purge the darkness with prayer and bolter and uncover the truth in the crypts.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P5-15')),
  ('P5-15.2', 5, 'Wreck and Ruin', 'Danie Ware', 105, 'novel', 2, 2019, 'low', 'novel', false, 'sub_item', 'Lycheate', NULL, NULL, 'Sister Superior Augusta', '{"Inquisitor Istrix","Scafidis Zale"}', 'Order of the Bloody Rose', 'Adepta Sororitas', NULL, 'Mystery; Military SF', '{"tense","atmospheric","suspenseful","faith-challenging"}', '{"Adepta Sororitas","Sister Augusta","Order of the Bloody Rose","Lycheate","forge world","Inquisition","Inquisitor Istrix","Scafidis Zale","psyker-witch","heretic hunt","renegades","Ophelia VII","faith","novella"}', 'Summoned into the service of the Inquisition, Augusta and her squad travel to the industrialised world of Lycheate to hunt the dangerous psyker-witch Scafidis Zale, while the secretive Inquisitor Istrix tests their faith.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P5-15')),
  ('P5-15.3', 5, 'The Rose in Anger', 'Danie Ware', 139, 'novel', 3, 2021, 'high', 'novel', false, 'sub_item', 'Lycheate', NULL, NULL, 'Sister Superior Augusta', '{"Jatoya","Viola"}', 'Order of the Bloody Rose', 'Adepta Sororitas', NULL, 'Military SF; Horror', '{"action-packed","grim","tense","faith-driven"}', '{"Adepta Sororitas","Sister Augusta","Order of the Bloody Rose","Lycheate","forge world","heretek","Dark Mechanicum","Mechanicus army","battle tanks","battle muster","Chaos","faith","Sisters of Battle","novella"}', 'Returning to the forge world of Lycheate as part of their Order''s battle muster, Augusta and her squad of the Bloody Rose face a heretek Mechanicus army, and something even more malign that lurks within the planet''s darkness.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P5-15')),
  ('P5-27.1', 5, 'The Twice-Dead King: Ruin', 'Nate Crowley', 368, 'novel', 1, 2021, 'high', 'novel', false, 'sub_item', 'Sedh', NULL, NULL, 'Oltyx', '{"Unnas","Djoseras"}', 'Ogdobekh Dynasty', 'Necrons', NULL, 'War Epic; Character Study', '{"melancholy","tragic","darkly humorous","gothic"}', '{"Necrons","Ogdobekh Dynasty","Oltyx","Sedh","ork invasion","exile","necron court politics","biotransference","flayer curse","partitioned subminds","Imperial crusade","dynastic feud","vengeance","gothic tragedy"}', 'Exiled to the miserable world of Sedh, disgraced necron lord Oltyx fights endless ork invaders while consumed by bitterness. When a far greater doom appears, he must break his exile and return to the court that cast him out.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P5-27')),
  ('P5-27.2', 5, 'The Twice-Dead King: Reign', 'Nate Crowley', 400, 'novel', 2, 2022, 'high', 'novel', false, 'sub_item', 'Battleship Akrops', 'Mobile/Fleet', NULL, 'Oltyx', NULL, 'Ogdobekh Dynasty', 'Necrons', NULL, 'War Epic; Character Study', '{"bleak","melancholy","gothic","claustrophobic"}', '{"Necrons","Ogdobekh Dynasty","Oltyx","battleship Akrops","flayer curse","Imperium of Man crusade","necron court politics","kingship","fleet voyage","survival","gothic tragedy"}', 'Granted the throne of the Ogdobekh Dynasty at last, Oltyx finds kingship aboard the dying battleship Akrops, fleeing a vast Imperial armada while the flayer curse festers within his fleet. He must become a different kind of king to survive.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P5-27')),
  ('P5-27.3', 5, 'Severed', 'Nate Crowley', 107, 'novel', 3, NULL, 'medium', 'novella', false, 'sub_item_optional', 'Doahht (Ghoul Stars)', NULL, NULL, 'Vargard Obyron', '{"Nemesor Zahndrekh","Imotekh the Stormlord"}', 'Sautekh Dynasty', 'Necrons', NULL, 'Character Study; Mystery', '{"tragicomic","melancholy","darkly humorous","poignant"}', '{"Necrons","Sautekh Dynasty","Vargard Obyron","Nemesor Zahndrekh","Imotekh the Stormlord","Ghoul Stars","Doahht","rebellion","loyalty","friendship","sanity","tomb world","dark humour"}', 'A rebellion in the Ghoul Stars sends the brilliant but delusion-plagued Nemesor Zahndrekh and his loyal Vargard Obyron, alongside uneasy allies, to unravel a mystery that threatens their bond and Zahndrekh''s fragile sanity.', 'optional', NULL, NULL, false, 'added in v3.0', (SELECT id FROM public.books WHERE entry_id='P5-27')),
  ('P5-27.4', 5, 'One Million Years', 'Nate Crowley', 42, 'short', 4, NULL, 'medium', 'short_story', false, 'sub_item_optional', 'Awakening necron ship', 'Mobile/Fleet', NULL, NULL, NULL, 'Necrons', 'Necrons', NULL, 'Military SF', '{"void-set","bleak","conflict-driven"}', '{"Necrons","Leagues of Votann","awakening necron ship","xenos conflict","void setting"}', 'The eternal necrons clash with the ambitious Leagues of Votann aboard an awakening necron ship.', 'optional', NULL, NULL, false, 'added in v3.0', (SELECT id FROM public.books WHERE entry_id='P5-27')),
  ('P5-27.5', 5, 'The Life of Jethras the Martyr', 'Nate Crowley', NULL, 'short', 5, NULL, 'pending', 'short_story', false, 'sub_item_optional', NULL, NULL, NULL, 'Jethras', NULL, 'Imperium of Man', 'Necrons', NULL, 'Character Study', '{"faithful","bleak","poignant"}', '{"Imperium of Man","pilgrim","martyr","Necrons","faith","Imperial perspective"}', 'Told from the Imperial side, the story of how a lowly pilgrim found a moment of glory fighting back against the hated necrons.', 'optional', NULL, NULL, false, 'added in v3.0; page_count pending (Open Library pass)', (SELECT id FROM public.books WHERE entry_id='P5-27')),
  ('P5-27.6', 5, 'Patience', 'Nate Crowley', NULL, 'short', 6, NULL, 'pending', 'short_story', false, 'sub_item_optional', NULL, NULL, NULL, 'Voidborn crewman (unnamed)', NULL, 'Imperium of Man', 'Necrons', NULL, 'Horror', '{"tense","eerie","dread-filled"}', '{"Imperium of Man","voidborn crewman","Adeptus Astartes","Necrons","void ship","first encounter"}', 'A voidborn crewman encounters Space Marines, necrons, and something else for the first time, and lives to tell the tale.', 'optional', NULL, NULL, false, 'added in v3.0; page_count pending (Open Library pass)', (SELECT id FROM public.books WHERE entry_id='P5-27')),
  ('P5-38.1', 5, 'Path of the Warrior', 'Gav Thorpe', 416, 'novel', 1, 2010, 'high', 'novel', false, 'sub_item', 'Craftworld Alaitoc', 'Ultima Segmentum', 'M41', 'Korlandril', '{"Thirianna","Aradryan"}', 'Craftworld Alaitoc (Striking Scorpions)', 'Aeldari', NULL, 'Character Study; Military SF', '{"contemplative","immersive","tragic","slow-burn"}', '{"Aeldari","Craftworld Alaitoc","Eldar Path system","Striking Scorpions","Aspect Warriors","Path of the Warrior","artist-turned-warrior","identity and self","Imperium conflict","Exarchs","warrior-spirit","eldar society","alien culture"}', 'The ancient eldar each follow a chosen path. When the artist Korlandril feels the call to war, he abandons peace for the Path of the Warrior, becoming a Striking Scorpion of Craftworld Alaitoc as battle looms with the vengeful Imperium.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P5-38')),
  ('P5-38.2', 5, 'Path of the Seer', 'Gav Thorpe', 416, 'novel', 2, 2011, 'medium', 'novel', false, 'sub_item', 'Craftworld Alaitoc', 'Ultima Segmentum', 'M41', 'Thirianna', '{"Korlandril","Aradryan"}', 'Craftworld Alaitoc', 'Aeldari', NULL, 'Character Study; Military SF', '{"mystical","contemplative","foreboding","immersive"}', '{"Aeldari","Craftworld Alaitoc","Eldar Path system","Path of the Seer","Farseer","psychic powers","divination","the warp","daemons","spirit stones","infinity circuit","prophecy","alien culture","Imperium threat"}', 'Each eldar follows a path that shapes their fate. Thirianna abandons her simple existence for the mysterious Path of the Seer, treading a dark road into the warp to realise her psychic gifts, until her visions reveal a great threat descending on Alaitoc.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P5-38')),
  ('P5-38.3', 5, 'Path of the Outcast', 'Gav Thorpe', 416, 'novel', 3, 2012, 'medium', 'novel', false, 'sub_item', 'Craftworld Alaitoc', 'Ultima Segmentum', 'M41', 'Aradryan', '{"Korlandril","Thirianna"}', 'Craftworld Alaitoc (Rangers/Outcasts)', 'Aeldari', NULL, 'Quest/Adventure; Character Study', '{"adventurous","tragic","wandering","foreboding"}', '{"Aeldari","Craftworld Alaitoc","Path of the Outcast","Rangers","eldar Corsairs","star pirate","Exodites","Harlequins","Drukhari","wider galaxy","Imperium conflict","freedom vs duty","hubris","identity"}', 'Aradryan abandons his sheltered life on Craftworld Alaitoc to walk the Path of the Outcast, seeking the galaxy''s pleasures and dangers as a ranger and then a star pirate, until his choices set in motion events that could doom his former home.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P5-38')),
  ('P6-05.1', 6, 'Cadia Stands', 'Justin D. Hill', 320, 'novel', 501, NULL, 'high', 'novel', false, 'sub_item', 'Cadia', 'Segmentum Obscurus', '999.M41', 'Major Bendikt', '{"Minka Lesk","Ursarkar E. Creed"}', 'Cadian Shock Troops (8th Regiment)', 'Astra Militarum', NULL, 'War Epic; Military SF', '{"bleak","grim","poignant","disjointed"}', '{"fall of Cadia","13th Black Crusade","Abaddon the Despoiler","Eye of Terror","planetary siege","last stand","fortress world","Chaos invasion","multi-POV ensemble","tank warfare","Cadian identity","bulwark against Chaos","Gathering Storm"}', 'As Abaddon''s Thirteenth Black Crusade batters Cadia, the Imperium flocks to reinforce the fortress world while a terrible ritual reaches fruition, told through a wide spread of Cadian defenders fighting for survival.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-05')),
  ('P6-05.2', 6, 'Cadian Honour', 'Justin D. Hill', 400, 'novel', 502, NULL, 'medium', 'novel', false, 'sub_item', 'Potence (Gallows Cluster)', NULL, 'M42 (post-Fall of Cadia)', 'Minka Lesk', '{"General Bendikt"}', 'Cadian 101st', 'Astra Militarum', NULL, 'Military SF; Political Thriller', '{"gritty","grounded","melancholic","tense"}', '{"post-Fall survivors","refugee crisis","Chaos cult","insurrection","garrison posting","Cadian identity","capital world","Gallows Cluster","terror attacks","faith and duty","Dark Imperium"}', 'Haunted by Cadia''s loss, Sergeant Minka Lesk and the Cadian 101st are posted to the capital world Potence, where they discover a rot of Chaos running through the seemingly peaceful world.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-05')),
  ('P6-05.3', 6, 'Traitor Rock', 'Justin D. Hill', 400, 'novel', 503, NULL, 'high', 'novel', false, 'sub_item', 'Malouri (Crannog Mons)', NULL, 'early M42', 'Minka Lesk', '{"General Bendikt","Lord Militant Warmund"}', 'Cadian 101st', 'Astra Militarum', NULL, 'Military SF; War Epic', '{"visceral","vivid","brutal","attritional"}', '{"siege","island fortress","traitor Astra Militarum uprising","internecine conflict","attrition warfare","Whiteshields","Cadian identity","meat-grinder","faith and pride","heresy and insurrection"}', 'On the world of Malouri, traitor forces hold the impregnable island fortress of Crannog Mons. After years of stalemate, Minka Lesk and the Cadian 101st are tasked with breaking the meat-grinder siege.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-05')),
  ('P6-17.1', 6, 'Cadian Blood', 'Aaron Dembski-Bowden', 320, 'novel', 1701, NULL, 'medium', 'novel', false, 'sub_item', 'Kathur', 'Segmentum Obscurus', '999.M41', 'Captain Parmenion Thade', '{"Typhus"}', 'Cadian 88th Mechanised Infantry', 'Astra Militarum', NULL, 'Military SF; Horror', '{"grim","action-packed","horror","dark humour"}', '{"shrine world","Nurgle plague","plague zombies","Death Guard","Raven Guard","Inquisition","reclamation","13th Black Crusade","commissar","Cadian 88th","pandemic","banter"}', 'When the shrine world of Kathur is blighted by the plague of Nurgle, the Cadians are sent to reclaim it, and Captain Parmenion Thade is thrust into an unlikely commanding role amid a legion of the infected.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-17')),
  ('P6-17.2', 6, 'Dead Men Walking', 'Steve Lyons', 414, 'novel', 1702, NULL, 'high', 'novel', false, 'sub_item', 'Hieronymous Theta', 'Segmentum Tempestus', 'M41', 'Commissar Costellin', NULL, 'Death Korps of Krieg', 'Astra Militarum', NULL, 'Military SF; Horror', '{"bleak","brutal","cynical","harrowing"}', '{"Necron awakening","mining hive world","siege","attrition","two implacable forces","commissar liaison","civilian sacrifice","dehumanisation","bleak","cynicism"}', 'When the necrons rise beneath a mining world and decimate its defenders, salvation arrives in the form of the Death Korps of Krieg, a force as unfeeling as the necrons themselves, as casualties mount.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-17')),
  ('P6-17.3', 6, 'Redemption Corps', 'Rob Sanders', 416, 'novel', 1703, NULL, 'high', 'novel', false, 'sub_item', 'Kaligari Cradle', NULL, NULL, 'Major Zane Mortensen', NULL, 'Redemption Corps (Volscian storm troopers)', 'Astra Militarum', NULL, 'Military SF; Mystery', '{"fast-paced","action-packed","intense","gritty"}', '{"storm troopers","elite regiment","Major Mortensen","Sisters of Battle","ork invasion","troopship revolt","covert missions","mystery","non-linear timeline","Inquisition","burned hero","Cadet-Commissar Krieg"}', 'Led by the fearsome Major Mortensen, the Redemption Corps storm troopers are sent to the deadliest warzones, but caught between an ork invasion and the deadly attentions of the Battle Sisters, they fight to survive.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-17')),
  ('P6-18.1', 6, 'Imperial Glory', 'Richard Williams', 416, 'novel', 1801, NULL, 'high', 'novel', false, 'sub_item', 'Voor', NULL, NULL, 'Major Stanhope', NULL, 'Brimlock 11th (Brimlock Dragoons)', 'Astra Militarum', NULL, 'Military SF; Character Study', '{"grim","melancholic","bittersweet","character-driven"}', '{"weary veterans","final campaign","feral orks","ork reproduction","colonisation promise","jungle warfare","broken officers","trauma","rivalries","bittersweet","Zulu homage","Lieutenant Carson","Commissar Reeve"}', 'Tired and broken by war, the men of the Brimlock Eleventh face one final battle to win the right to colonise the distant world of Voor and live in peace, standing against a plague of feral orks.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-18')),
  ('P6-18.2', 6, 'Commissar', 'Andy Hoare', 416, 'novel', 1802, NULL, 'medium', 'novel', false, 'sub_item', 'Furia Penitens', NULL, NULL, 'Commissar Flint', NULL, 'Vostroyan 77th Firstborn', 'Astra Militarum', NULL, 'Military SF; Mystery', '{"fast-paced","mysterious","gritty"}', '{"prison planet","uprising","penal hive","disgraced regiment","redemption","Vostroyan Firstborn","new commissar","mutants","psykers","Vostroyan nobility","clan loyalty","heretical experiments"}', 'Deployed to the prison planet Furia Penitens to quell a violent uprising, the disgraced Vostroyan 77th Firstborn and their new commissar must achieve victory and restore their reputation.', 'core', NULL, NULL, false, 'page_count: sourcing thin', (SELECT id FROM public.books WHERE entry_id='P6-18')),
  ('P6-18.3', 6, 'Iron Guard', 'Mark Clapham', 416, 'novel', 1803, NULL, 'medium', 'novel', false, 'sub_item', 'Belmos VII', NULL, NULL, 'Fernand Hool', NULL, 'Mordian 114th Iron Guard', 'Astra Militarum', NULL, 'Horror; Mystery', '{"tense","claustrophobic","horror","mysterious"}', '{"mining world","affliction","corruption","mystery","rebellion","Mordian recruit","night terror","surrounded","hive gang origins","survival","horror","Sergeant Polk"}', 'The 114th Mordian Iron Guard deploy to the mining world of Belmos VII, unaware of a terrible affliction plaguing its populace, and as panic spreads they find themselves surrounded by enemies within and without.', 'core', NULL, NULL, false, 'page_count: sourcing thin', (SELECT id FROM public.books WHERE entry_id='P6-18')),
  ('P6-29.1', 6, '13th Legion', 'Gav Thorpe', 288, 'novel', 2901, NULL, 'high', 'novel', false, 'sub_item', 'Multiple war-zones (climaxes on Coritanorum)', 'Multiple/Galaxy-wide', 'M41 (Second Tyrannic War era)', 'Lieutenant Kage', '{"Colonel Schaeffer"}', '13th Penal Legion (Last Chancers)', 'Astra Militarum', NULL, 'Military SF', '{"grim","brutal","bleak"}', '{"penal legion","Last Chancers","convict soldiers","suicide missions","redemption","Imperial Guard","Colonel Schaeffer","Dirty Dozen","survival","attrition","Tyranids","Coritanorum","first-person memoir","desperation"}', 'Across a hundred war-zones on a dozen worlds, the convict soldiers of the 13th Penal Legion fight a desperate battle for redemption. Against orks, eldar and Chaos, Lieutenant Kage and the Last Chancers fight not to win, but merely to survive.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-29')),
  ('P6-29.2', 6, 'Kill Team', 'Gav Thorpe', 256, 'novel', 2902, NULL, 'high', 'novel', false, 'sub_item', 'T''au Empire space', 'Eastern Fringe', 'M41', 'Lieutenant Kage', '{"Colonel Schaeffer","Inquisitor Oriel"}', '13th Penal Legion (Last Chancers)', 'Astra Militarum', NULL, 'Military SF; Quest/Adventure', '{"brutal","action-packed","intriguing"}', '{"penal legion","Last Chancers","assassination","infiltration","T''au Empire","Inquisition","suicide mission","convict soldiers","Colonel Schaeffer","training montage","prison","alien perspective","redemption","intrigue","Greater Good"}', 'Languishing in an Imperial detention centre, convict soldier Lieutenant Kage is at the end of the line - until Colonel Schaeffer returns with one more assignment: whip a new team of the Guard''s worst into shape to assassinate a warmongering t''au commander.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-29')),
  ('P6-29.3', 6, 'Annihilation Squad', 'Gav Thorpe', 416, 'novel', 2903, NULL, 'high', 'novel', false, 'sub_item', 'Armageddon (Hive Acheron)', 'Segmentum Solar', '998.M41 (Third War for Armageddon)', 'Lieutenant Kage', '{"Colonel Schaeffer","Herman von Strab","Inquisitor Oriel"}', '13th Penal Legion (Last Chancers)', 'Astra Militarum', NULL, 'Military SF; Quest/Adventure', '{"grim","brutal","bleak","intense"}', '{"penal legion","Last Chancers","Third War for Armageddon","assassination","traitor hunt","Orks","Herman von Strab","suicide mission","Colonel Schaeffer","convict soldiers","hive world","redemption","Hive Acheron","finale"}', 'Lieutenant Kage, longest-surviving convict of the 13th Penal Legion, is reacquired by his ruthless Colonel. With a new team of Last Chancers, he is sent to war-torn Armageddon to hunt and assassinate traitor overlord Herman von Strab amid the Third War.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-29')),
  ('P6-29.4', 6, 'Deliverance', 'Gav Thorpe', NULL, 'short', 2904, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Deliverance (death world)', NULL, 'M41', 'Lieutenant Kage', '{"Colonel Schaeffer"}', '13th Penal Legion (Last Chancers)', 'Astra Militarum', NULL, 'Military SF; Horror', '{"grim","tense","brutal"}', '{"penal legion","Last Chancers","Tyranids","convict soldiers","suicide mission","Colonel Schaeffer","survival","desertion","death world","redemption"}', 'A short tale of the Last Chancers: Lieutenant Kage and the convict soldiers of the 13th Penal Legion are thrown against a tyranid swarm, with Kage struggling to keep his desperate comrades from deserting.', 'optional', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-29')),
  ('P6-30.1', 6, 'For the Emperor', 'Sandy Mitchell', 416, 'novel', 3001, NULL, 'high', 'novel', false, 'sub_item', 'Gravalax', 'Ultima Segmentum', '931.M41', 'Commissar Ciaphas Cain', '{"Jurgen","Amberley Vail","Regina Kasteen"}', 'Valhallan 597th', 'Astra Militarum', NULL, 'Military SF; Political Thriller', '{"witty","satirical","humorous","irreverent"}', '{"commissar","Astra Militarum","Valhallan Ice Warriors","T''au Empire","political intrigue","dark comedy","satire","reluctant hero","Inquisition","conspiracy","diplomacy","Gravalax","memoir narration","cowardice","Eastern Fringe"}', 'Commissar Ciaphas Cain - hero of the Imperium, or so the propaganda says - is sent to keep order on Gravalax, an outpost world bordering T''au space. When the alien ambassador is murdered, Cain and his Valhallan regiment are pulled into a conspiracy.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-30')),
  ('P6-30.2', 6, 'Caves of Ice', 'Sandy Mitchell', 256, 'novel', 3002, NULL, 'high', 'novel', false, 'sub_item', 'Simia Orichalcae (ice world)', NULL, '932.M41', 'Commissar Ciaphas Cain', '{"Jurgen","Regina Kasteen","Ruput Broklaw"}', 'Valhallan 597th', 'Astra Militarum', NULL, 'Military SF; Horror', '{"claustrophobic","tense","humorous","creeping dread"}', '{"commissar","Astra Militarum","Valhallan Ice Warriors","ice world","Orks","promethium refinery","underground caves","investigation","dark comedy","reluctant hero","ancient evil","Simia Orichalcae","memoir narration","siege defence","mystery"}', 'On the ice world of Simia Orichalcae, mysterious disappearances unsettle the mine workers and Commissar Cain is nominated to investigate. Unbeknownst to him the planet lies in an ork incursion''s path, and a malevolent evil stirs deep in the ice caves.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-30')),
  ('P6-30.3', 6, 'The Traitor''s Hand', 'Sandy Mitchell', 380, 'novel', 3003, NULL, 'medium', 'novel', false, 'sub_item', 'Adumbria', NULL, '937.M41', 'Commissar Ciaphas Cain', '{"Jurgen","Tomas Beije","Amberley Vail"}', 'Valhallan 597th', 'Astra Militarum', NULL, 'Military SF', '{"witty","humorous","action-packed"}', '{"commissar","Astra Militarum","Valhallan Ice Warriors","Chaos","Slaanesh cult","World Eaters","regimental rivalry","dark comedy","reluctant hero","planetary defence","nemesis","Adumbria","memoir narration","satire","heresy"}', 'An old rival, infighting with fellow Astra Militarum regiments and a cult devoted to Slaanesh derail Commissar Cain''s hopes for a quiet posting. Sent with his Valhallan regiment to defend Adumbria against an approaching Chaos invasion, an easy life proves impossible.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-30')),
  ('P6-30.4', 6, 'Fight or Flight', 'Sandy Mitchell', NULL, 'short', 3004, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Barren mining world (unnamed)', NULL, 'M41 (c. 928.M41)', 'Commissar Ciaphas Cain', '{"Jurgen"}', 'Valhallan 12th Field Artillery', 'Astra Militarum', NULL, 'Military SF', '{"witty","humorous","tense"}', '{"commissar","Astra Militarum","Valhallan","Tyranids","artillery regiment","reluctant hero","dark comedy","origin story","mining world","memoir narration"}', 'In his first recorded exploit, Commissar Cain joins the Valhallan 12th Field Artillery expecting a safe posting far from the front - only to find himself fending off a tyranid invasion on a barren mining world.', 'optional', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-30')),
  ('P6-30.5', 6, 'Echoes of the Tomb', 'Sandy Mitchell', NULL, 'short', 3005, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Interitus Prime (Necron tomb world)', NULL, 'M41', 'Commissar Ciaphas Cain', '{"Jurgen"}', NULL, NULL, NULL, 'Horror; Military SF', '{"tense","dread","humorous"}', '{"commissar","Necrons","tomb world","Adeptus Mechanicus","ancient ruins","horror","reluctant hero","memoir narration","survival","dark comedy"}', 'Commissar Cain recounts the experience that haunts him most: serving as a field adjutant helping Adeptus Mechanicus agents investigate ancient ruins, leading to his first terrifying encounter with the Necrons in their tomb.', 'optional', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-30')),
  ('P6-30.6', 6, 'The Beguiling', 'Sandy Mitchell', NULL, 'short', 3006, NULL, NULL, 'short_story', false, 'sub_item_optional', 'Slawkenberg', NULL, 'M41', 'Commissar Ciaphas Cain', '{"Jurgen","Emeli Duboir"}', 'Valhallan 597th', 'Astra Militarum', NULL, 'Military SF; Horror', '{"witty","humorous","tense"}', '{"commissar","Chaos","Slaanesh cult","temptation","reluctant hero","dark comedy","Valhallans","memoir narration","heresy","Slawkenberg"}', 'On the world of Slawkenberg, Commissar Cain encounters Emeli, a seductive priestess in service to the Chaos god Slaanesh, whose attentions place him in as much danger as any battlefield.', 'optional', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-30')),
  ('P6-31.1', 6, 'Death or Glory', 'Sandy Mitchell', 414, 'novel', 3101, NULL, 'high', 'novel', false, 'sub_item', 'Perlia', NULL, NULL, 'Ciaphas Cain', '{"Jurgen","Amberley Vail"}', 'Valhallan 597th', 'Astra Militarum', NULL, 'Military SF; Quest/Adventure', '{"darkly comic","satirical","action-packed","witty"}', '{"Ciaphas Cain","Astra Militarum","Commissariat","cowardly hero","Ork invasion","Waaagh","behind-enemy-lines","civilian refugee convoy","desert journey","self-preservation","reluctant heroism","reputation","black comedy","survival narrative"}', 'Escaping a disastrous space battle, Commissar Cain and his aide Jurgen crash-land behind Ork lines on besieged Perlia. To survive they must gather scattered troops and desperate civilians and fight their way back to Imperial lines.', 'core', NULL, NULL, false, 'Defender omnibus Book 4 (was missing from my v3.0 extraction)', (SELECT id FROM public.books WHERE entry_id='P6-31')),
  ('P6-31.2', 6, 'Duty Calls', 'Sandy Mitchell', 416, 'novel', 3102, NULL, 'high', 'novel', false, 'sub_item', 'Periremunda', NULL, NULL, 'Ciaphas Cain', '{"Jurgen","Amberley Vail","Lord General Zyvan"}', 'Valhallan 597th', 'Astra Militarum', NULL, 'Military SF; Mystery', '{"darkly comic","tense","conspiratorial","action-packed"}', '{"Ciaphas Cain","Astra Militarum","Commissariat","insurrection","genestealer cult","Tyranid hive fleet","Inquisition","assassination attempts","Sisters of Battle","hidden conspiracy","reluctant heroism","black comedy"}', 'Sent to quell civil unrest on Periremunda, Commissar Cain finds the rebellion masks deeper threats - genestealers heralding a Tyranid hive fleet. Reunited with Inquisitor Amberley Vail, he is drawn into a hunt for a galaxy-changing secret.', 'core', NULL, NULL, false, 'Defender omnibus Book 5 (was missing from my v3.0 extraction)', (SELECT id FROM public.books WHERE entry_id='P6-31')),
  ('P6-31.3', 6, 'Cain''s Last Stand', 'Sandy Mitchell', 410, 'novel', 3103, NULL, 'low', 'novel', false, 'sub_item', 'Perlia', NULL, '999.M41', 'Ciaphas Cain', '{"Jurgen","Amberley Vail"}', 'Schola Progenium commissar-cadets', 'Astra Militarum', NULL, 'War Epic; Military SF', '{"nostalgic","epic","bittersweet","darkly humorous"}', '{"Ciaphas Cain","Astra Militarum","Schola Progenium","commissar cadets","13th Black Crusade","Abaddon the Despoiler","Chaos invasion","ancient xenos artefact","planetary defence","last stand","Eye of Terror","PDF militia"}', 'Semi-retired and teaching commissar-cadets on Perlia, the aged Cain faces a Chaos splinter fleet from Abaddon''s 13th Black Crusade bound for the planet to seize an ancient relic he has encountered before.', 'core', NULL, NULL, false, 'Defender omnibus Book 6 (P6-31.3); P6-31.1 Death or Glory + .2 Duty Calls noch anzureichern (next batch)', (SELECT id FROM public.books WHERE entry_id='P6-31')),
  ('P6-32.1', 6, 'The Emperor''s Finest', 'Sandy Mitchell', 406, 'novel', 3201, NULL, 'high', 'novel', false, 'sub_item', 'Viridia System', NULL, 'late 928.M41', 'Ciaphas Cain', '{"Jurgen","Amberley Vail"}', NULL, NULL, NULL, 'Military SF; Quest/Adventure', '{"comedic","action-packed","satirical"}', '{"Ciaphas Cain","Astra Militarum","Commissariat","Space Marines","Reclaimers Chapter","genestealer hybrids","space hulk","orks","tyranids","insurrection","unreliable narrator","dark comedy","xenos cult","Adeptus Astartes liaison"}', 'Attached as commissarial liaison to the Reclaimers Space Marines, Cain is drawn into suppressing a rebellion masking genestealer hybrids, then onto a drifting space hulk, while dodging a governor''s husband-hunting daughter.', 'core', NULL, NULL, false, 'REMAP: delivered as P6-31.1 (Defender); correct omnibus is Saviour -> P6-32.1 (TV Tropes+Amazon verified)', (SELECT id FROM public.books WHERE entry_id='P6-32')),
  ('P6-32.2', 6, 'The Last Ditch', 'Sandy Mitchell', 315, 'novel', 3202, NULL, 'medium', 'novel', false, 'sub_item', 'Nusquam Fundumentibus', NULL, '942.M41', 'Ciaphas Cain', '{"Jurgen","Amberley Vail","Jenit Sulla","Regina Kasteen"}', 'Valhallan 597th', 'Astra Militarum', NULL, 'Military SF; Horror', '{"darkly comedic","tense","cynical","action-packed"}', '{"Ciaphas Cain","Astra Militarum","Valhallan 597th","Valhallan Ice Warriors","ice world","orks","ancient buried threat","warp daemon incursion","ship crash","commissar mentor","Jenit Sulla","survival","grimdark satire"}', 'Returning to frozen Nusquam Fundumentibus to crush ork raids, Cain''s crashing ship disturbs a far greater enemy long dormant beneath the permafrost, forcing him to rally his Valhallans and a zealous novice commissar.', 'core', NULL, NULL, false, 'REMAP: delivered as P6-31.2 -> P6-32.2 (Saviour)', (SELECT id FROM public.books WHERE entry_id='P6-32')),
  ('P6-32.3', 6, 'The Greater Good', 'Sandy Mitchell', 416, 'novel', 3203, NULL, 'high', 'novel', false, 'sub_item', 'Quadravidia', NULL, '992.M41', 'Ciaphas Cain', '{"Jurgen","Amberley Vail"}', 'Valhallan 597th', 'Astra Militarum', NULL, 'Military SF; Political Thriller', '{"satirical","comedic","tense"}', '{"Ciaphas Cain","Astra Militarum","Valhallan 597th","T''au Empire","tau battlesuits","tyranids","hive fleet","uneasy alliance","diplomacy","xenos politics","the Greater Good","satire"}', 'When the tau attack Quadravidia, Cain is sent to advise the defence; an unexpected ceasefire arrives as a tyranid hive fleet nears, forcing him to broker an uneasy Imperium-tau alliance against the greater threat.', 'core', NULL, NULL, false, 'REMAP: delivered as P6-32.2 -> P6-32.3 (Saviour)', (SELECT id FROM public.books WHERE entry_id='P6-32')),
  ('P6-32.4', 6, 'Old Soldiers Never Die', 'Sandy Mitchell', NULL, 'novel', 3204, NULL, 'pending', 'novella', false, 'sub_item', 'Lentonia', NULL, '938.M41', 'Ciaphas Cain', '{"Jurgen","Amberley Vail"}', 'Valhallan 597th', 'Astra Militarum', NULL, 'Horror; Military SF', '{"darkly comedic","horror-tinged","fast-paced"}', '{"Ciaphas Cain","Astra Militarum","Valhallan 597th","zombie plague","warp-tainted infection","undead","Chaos curse","insurrection aftermath","novella","survival horror","dark comedy","Lentonia"}', 'Policing the aftermath of an insurrection on Lentonia, Cain and the Valhallan 597th confront a warp-tainted plague that kills its victims and raises them as flesh-eating zombies, racing to find the source and a cure.', 'core', NULL, NULL, false, 'REMAP: delivered as P6-32.1 -> P6-32.4 (Saviour novella, not lead novel)', (SELECT id FROM public.books WHERE entry_id='P6-32')),
  ('P6-32.5', 6, 'A Mug of Recaff', 'Sandy Mitchell', NULL, 'short', 3205, NULL, NULL, 'short_story', false, 'sub_item_optional', NULL, NULL, NULL, 'Ciaphas Cain', '{"Amberley Vail"}', NULL, NULL, NULL, 'Character Study', '{"comedic","satirical"}', '{"Ciaphas Cain","Astra Militarum","Commissariat","dark comedy","short story","Cain Archive"}', 'A short Cain Archive story collected in the Saviour of the Imperium omnibus.', 'optional', NULL, NULL, false, 'membership verified TV Tropes (Saviour shorts)', (SELECT id FROM public.books WHERE entry_id='P6-32')),
  ('P6-32.6', 6, 'The Smallest Detail', 'Sandy Mitchell', NULL, 'short', 3206, NULL, NULL, 'short_story', false, 'sub_item_optional', NULL, NULL, NULL, 'Ciaphas Cain', '{"Amberley Vail"}', NULL, NULL, NULL, 'Character Study', '{"comedic","satirical"}', '{"Ciaphas Cain","Astra Militarum","Commissariat","dark comedy","short story","Cain Archive"}', 'A short Cain Archive story collected in the Saviour of the Imperium omnibus.', 'optional', NULL, NULL, false, 'membership verified TV Tropes', (SELECT id FROM public.books WHERE entry_id='P6-32')),
  ('P6-32.7', 6, 'The Little Things', 'Sandy Mitchell', NULL, 'short', 3207, NULL, NULL, 'short_story', false, 'sub_item_optional', NULL, NULL, NULL, 'Ciaphas Cain', '{"Amberley Vail"}', NULL, NULL, NULL, 'Character Study', '{"comedic","satirical"}', '{"Ciaphas Cain","Astra Militarum","Commissariat","dark comedy","short story","Cain Archive"}', 'A short Cain Archive story collected in the Saviour of the Imperium omnibus.', 'optional', NULL, NULL, false, 'membership verified TV Tropes', (SELECT id FROM public.books WHERE entry_id='P6-32')),
  ('P6-37.1', 6, 'Crossfire', 'Matthew Farrer', 288, 'novel', 3701, NULL, 'medium', 'novel', false, 'sub_item', 'Hydraphur', 'Segmentum Pacificus', 'M41', 'Shira Calpurnia Lucina', '{"Magos Sanja","Arbitor Dvorov"}', 'UNKNOWN (Adeptus Arbites)', 'Adeptus Arbites', NULL, 'Mystery; Political Thriller', '{"noir","investigative","grim","immersive"}', '{"Adeptus Arbites","Shira Calpurnia","Hydraphur","Imperial Navy fortress-system","assassination plot","religious festival","Ecclesiarchy","Adepta Sororitas","noble houses","corruption","detective investigation","Lex Imperia"}', 'Newly assigned to the warfleet fortress-system of Hydraphur, Adeptus Arbites officer Shira Calpurnia survives an assassination attempt and must investigate a conspiracy threatening a major religious festival amid the corruption of the planet''s elite.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-37')),
  ('P6-37.2', 6, 'Legacy', 'Matthew Farrer', 256, 'novel', 3702, NULL, 'high', 'novel', false, 'sub_item', 'Hydraphur', 'Segmentum Pacificus', 'M41', 'Shira Calpurnia Lucina', '{"Culann","Magos Sanja"}', 'UNKNOWN (Adeptus Arbites)', 'Adeptus Arbites', NULL, 'Political Thriller; Mystery', '{"political","intriguing","slow-burn"}', '{"Adeptus Arbites","Shira Calpurnia","Hydraphur","Rogue Trader charter","succession dispute","relic","Ecclesiarchy","Adeptus Mechanicus","legal arbitration","political intrigue","conspiracy"}', 'Calpurnia is charged with overseeing the lawful succession of a dead Rogue Trader''s ancient, Emperor-signed charter on Hydraphur, but rival heirs, scheming clerics and a contested counter-claim turn the ceremony into a deadly struggle.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-37')),
  ('P6-37.3', 6, 'Blind', 'Matthew Farrer', 256, 'novel', 3703, NULL, 'medium', 'novel', false, 'sub_item', 'Bastion Psykana (Hydraphur System)', 'Segmentum Pacificus', 'M41', 'Shira Calpurnia Lucina', NULL, 'UNKNOWN (Adeptus Arbites)', 'Adeptus Arbites', NULL, 'Mystery; Horror', '{"claustrophobic","dark","introspective","mysterious"}', '{"Adeptus Arbites","Shira Calpurnia","Bastion Psykana","astropaths","Adeptus Astra Telepathica","psykers","locked-room murder","deep-space station","redemption","murder mystery"}', 'Disgraced and self-doubting, Calpurnia is given a last chance to redeem herself by solving the locked-room murder of the master of the Bastion Psykana, a deep-space astropathic tower full of half-mad, hostile telepaths.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-37')),
  ('P6-43.1', 6, 'Deathwatch', 'Steve Parker', 416, 'novel', 4301, NULL, 'high', 'novel', false, 'sub_item', '31-Caro (mining world)', NULL, NULL, 'Lyandro Karras', '{"Siefer Zeed","Ignacio Solarion","Darrion Rauth","Inquisitor Sigma"}', 'Deathwatch, Talon Squad', 'Adeptus Astartes (Deathwatch)', NULL, 'Military SF; Horror', '{"grimdark","tense","brooding","action-packed"}', '{"Deathwatch","kill-team","xenos hunters","Librarian psyker","Inquisition handler","genestealer infestation","Watch Fortress training","special forces","multi-Chapter brotherhood","Ordo Xenos","origin story","Dreadnought","Death Spectres"}', 'Drawn from many Chapters, Talon Squad are forged into a Deathwatch kill-team under the mysterious Inquisitor Sigma. Led by Death Spectres Librarian Karras, their first mission pits them against a genestealer infestation threatening a whole world.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-43')),
  ('P6-43.2', 6, 'Storm of Damocles', 'Justin D. Hill', 246, 'novel', 4302, NULL, 'medium', 'novel', false, 'sub_item', 'Damocles Gulf', 'Eastern Fringe', NULL, 'Nergui', NULL, 'Deathwatch (White Scars-born)', 'Adeptus Astartes (Deathwatch)', NULL, 'Military SF', '{"tense","honour-bound","contemplative","martial"}', '{"Deathwatch","Tau Empire","Damocles Gulf war","Stormsurge","White Scars","kill-team","Chapter versus Deathwatch loyalty","xenos weapon","brotherhood","bikes","Eastern Fringe","alien diplomacy"}', 'As war rages in the Damocles Gulf between Imperium and Tau, a Deathwatch kill-team uncovers a deadly new tau weapon - the Stormsurge. To destroy it, Captain Nergui must call on his former White Scars brothers, straining the bonds of brotherhood.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-43')),
  ('P6-43.3', 6, 'Deathwatch: Kryptman''s War', 'Ian St Martin', NULL, 'novel', 4303, NULL, 'pending', 'novel', false, 'sub_item', 'Kurbynola System', 'Ultima Segmentum', '997.M41', 'Watch Captain Artemis', NULL, 'Deathwatch, Watch Fortress Talasa Prime', 'Adeptus Astartes (Deathwatch)', NULL, 'Military SF; War Epic', '{"grim","relentless","bleak","dutiful"}', '{"Deathwatch","Watch Captain","Mortifactors","Octarius War","Hive Fleet Leviathan","Tyranids","Orks","xenos versus xenos","Inquisitor Kryptman gambit","duty","sacrifice","Talasa Prime","kill-team"}', 'Amid the Octarius War, as Hive Fleet Leviathan collides with the Orks, Watch Captain Artemis leads the Deathwatch into battle against untold billions - a war that tests the true meaning of duty and the price of preserving the Imperium.', 'core', NULL, NULL, false, 'P6-43.3 verified = Kryptman''s War (Ian St Martin); omnibus has 3 novels + ~14 optional shorts (separate enrichment at phase end)', (SELECT id FROM public.books WHERE entry_id='P6-43')),
  ('P6-44.1', 6, 'Space Wolf', 'William King', 288, 'novel', 4401, NULL, 'medium', 'novel', false, 'sub_item', 'Fenris', 'Segmentum Obscurus', 'M41', 'Ragnar', '{"Strybjorn Grimskull","Sven","Ranek"}', 'Space Wolves (Blood Claws)', 'Adeptus Astartes', NULL, 'Military SF; Character Study', '{"savage","heroic","coming-of-age","vivid"}', '{"Space Wolves","Fenris","death world","recruitment","rite of passage","Test of Morkai","Blood Claws","tribal culture","Space Viking","rivalry and vengeance","Thousand Sons","Tzeentch","coming of age","gene-seed transformation"}', 'On the death world Fenris, young tribesman Ragnar is mortally wounded and recruited by the Space Wolves. Alongside Strybjorn - the rival who slew his kin - he endures brutal training and transformation into a Space Marine as Chaos stirs.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-44')),
  ('P6-44.2', 6, 'Ragnar''s Claw', 'William King', 288, 'novel', 4402, NULL, 'medium', 'novel', false, 'sub_item', 'Aerius', NULL, 'M41', 'Ragnar Blackmane', '{"Strybjorn Grimskull","Sven","Inquisitor Sternberg"}', 'Space Wolves (Blood Claws)', 'Adeptus Astartes', NULL, 'Military SF; Quest/Adventure', '{"adventurous","savage","mystical"}', '{"Space Wolves","Blood Claws","Inquisition","eldar artefact","Talisman of Lykos","plague","quest","Nurgle daemons","Ork Waaagh","relic recovery","psyker apprentice","Space Viking","off-world mission"}', 'As a Blood Claw, Ragnar joins his pack escorting Inquisitor Sternberg on a quest to recover an ancient eldar talisman said to cure a deadly plague ravaging the world of Aerius, facing Chaos, Orks and daemons along the way.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-44')),
  ('P6-44.3', 6, 'Grey Hunter', 'William King', 282, 'novel', 4403, NULL, 'medium', 'novel', false, 'sub_item', 'Garm', NULL, 'M41', 'Ragnar Blackmane', '{"Strybjorn Grimskull","Sven","Logan Grimnar"}', 'Space Wolves', 'Adeptus Astartes', NULL, 'Military SF; Quest/Adventure', '{"action-packed","grim","vengeful","epic"}', '{"Space Wolves","Spear of Russ","sacred relic","Garm","Chaos uprising","Thousand Sons","warp portal","industrial wasteland","prophecy","boarding action","relic recovery","Blood Claw to Grey Hunter"}', 'When the Spear of Russ, a relic wielded by Leman Russ himself, is stolen, the Space Wolves march on the world of Garm to reclaim it. Ambushed by Chaos, Ragnar''s brothers learn an ancient enemy is prophesied to be reborn.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-44')),
  ('P6-46.1', 6, 'Blood of Asaheim', 'Chris Wraight', 320, 'novel', 4601, NULL, 'medium', 'novel', false, 'sub_item', 'Ras Shakeh (shrine world)', NULL, 'Late M41', 'Ingvar', '{"Gunnlaugur","Olgeir","Jorundur","Baldr"}', 'Space Wolves, Jarnhamar Pack', 'Adeptus Astartes', NULL, 'Military SF; Character Study', '{"dour","brooding","tense","grim"}', '{"Space Wolves","Jarnhamar Pack","Grey Hunters","Deathwatch veteran returning","shrine world","Death Guard","Nurgle plague","Sisters of Battle","pack dynamics","brotherhood and rivalry","leadership","Ras Shakeh","siege defence","identity"}', 'After half a century in the Deathwatch, Wolf Guard Ingvar returns to Fenris and his old pack, Jarnhamar. Sent to defend a shrine world against the plague-ridden Death Guard, the Wolves clash with wary Sisters of Battle as old tensions resurface.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-46')),
  ('P6-46.2', 6, 'Stormcaller', 'Chris Wraight', 416, 'novel', 4602, NULL, 'high', 'novel', false, 'sub_item', 'Ras Shakeh (shrine world)', NULL, 'Late M41 (around the 13th Black Crusade)', 'Ingvar', '{"Gunnlaugur","Njal Stormcaller","Baldr"}', 'Space Wolves, Jarnhamar Pack', 'Adeptus Astartes', NULL, 'Military SF; Horror', '{"grim","foreboding","embattled","bleak"}', '{"Space Wolves","Jarnhamar Pack","Njal Stormcaller","Rune Priest","psyker","Ras Shakeh","Nurgle corruption","Death Guard","space hulk","Ecclesiarchy","hidden secret","pack tensions","plague war"}', 'As the plague-wracked world of Ras Shakeh spirals out of control, Rune Priest Njal Stormcaller arrives to reinforce the embattled Jarnhamar pack. The Ecclesiarchy descends in force, uncovering a sinister secret that threatens the Imperium itself.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-46')),
  ('P6-46.3', 6, 'The Helwinter Gate', 'Chris Wraight', 384, 'novel', 4603, NULL, 'medium', 'novel', false, 'sub_item', 'Mobile/voidship (climax on Cadia)', 'Mobile/Fleet', '999.M41 (13th Black Crusade / fall of Cadia)', 'Ingvar', '{"Gunnlaugur","Baldr","Jorundur"}', 'Space Wolves, Jarnhamar Pack', 'Adeptus Astartes', NULL, 'Military SF; Quest/Adventure', '{"bleak","embittered","isolated","brooding"}', '{"Space Wolves","Jarnhamar Pack","exile","stolen voidship","hunt for an enemy","ancient betrayal","13th Black Crusade","Dark Imperium","Cadia","brotherhood","vengeance","isolation","Archenemy"}', 'Isolated and fleeing their own Chapter''s judgement aboard a stolen voidship, Jarnhamar pack hunt a hidden enemy through ruined worlds as the Imperium descends into total war, racing to uncover the truth of an ancient betrayal.', 'core', NULL, NULL, false, 'page_count: editions 384/421/432', (SELECT id FROM public.books WHERE entry_id='P6-46')),
  ('P6-46.4', 6, 'Kraken', 'Chris Wraight', NULL, 'short', 4604, NULL, NULL, 'short_story', false, 'sub_item_optional', NULL, NULL, NULL, NULL, NULL, 'Space Wolves, Jarnhamar Pack', 'Adeptus Astartes', NULL, 'Military SF', '{"saga-like"}', '{"Space Wolves","Jarnhamar Pack","short story","omnibus inclusion"}', 'A Space Wolves short story featuring Jarnhamar pack, collected in the Legends of the Wolf omnibus alongside the Blood of Asaheim trilogy.', 'optional', NULL, NULL, false, 'Kraken short verified via Lexicanum (Chris Wraight, March 2012)', (SELECT id FROM public.books WHERE entry_id='P6-46')),
  ('P6-53.1', 6, 'Helsreach', 'Aaron Dembski-Bowden', 416, 'novel', 5301, NULL, 'medium', 'novel', false, 'sub_item', 'Hive Helsreach, Armageddon', 'Segmentum Solar', '998.M41 (Third War for Armageddon)', 'Reclusiarch Merek Grimaldus', '{"Andrej"}', 'Black Templars (Sword Brethren)', 'Adeptus Astartes', NULL, 'Military SF; War Epic', '{"grimdark","heroic","desperate","action-packed"}', '{"Black Templars","orks","Ghazghkull","siege","last stand","hive city","Third War for Armageddon","Armageddon Steel Legion","Titan Legions","Legio Invigilata","Chaplain","faith","martyrdom","Ordinatus"}', 'When orks invade Armageddon, Chaplain Grimaldus and a force of 100 Black Templars are charged with defending Hive Helsreach. As ork numbers swell and the Space Marines dwindle, Grimaldus faces a desperate last stand.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-53')),
  ('P6-53.2', 6, 'Blood and Fire', 'Aaron Dembski-Bowden', NULL, 'novel', 5302, NULL, 'pending', 'novella', false, 'sub_item', 'Armageddon (Hive Volcanus/Mannheim Gap)', 'Segmentum Solar', '998.M41 (Third War for Armageddon)', 'Reclusiarch Merek Grimaldus', '{"Cyneric","Ekene Dubaku","Andrej"}', 'Black Templars', 'Adeptus Astartes', NULL, 'Military SF; Character Study', '{"character-driven","sombre","vengeful","intense"}', '{"novella","Black Templars","Celestial Lions","Inquisition","Armageddon","orks","brotherhood","honour","vengeance","Chaplain mentorship","Imperial Fists lineage"}', 'In the aftermath of the war for Hive Helsreach, Chaplain Grimaldus receives a distress call from an old ally - the Celestial Lions, reduced to survivors targeted by the Inquisition. Grimaldus must decide their fate.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-53')),
  ('P6-53.3', 6, 'The Eternal Crusader', 'Guy Haley', NULL, 'novel', 5303, NULL, 'pending', 'novella', false, 'sub_item', 'Armageddon system (battle barge Eternal Crusader)', 'Segmentum Solar', '998.M41 (Third War for Armageddon)', 'High Marshal Helbrecht', '{"Ghazghkull Thraka","Grimaldus"}', 'Black Templars', 'Adeptus Astartes', NULL, 'Military SF; War Epic', '{"bombastic","grand","martial","brisk"}', '{"novella","Black Templars","High Marshal","battle barge","void warfare","orks","Ghazghkull","Armageddon","crusade","Ghoul Stars","leadership","Third War for Armageddon"}', 'Fresh from the Ghoul Stars Crusade, High Marshal Helbrecht gathers his Black Templars and sets out for Armageddon, where Ghazghkull''s second invasion is under way. Given command of the void war, he prepares to bring battle to the greenskins.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-53')),
  ('P6-53.4', 6, 'Angron''s Monolith', 'Steve Lyons', NULL, 'novel', 5304, NULL, 'pending', 'novella', false, 'sub_item', 'Armageddon (equatorial jungles)', 'Segmentum Solar', '998.M41 (Third War for Armageddon)', NULL, NULL, 'Relictors', 'Adeptus Astartes', NULL, 'Quest/Adventure; Military SF', '{"mysterious","grim","dark"}', '{"novella","Relictors","Armageddon","orks","feral orks","jungle warfare","relic hunt","Chaos artefact","Angron","traitor primarch","edge of heresy","mystery"}', 'As war engulfs Armageddon, the mistrusted Relictors Chapter deploys to the equatorial jungles. Battling feral orks, they scour the jungle for lost battle-brothers sent to recover an ancient relic linked to the traitor primarch Angron.', 'core', NULL, NULL, false, 'author Steve Lyons verified (Lexicanum omnibus contents)', (SELECT id FROM public.books WHERE entry_id='P6-53')),
  ('P6-53.5', 6, 'Dante''s Canyon', 'Josh Reynolds', NULL, 'novel', 5305, NULL, 'pending', 'novella', false, 'sub_item', 'Armageddon (wastes; promethium refinery)', 'Segmentum Solar', '998.M41 (Third War for Armageddon)', 'Stormseer Kanim', NULL, 'White Scars', 'Adeptus Astartes', NULL, 'Military SF', '{"fast-paced","action-packed","tense"}', '{"novella","White Scars","Stormseer","orks","Armageddon","ambush","promethium refinery","destiny","psyker","Chogoris","fast attack"}', 'In the wastes of Armageddon, a White Scars strike force baits the orks into a deadly trap at a promethium refinery. But one son of Chogoris has a great destiny, and Stormseer Kanim must keep him alive whatever the cost.', 'core', NULL, NULL, false, 'author Josh Reynolds verified (Lexicanum omnibus contents)', (SELECT id FROM public.books WHERE entry_id='P6-53')),
  ('P6-54.1', 6, 'Stormseer', 'David Annandale', NULL, 'novel', 5401, NULL, 'pending', 'novella', false, 'sub_item', 'Lepidus Prime (Octarius system)', 'Ultima Segmentum', NULL, 'Stormseer Ghazan', '{"Temur Khan"}', 'White Scars, Fifth Brotherhood', 'Adeptus Astartes', NULL, 'Military SF; Mystery', '{"fast and furious","action-packed","mystical"}', '{"novella","White Scars","Stormseer","zadyin arga","orks","Overfiend","Octarius","eldar","Saim-Hann","psyker","visions","Mordian Iron Guard","bikes","super-weapon","mystery"}', 'The hordes of the Overfiend of Octarius plague the Imperium. Temur Khan''s White Scars descend on Lepidus Prime to cleanse it, striking hard and fast - but when the orks reveal a super-weapon, a lone Stormseer investigates behind enemy lines.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-54')),
  ('P6-54.2', 6, 'Shadow Captain', 'David Annandale', NULL, 'novel', 5402, NULL, 'pending', 'novella', false, 'sub_item', 'Lepidus Prime (city of Reclamation, Octarius)', 'Ultima Segmentum', NULL, 'Shadow Captain Krevaan', '{"Techmarine Thaene"}', 'Raven Guard', 'Adeptus Astartes', NULL, 'Military SF; Mystery', '{"tense","suspicious","action-driven"}', '{"novella","Raven Guard","Shadow Captain","orks","Overfiend","Octarius","eldar alliance","Saim-Hann","shadow tactics","Techmarine","hidden agenda","Lepidus Prime"}', 'On Lepidus Prime the beleaguered Imperial forces gain an unlikely ally - the eldar of Craftworld Saim-Hann. Shadow Captain Krevaan of the Raven Guard forges a fragile alliance to stop the orks before the city of Reclamation falls, while suspecting a sinister eldar motive.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-54')),
  ('P6-54.3', 6, 'Forge Master', 'David Annandale', NULL, 'novel', 5403, NULL, 'pending', 'novella', false, 'sub_item', 'Ork flagship (void), Octarius system', 'Ultima Segmentum', NULL, 'Techmarine Ha''garen', '{"Captain Mulcebar","Ba''birin","Neleus"}', 'Salamanders, 5th Company', 'Adeptus Astartes', NULL, 'Military SF; Character Study', '{"intense","fiery","action-packed","introspective"}', '{"novella","Salamanders","Techmarine","Adeptus Mechanicus","orks","Overfiend","Octarius","boarding action","ork flagship","alien prisoner","eldar","flesh vs machine","Nocturne","identity"}', 'As the war against the orks of Octarius grinds on, the Salamanders'' Fifth Company is tasked with killing the Overfiend himself. Boarding the greenskin flagship, they discover a dangerous alien prisoner who may hold the key to ending the conflict.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-54')),
  ('P6-56.1', 6, 'Faith & Fire', 'James Swallow', 416, 'novel', 5601, NULL, 'high', 'novel', false, 'sub_item', 'Neva', NULL, NULL, 'Sister Miriya', '{"Sister Verity","Torris Vaun","Lethe"}', 'Adepta Sororitas, Order of Our Martyred Lady', 'Adepta Sororitas', NULL, 'Mystery; Military SF', '{"zealous","intense","fanatical","action-driven"}', '{"Adepta Sororitas","Sisters of Battle","Order of Our Martyred Lady","Ecclesiarchy","psyker","heretic","manhunt","faith","Seraphim","Sisters Repentia","Hospitaller","conspiracy","witch-hunting","Celestian"}', 'When the dangerous psychic heretic Torris Vaun escapes her custody, Celestian Miriya of the Order of Our Martyred Lady is disgraced. To regain her honour she pursues Vaun to the planet Neva with Sister Verity, uncovering a plot that threatens the Imperium.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-56')),
  ('P6-56.2', 6, 'Hammer & Anvil', 'James Swallow', 410, 'novel', 5602, NULL, 'high', 'novel', false, 'sub_item', 'Sanctuary 101 (desolate world)', NULL, 'Reconsecration 909.M41', 'Sister Miriya', '{"Sister Verity","Canoness Sepherina","Sister Decima"}', 'Adepta Sororitas, Order of Our Martyred Lady', 'Adepta Sororitas', NULL, 'Military SF; Horror', '{"grim","besieged","relentless","ominous"}', '{"Adepta Sororitas","Order of Our Martyred Lady","Necrons","Sautekh Dynasty","Sanctuary 101","siege","reconsecration","xenos horror","relic","Adeptus Mechanicus","faith","last stand","Saint Katherine","tomb world"}', 'A mission of the Sisterhood returns to the desolate Sanctuary 101 - annihilated by the Necrons - to reconsecrate an Ecclesiarchy outpost. But the soulless xenos still lurk in the darkness, guarding a secret, and a vicious battle erupts.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-56')),
  ('P6-56.3', 6, 'Red & Black', 'James Swallow', NULL, 'novel', 5603, NULL, 'pending', 'novel', false, 'sub_item', 'Hollos', NULL, NULL, 'Celestian Miriya', '{"Lethe","Adept Nolan","Rho"}', 'Adepta Sororitas, Order of Our Martyred Lady', 'Adepta Sororitas', NULL, 'Mystery; Military SF', '{"thought-provoking","morally complex","tense"}', '{"Adepta Sororitas","Order of Our Martyred Lady","Ecclesiarchy","Imperial faith","Hollos","Replicae","clones","warp storms","judgement","free will","non-human believers"}', 'After two millennia of warp storms abate, the isolated world of Hollos reconnects with the Imperium. Celestian Miriya is sent to pass judgement - will she find a world embracing the Emperor''s truth, or one in need of cleansing?', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P6-56')),
  ('P6-56.4', 6, 'Heart & Soul', 'James Swallow', NULL, 'short', 5604, NULL, 'pending', 'short_story', false, 'sub_item', 'Meseda Quintus (rebel world)', NULL, NULL, 'Sister Miriya', '{"Sister Verity","the Iconoclast"}', 'Adepta Sororitas, Order of Our Martyred Lady', 'Adepta Sororitas', NULL, 'Political Thriller; Military SF', '{"tense","dark","morally fraught"}', '{"short story","Adepta Sororitas","Order of Our Martyred Lady","Ecclesiarchy","rebellion","internecine politics","traitor","Iconoclast","execution","inter-order conflict","faith","heresy"}', 'On the war-ravaged rebel world of Meseda Quintus, Sister Miriya is relieved the Army of the Iconoclast has been defeated, with only the arch-traitor''s execution left. But the arrival of Sisters from another order throws everything into doubt.', 'core', NULL, NULL, false, 'format: Heart & Soul is a short story (omnibus closer); kept as tracked sub_item per Sisters omnibus completeness', (SELECT id FROM public.books WHERE entry_id='P6-56')),
  ('P7-01.1', 7, 'Belisarius Cawl: The Great Work', 'Guy Haley', 416, 'novel', 101, NULL, 'high', 'novel', false, 'sub_item', 'Sotha', 'Ultima Segmentum', 'Era Indomitus (after the Great Rift)', 'Belisarius Cawl', '{"Tetrarch Decimus Felix","Alpha Primus","Chapter Master Thracian"}', 'Adeptus Mechanicus', 'Adeptus Mechanicus', NULL, 'Mystery; Quest/Adventure', '{"cerebral","mysterious","lore-rich","melancholic"}', '{"Adeptus Mechanicus","archmagos","tech-priest","Pharos beacon","archeotech","Necron technology","Great Rift","Tyranids","Scythes of the Emperor","Ultramarines","Primaris Space Marines","dead world","ancient secrets","multiple timelines","Sotha","xenos artefact"}', 'In the wake of the Great Rift, Archmagos Belisarius Cawl travels to the dead world of Sotha, once home to the Scythes of the Emperor, seeking a lynchpin of his Great Work hidden amid Tyranid-ravaged ruins and an ancient evil.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P7-01')),
  ('P7-01.2', 7, 'Genefather', 'Guy Haley', 352, 'novel', 102, NULL, 'high', 'novel', false, 'sub_item', 'Pontus Avernes (artificial world)', 'Ultima Segmentum', 'M42 (Era Indomitus)', 'Belisarius Cawl', '{"Fabius Bile","Friedrich Qvo-89","Alpha Primus"}', 'Adeptus Mechanicus', 'Adeptus Mechanicus', NULL, 'Character Study; Mystery', '{"witty","cerebral","character-driven","tense"}', '{"Adeptus Mechanicus","archmagos","tech-priest","Fabius Bile","clash of intellects","pylon network","Great Rift","the Warp","genecraft","New Men","Necron pylons","humanity''s survival","ego","rivalry","symposium","Chaos Space Marines"}', 'Hoping to tame the Great Rift, Archmagos Belisarius Cawl invites the Imperium''s great minds to the artificial world of Pontus Avernes to unlock the secrets of the pylon network - but an uninvited guest, Fabius Bile, arrives with his own agenda.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P7-01')),
  ('P7-01.3', 7, 'Belisarius Cawl: Archmagos', 'Guy Haley', 384, 'novel', 103, NULL, 'medium', 'novel', false, 'sub_item', 'Necron tomb world (black hole event horizon)', NULL, 'Era Indomitus (Great Rift era)', 'Belisarius Cawl', '{"Solana","Friedrich Qvo-89","Alpha Primus","Vashtorr the Arkifane"}', 'Adeptus Mechanicus', 'Adeptus Mechanicus', NULL, 'Quest/Adventure; Mystery', '{"adventurous","cerebral","ominous","witty"}', '{"Adeptus Mechanicus","archmagos","tech-priest","Necrons","tomb world","black hole","Attilan Gap","Great Rift","Vashtorr the Arkifane","Dark Mechanicum","archeotech","dungeon-crawl","Imperium Nihilus","quest"}', 'To open the Attilan Gap and bridge the Great Rift, Cawl must retrieve control codes from an ancient necron world trapped on a black hole''s event horizon, recruiting aid from across the Adeptus Mechanicus - while drawing the attention of Vashtorr the Arkifane.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P7-01')),
  ('P7-03.1', 7, 'Bequin: Pariah', 'Dan Abnett', 336, 'novel', 301, NULL, 'medium', 'novel', false, 'sub_item', 'Queen Mab, Sancour', 'Segmentum Obscurus', 'ca. 500.M41', 'Alizebeth Bequin', '{"Gregor Eisenhorn","Gideon Ravenor","the Cognitae"}', 'Inquisition', 'Inquisition', NULL, 'Mystery; Political Thriller', '{"dark","enigmatic","gothic","suspenseful"}', '{"Inquisition","pariah","blank","Alizebeth Bequin","Eisenhorn","Ravenor","Cognitae","Queen Mab","Sancour","Scarus Sector","espionage","shadow game","Archenemy","identity mystery","covert operations","psychic blanks"}', 'In the city of Queen Mab, the pariah and Inquisitorial agent Alizebeth Bequin - an enigma even to herself - is caught between former allies turned enemies, Inquisitors Eisenhorn and Ravenor, and embroiled in a dark plot she does not understand.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P7-03')),
  ('P7-03.2', 7, 'Bequin: Penitent', 'Dan Abnett', 336, 'novel', 302, NULL, 'high', 'novel', false, 'sub_item', 'Queen Mab, Sancour', 'Segmentum Obscurus', 'ca. 500.M41', 'Alizebeth Bequin', '{"Gregor Eisenhorn","Gideon Ravenor","the Cognitae"}', 'Inquisition', 'Inquisition', NULL, 'Mystery; Horror', '{"macabre","eerie","intrigue-laden","unsettling"}', '{"Inquisition","pariah","blank","Alizebeth Bequin","Eisenhorn","Ravenor","Cognitae","King in Yellow","Queen Mab","Sancour","Scarus Sector","esoteric mystery","daemons","Traitor Legions","puzzle","identity","gothic horror"}', 'In the mysterious city of Queen Mab, agents of the Inquisition and the shadowy Cognitae struggle to uncover the encrypted identity of the all-powerful King in Yellow, with the pariah Alizebeth Bequin caught at the heart of the conflict.', 'core', NULL, NULL, false, NULL, (SELECT id FROM public.books WHERE entry_id='P7-03')),
  ('P7-07.1', 7, 'The Reverie', 'Peter Fehervari', 349, 'novel', 701, NULL, 'high', 'novel', false, 'sub_item', 'Malpertuis (Kanvolis)', NULL, NULL, NULL, '{"Varzival Czervantes","Marisol","Tarsem"}', 'Angels Resplendent (Blood Angels successor)', 'Adeptus Astartes', NULL, 'Horror; Character Study', '{"eerie","dreamlike","insidious","unsettling"}', '{"Space Marines","Blood Angels successor","Chapter secrets","artistic enlightenment","psychological horror","pilgrimage","corruption","Warhammer Horror","ensemble POV","faith","hidden darkness","the Dark Coil"}', 'Three travellers - a haunted Knight Exemplar, an aging poet-Muse, and an idealistic scholar - are drawn to the radiant world of Malpertuis, where behind the Angels Resplendent''s artistic enlightenment an insidious darkness gathers.', 'core', NULL, NULL, false, 'Dark Coil omnibus component', (SELECT id FROM public.books WHERE entry_id='P7-07')),
  ('P7-07.2', 7, 'Requiem Infernal', 'Peter Fehervari', 392, 'novel', 702, NULL, 'high', 'novel', false, 'sub_item', 'Vytarn (Candleworld)', NULL, NULL, 'Asenath Hyades', '{"Jonah Tythe"}', 'Adepta Sororitas (Order of the Last Candle)', 'Adepta Sororitas', NULL, 'Horror; Mystery', '{"haunting","atmospheric","melancholic","foreboding"}', '{"Adepta Sororitas","Sisters of Battle","Sister Hospitaller","Astra Militarum","healing sanctuary","faith","xenos threat","isolated world","storm-wracked spires","redemption","the Dark Coil","gothic horror"}', 'Survivors of the Exordio Void Breachers, broken by a deadly foe, journey to a secluded Candleworld of the Adepta Sororitas in search of healing, escorted by a Sister Hospitaller who long ago abandoned her order.', 'core', NULL, NULL, false, 'Dark Coil omnibus component', (SELECT id FROM public.books WHERE entry_id='P7-07')),
  ('P7-09.1', 7, 'Skitarius', 'Rob Sanders', 267, 'novel', 901, NULL, 'medium', 'novel', false, 'sub_item', 'Velchanos Magna (forge world)', NULL, 'M41', 'Haldron-44 Stroika', '{"Omnid Torquora","Idriss Krendl"}', 'Adeptus Mechanicus (Forge World Satzica Secundus)', 'Adeptus Mechanicus', NULL, 'Military SF', '{"grim","relentless","mechanical","action-driven"}', '{"Adeptus Mechanicus","skitarii","Machine God","Omnissiah","Alpha Primus","forge world","Satzica Secundus","Velchanos Magna","Stella-Xenithica","STC","Geller Device","Chaos Space Marines","Iron Warriors","Orks","Dark Mechanicum","cybernetic warriors"}', 'The skitarii are the tireless soldiers of the Machine God. A discovery of ancient technology sends a skitarii legion under Alpha Primus Haldron-44 Stroika into battle on a forge world overrun by Chaos; cut off from his tech-priest overseers, he must rally his forces.', 'optional', NULL, NULL, false, 'v3.0 Backlog/Optional — enriched, not active reading', (SELECT id FROM public.books WHERE entry_id='P7-09')),
  ('P7-09.2', 7, 'Tech-Priest', 'Rob Sanders', 189, 'novel', 902, NULL, 'medium', 'novel', false, 'sub_item', 'Velchanos Magna (forge world)', NULL, 'M41', 'Omnid Torquora', '{"Haldron-44 Stroika","Idriss Krendl","Engra Myrmidex"}', 'Adeptus Mechanicus (Forge World Satzica Secundus)', 'Adeptus Mechanicus', NULL, 'Military SF', '{"grim","relentless","mechanical","epic"}', '{"Adeptus Mechanicus","Cult Mechanicus","tech-priest","Magos-Explorator","Omnid Torquora","forge world","Velchanos Magna","Satzica Secundus","Iron Warriors","Idriss Krendl","battle-servitors","Kataphron","Titan Legions","Warhound Titans","treachery","Quest for Knowledge"}', 'The Cult Mechanicus stands on the front line of the Quest for Knowledge. Magos-Explorator Omnid Torquora orchestrates war against the Iron Warriors for control of a long-lost forge world, with skitarii, battle-servitors and Titans at his command - until treachery threatens his conquest.', 'optional', NULL, NULL, false, 'v3.0 Backlog/Optional — enriched, not active reading', (SELECT id FROM public.books WHERE entry_id='P7-09')),
  ('P7-11.1', 7, 'Fifteen Hours', 'Mitchel Scanlon', 256, 'novel', 1101, NULL, 'high', 'novel', false, 'sub_item', 'Broucheroc', NULL, NULL, 'Arvin Larn', NULL, 'Jumael 14th Volunteers; 902nd Vardan Rifles', 'Astra Militarum', NULL, 'Military SF; Character Study', '{"bleak","grim","claustrophobic","tense"}', '{"Astra Militarum","Imperial Guard","conscription","orks","trench warfare","siege","bureaucratic error","coming of age","survival","attrition","hopeless war","new recruit"}', 'Larn of agri-world Jumael IV, bound for Seltura VII, is mistakenly dropped by an administrative error into the ork-besieged city of Broucheroc, where a replacement guardsman''s life expectancy is just fifteen hours.', 'optional', NULL, NULL, false, 'Imperial Guard Omnibus Vol.1 / Shield of the Emperor component; v3.0 Backlog/Optional — enriched, not active reading', (SELECT id FROM public.books WHERE entry_id='P7-11')),
  ('P7-11.2', 7, 'Death World', 'Steve Lyons', 256, 'novel', 1102, NULL, 'high', 'novel', false, 'sub_item', 'Rogar III', NULL, NULL, 'Trooper Lorenzo', '{"Sergeant Greiss","Braxton"}', 'Catachan Jungle Fighters (Catachan XIV)', 'Astra Militarum', NULL, 'Military SF; Horror', '{"tense","horror-tinged","grim","survival"}', '{"Astra Militarum","Catachan Jungle Fighters","death world","orks","sentient planet","jungle warfare","survival horror","squad cohesion","ambush","lethal flora","rite of passage"}', 'A squad of Catachan Jungle Fighters deploys to the death world of Rogar III to counter an ork incursion, but must also battle the lethal planet itself and mysterious figures stalking them through the terrain.', 'optional', NULL, NULL, false, 'Imperial Guard Omnibus component; counts here (P7-23 20th Anniv = same book, xref); v3.0 Backlog/Optional — enriched, not active reading', (SELECT id FROM public.books WHERE entry_id='P7-11')),
