-- B-3c-2: full BL-GRP master-CSV seed into public.books
-- Source of truth: BLGRPMasterMetadatav2.csv (349 rows: 176 entries + 173 sub_items)
-- Join key: entry_id (B-3c-1). Idempotent via ON CONFLICT (entry_id) DO UPDATE.
--
-- Parsing rules (verified against the CSV during B-3c diagnosis):
--   * Array fields (key_characters, faction_secondary, mood_tags, semantic_tags):
--     semicolon-delimited -> text[]. mood_tags has 16 Phase-1 rows that use COMMA
--     as delimiter (comma fallback applied only when no semicolon present).
--   * Apostrophes inside tags (C'tan, El'Jonson, Emperor's Children) are SQL-escaped.
--   * format -> type: novel/novella->novel, short_story->short, anthology/collection
--     ->anthology, omnibus/series->omnibus; empty/tabletop falls back to is_omnibus.
--   * page_count_confidence: 'med' normalised to 'medium'.
--   * UNKNOWN / empty -> NULL (anti-hallucination).
--   * Pass 1 = entries; Pass 2 = sub_items with parent_book_id resolved via
--     entry_id self-join (parent_id -> books.id). parent chain verified: 0 orphans.
--   * The 3 user_progress-bearing rows (P0-01/P0-03/P0-08) keep their UUIDs
--     (ON CONFLICT UPDATE, never DELETE) so user_progress FKs stay intact.

BEGIN;

-- ===== PASS 1: ENTRIES (176) =====
ON CONFLICT (entry_id) DO UPDATE SET phase_id=EXCLUDED.phase_id, title=EXCLUDED.title, author=EXCLUDED.author, pages=EXCLUDED.pages, type=EXCLUDED.type, sort_order=EXCLUDED.sort_order, pub_year=EXCLUDED.pub_year, page_count_confidence=EXCLUDED.page_count_confidence, format=EXCLUDED.format, is_omnibus=EXCLUDED.is_omnibus, row_type=EXCLUDED.row_type, location_primary=EXCLUDED.location_primary, location_segmentum=EXCLUDED.location_segmentum, in_universe_date=EXCLUDED.in_universe_date, protagonist=EXCLUDED.protagonist, key_characters=EXCLUDED.key_characters, sub_faction=EXCLUDED.sub_faction, faction_primary=EXCLUDED.faction_primary, faction_secondary=EXCLUDED.faction_secondary, sub_genre=EXCLUDED.sub_genre, mood_tags=EXCLUDED.mood_tags, semantic_tags=EXCLUDED.semantic_tags, spoiler_free_summary=EXCLUDED.spoiler_free_summary, track=EXCLUDED.track, reading_order_note=EXCLUDED.reading_order_note, also_in=EXCLUDED.also_in, acquired=EXCLUDED.acquired, research_note=EXCLUDED.research_note;

-- ===== PASS 2: SUB-ITEMS (173) with parent_book_id =====
ON CONFLICT (entry_id) DO UPDATE SET phase_id=EXCLUDED.phase_id, title=EXCLUDED.title, author=EXCLUDED.author, pages=EXCLUDED.pages, type=EXCLUDED.type, sort_order=EXCLUDED.sort_order, pub_year=EXCLUDED.pub_year, page_count_confidence=EXCLUDED.page_count_confidence, format=EXCLUDED.format, is_omnibus=EXCLUDED.is_omnibus, row_type=EXCLUDED.row_type, location_primary=EXCLUDED.location_primary, location_segmentum=EXCLUDED.location_segmentum, in_universe_date=EXCLUDED.in_universe_date, protagonist=EXCLUDED.protagonist, key_characters=EXCLUDED.key_characters, sub_faction=EXCLUDED.sub_faction, faction_primary=EXCLUDED.faction_primary, faction_secondary=EXCLUDED.faction_secondary, sub_genre=EXCLUDED.sub_genre, mood_tags=EXCLUDED.mood_tags, semantic_tags=EXCLUDED.semantic_tags, spoiler_free_summary=EXCLUDED.spoiler_free_summary, track=EXCLUDED.track, reading_order_note=EXCLUDED.reading_order_note, also_in=EXCLUDED.also_in, acquired=EXCLUDED.acquired, research_note=EXCLUDED.research_note, parent_book_id=EXCLUDED.parent_book_id;


-- ===== POST-SEED CORRECTION =====
-- Ravenwing (P0-03) was a sub_item in the pre-B-3c catalog and carried a stale
-- parent_book_id into the ON CONFLICT UPDATE (CSV has it as a top-level entry).
-- The UPDATE SET intentionally does not touch parent_book_id for entries, so the
-- legacy pointer survived. Null it out to match its entry row_type.
UPDATE public.books SET parent_book_id = NULL WHERE entry_id = 'P0-03' AND row_type = 'entry';

COMMIT;
